/* ============================================================
   LLM FIELD MANUAL — hover glossary
   Scans prose for known terms and attaches definition tooltips.
   Runs after KaTeX (shared.js calls window.__glossaryScan), with
   a timeout fallback if math never loads. Skips math, code,
   headings, links and widget internals.
   ============================================================ */
(function () {
  "use strict";

  var DEFS = {
    "token": "The atomic unit a model reads and writes — an entry in a fixed vocabulary, typically a word piece of ~4 characters of English.",
    "tokenizer": "The fixed, pre-trained mapping between raw text and token IDs. Not learned during model training.",
    "BPE": "Byte-pair encoding — builds a vocabulary by repeatedly merging the most frequent adjacent symbol pair in a corpus.",
    "embedding": "The learned vector (row of the embedding matrix) that gives a token coordinates in d_model-dimensional space.",
    "logits": "The raw, unnormalized scores the network outputs — one real number per vocabulary token, before softmax.",
    "softmax": "Exponentiates and normalizes a score vector into a probability distribution. Temperature rescales scores first.",
    "cross-entropy": "The training loss: the negative log-probability the model assigns to the true next token, averaged over positions.",
    "perplexity": "exp(loss) — the effective number of equally likely tokens the model is choosing among. Lower is better.",
    "autoregressive": "Generating one token at a time, each conditioned on everything before it, via the chain rule of probability.",
    "teacher forcing": "During training, predicting each position from the true prefix rather than the model's own samples — so all positions train in parallel.",
    "in-context learning": "A trained model's ability to pick up a pattern from examples placed in the prompt, without any weight update.",
    "residual stream": "The d_model-wide vector bus flowing through the network; every attention head and MLP reads from it and writes back by addition.",
    "RMSNorm": "Root-mean-square normalization — rescales a vector to unit RMS with a learned gain. LayerNorm minus mean-centering.",
    "LayerNorm": "Normalizes a vector to zero mean and unit variance with learned gain and bias. Largely replaced by RMSNorm in modern LLMs.",
    "SwiGLU": "The modern MLP form: a SiLU-squashed gate multiplied element-wise with an up-projection, then projected back down.",
    "GELU": "Gaussian-error linear unit, z·Φ(z) — the smooth activation used by GPT-2/BERT-era MLPs.",
    "MLP": "The per-position feed-forward sub-layer (expand, nonlinearity, contract). Holds roughly two-thirds of a transformer's parameters.",
    "RoPE": "Rotary position embeddings — encode position by rotating query/key dimension pairs, making attention scores depend only on relative offset.",
    "ALiBi": "Attention with linear biases — skips position vectors and subtracts a per-head distance penalty from attention scores.",
    "attention": "The mechanism that lets each position read information from others: queries match keys, and the resulting weights blend values.",
    "multi-head attention": "Running many attention operations in parallel low-dimensional subspaces, so a token can look at several things at once.",
    "causal mask": "Additive −∞ entries that zero out attention to future positions, keeping a language model from seeing its own labels.",
    "induction head": "An attention head that finds an earlier occurrence of the current pattern and copies what followed it — a core circuit behind in-context learning.",
    "KV cache": "Stored keys and values of all previous positions, kept so each generation step avoids recomputing them. Dominates inference memory.",
    "MQA": "Multi-query attention — all query heads share a single key/value head, shrinking the KV cache by the head count.",
    "GQA": "Grouped-query attention — groups of query heads share key/value heads; the production compromise between MHA quality and MQA memory.",
    "MLA": "Multi-head latent attention (DeepSeek) — caches one small latent vector per position and reconstructs keys/values from it on the fly.",
    "FlashAttention": "An exact attention kernel that never materializes the T×T score matrix, computing softmax tile-by-tile in on-chip SRAM.",
    "sliding-window attention": "Each position attends only to the last w tokens; stacked layers extend effective reach while keeping cost linear.",
    "attention sink": "The first few tokens of a sequence, which softmax uses to park spare probability mass — evicting them destabilizes generation.",
    "scaling laws": "Empirical power laws relating loss to parameters, data, and compute — the basis for deciding how big to build.",
    "Chinchilla": "DeepMind's 2022 result: at fixed compute, scale parameters and tokens together (~20 tokens per parameter), not parameters alone.",
    "AdamW": "The default LLM optimizer: Adam's per-parameter adaptive steps with weight decay applied directly to weights.",
    "warmup": "The initial phase where learning rate ramps linearly from zero, protecting fragile early optimization.",
    "cosine decay": "Learning-rate schedule that falls along a half-cosine from peak to a small floor over the run.",
    "gradient clipping": "Rescaling the global gradient when its norm exceeds a threshold (usually 1.0), preventing destabilizing steps.",
    "BF16": "bfloat16 — 16-bit float with FP32's exponent range. The default training precision since A100-class hardware.",
    "FP8": "8-bit float formats (E4M3/E5M2) used on Hopper/Blackwell GPUs for matmuls in training and serving.",
    "mixed precision": "Computing in low precision (BF16/FP8) while keeping master weights and optimizer state in FP32 for stable accumulation.",
    "data parallelism": "Cloning the model across devices, splitting the batch, and all-reducing gradients each step.",
    "tensor parallelism": "Splitting individual weight matrices across GPUs so each matmul runs jointly — needs fast interconnect per layer.",
    "pipeline parallelism": "Splitting the model by depth into stages and streaming micro-batches through them.",
    "ZeRO": "Sharding optimizer state, gradients, and finally parameters across data-parallel replicas instead of replicating them (FSDP implements stage 3).",
    "FSDP": "Fully-sharded data parallelism — PyTorch's ZeRO-3: parameters are gathered just-in-time per layer and discarded after use.",
    "activation checkpointing": "Storing only sub-layer boundary activations and recomputing the rest during backward — trades ~30% compute for large memory savings.",
    "MFU": "Model FLOPs utilization — the fraction of theoretical peak GPU throughput spent on useful model math. 35–50% is good at scale.",
    "SFT": "Supervised fine-tuning — training on prompt→response demonstrations with loss only on response tokens. Teaches format and instruction-following.",
    "RLHF": "Reinforcement learning from human feedback — optimizing the model against a learned reward model, with a KL leash to a reference policy.",
    "reward model": "A network (usually the LLM with a scalar head) trained on human comparisons to score how good a response is.",
    "Bradley–Terry": "The preference model behind reward training: P(A beats B) = σ(r_A − r_B).",
    "PPO": "Proximal policy optimization — RL with a clipped update that forbids the policy from moving too far per step. The original RLHF workhorse.",
    "KL divergence": "A measure of how far one distribution drifts from another; RLHF penalizes KL from the reference model to prevent reward hacking.",
    "reward hacking": "Exploiting flaws in a proxy reward — verbosity, sycophancy, confident nonsense — instead of genuinely improving.",
    "DPO": "Direct preference optimization — a classification loss on preference pairs that achieves RLHF's objective with no reward model or RL loop.",
    "GRPO": "Group relative policy optimization — samples a group of responses per prompt and uses the group's mean reward as the baseline, deleting PPO's value network.",
    "RLVR": "RL with verifiable rewards — training against checkable signals (tests pass, answer matches) rather than learned reward models. The engine of reasoning models.",
    "chain of thought": "Intermediate reasoning tokens a model emits before its answer — trading test-time compute for accuracy.",
    "constitutional AI": "Anthropic's method: the model critiques and revises outputs against explicit written principles, and an AI judge generates preference labels from them.",
    "RLAIF": "RL from AI feedback — replacing human preference labels with judgments from a (usually stronger) model.",
    "LoRA": "Low-rank adaptation — freeze the weights, learn the update as a thin matrix product BA. Mergeable after training, swappable at serving time.",
    "QLoRA": "Fine-tuning bf16 LoRA adapters on top of a 4-bit (NF4) frozen base — the technique that put 70B fine-tuning on one GPU.",
    "NF4": "NormalFloat-4 — a 4-bit code whose 16 levels sit at Gaussian quantiles, matching where trained weights actually live.",
    "PEFT": "Parameter-efficient fine-tuning — any method that adapts a model while training a small fraction of its weights.",
    "catastrophic forgetting": "Losing general capability while fine-tuning on a narrow task — probed by re-running broad benchmarks after tuning.",
    "distillation": "Training a small student to match a large teacher's output distribution (or its generated outputs) rather than raw data labels.",
    "dark knowledge": "The information in a teacher's relative probabilities over wrong answers — revealed by softening the softmax with temperature.",
    "quantization": "Mapping weights (and activations) onto a small grid of representable values — fewer bits per parameter, faster and smaller models.",
    "GPTQ": "Post-training quantization that rounds one column at a time, using second-order information to push each column's error onto not-yet-quantized ones.",
    "AWQ": "Activation-aware weight quantization — rescales the ~1% of channels that activations say matter most before rounding.",
    "SmoothQuant": "Migrates activation outlier magnitude into weights via per-channel scaling, enabling fast 8-bit weight-and-activation inference.",
    "QAT": "Quantization-aware training — training with fake-quantized weights in the loop so the model learns to live on the grid.",
    "straight-through estimator": "The trick that lets gradients flow through round(): pretend it's the identity inside the clipping range.",
    "2:4 sparsity": "Semi-structured pattern (two zeros per four weights) that NVIDIA tensor cores execute at up to 2× — the one sparsity with hardware support.",
    "prefill": "The first inference phase: processing the whole prompt in one parallel, compute-bound pass. Sets time-to-first-token.",
    "decode": "The second inference phase: emitting one token at a time, reading all weights and KV cache per step. Memory-bandwidth-bound.",
    "TTFT": "Time to first token — dominated by queueing plus prefill compute.",
    "TPOT": "Time per output token during decode — dominated by memory bandwidth and effective batch size.",
    "arithmetic intensity": "FLOPs per byte moved. Below the hardware's critical ratio you're bandwidth-bound; above it, compute-bound.",
    "roofline": "The performance model plotting achievable FLOP/s against arithmetic intensity — a bandwidth slope capped by a compute ceiling.",
    "PagedAttention": "vLLM's virtual-memory scheme for the KV cache: fixed-size blocks allocated on demand through a block table, eliminating fragmentation.",
    "prefix caching": "Reusing the KV blocks of shared prompt prefixes (system prompts, history) across requests instead of re-running prefill.",
    "continuous batching": "Iteration-level scheduling: finished sequences leave the batch immediately and queued ones join mid-flight.",
    "chunked prefill": "Splitting a long prompt into slices interleaved with ongoing decodes so one big request doesn't spike everyone's latency.",
    "speculative decoding": "A small drafter proposes several tokens; the big model verifies them in one parallel pass with a rejection rule that preserves its exact distribution.",
    "temperature": "Divides logits before softmax: below 1 sharpens toward greedy, above 1 flattens toward uniform.",
    "top-p": "Nucleus sampling — keep the smallest set of tokens whose probabilities sum to p, then renormalize.",
    "top-k": "Keep only the k most probable tokens before sampling.",
    "min-p": "Keep tokens whose probability exceeds a fraction of the maximum — adaptive truncation that tolerates high temperatures.",
    "MoE": "Mixture-of-experts — replace each MLP with many parallel experts and a router sending each token to its top-k. Parameters scale; FLOPs don't.",
    "router": "The small learned layer in an MoE block that scores experts for each token and picks the top-k.",
    "load balancing": "Auxiliary pressure (a loss term or bias) keeping MoE experts evenly used, preventing router collapse onto favorites.",
    "expert parallelism": "Spreading MoE experts across GPUs, with all-to-all communication routing tokens to their experts each layer.",
    "YaRN": "RoPE extension that interpolates per-frequency — fast dimensions untouched, slow ones stretched — plus an attention temperature fix.",
    "position interpolation": "Extending context by compressing all RoPE frequencies so the trained range covers a longer window.",
    "ring attention": "Context parallelism: shard the sequence across GPUs and pass KV blocks around a ring so attention covers the full length.",
    "RAG": "Retrieval-augmented generation — fetch relevant documents and place them in the prompt, fixing knowledge gaps without touching weights.",
    "ViT": "Vision transformer — slices an image into patches, projects each to an embedding, and runs a standard transformer over them.",
    "MCP": "Model Context Protocol — an open standard interface through which models discover and call external tools and resources.",
    "ReAct": "The reason-act loop: think, call a tool, observe the result, repeat — now largely internalized by tool-trained models.",
    "SSM": "State-space model — a (linear) recurrence that compresses history into a fixed-size state: O(1) per decode step, no KV cache.",
    "Mamba": "The selective SSM: transition matrices are functions of the input, letting the state gate what to remember — trainable in parallel via scans.",
    "sparse autoencoder": "An interpretability tool that decompresses the residual stream's superposed features into many sparse, often human-interpretable ones.",
    "hallucination": "Confident generation of false content — a structural consequence of sampling from an imperfect distribution, managed rather than solved.",
    "diffusion": "Generative modeling by learning to reverse a gradual noising process — walk noise backwards into data.",
    "DDPM": "Denoising diffusion probabilistic models — the canonical formulation: train a network to predict the noise added at each step.",
    "score function": "The gradient of log-density, ∇x log p(x) — the vector field pointing toward higher data probability that diffusion models learn.",
    "latent diffusion": "Running diffusion in a VAE's compressed latent space instead of pixels — Stable Diffusion's key efficiency move.",
    "flow matching": "Training a velocity field along straight noise→data paths — simpler objective, fewer sampling steps; behind SD3 and Flux.",
    "classifier-free guidance": "Sampling trick: extrapolate from the unconditional toward the conditional prediction to sharpen prompt adherence.",
    "masked diffusion": "Discrete diffusion for text: corrupt by masking tokens, learn to unmask; generation fills positions in parallel over a few steps.",
    "HBM": "High-bandwidth memory — the GPU's main memory stack; its bandwidth, not compute, bounds decode speed.",
    "goodput": "Throughput that counts — requests per second served within their latency SLO.",
    "context window": "The maximum number of tokens a model can attend over in one sequence.",
    "emergent capability": "An ability that appears abruptly on task metrics as scale grows — usually a step-function metric over smooth loss gains.",
    "superposition": "Packing more features than dimensions into the residual stream as non-orthogonal directions — why raw neurons resist interpretation.",
    "parameter (weight)": "An adjustable number inside a model \u2014 the slope and intercept of a line, or the ~10^12 knobs of a frontier LLM. Written collectively as \u03b8; training sets them, inference freezes them.",
    "loss function": "A single number measuring how badly a model's predictions disagree with the true labels on a dataset. Learning means choosing parameters that push it down; the choice of loss is a design decision, not a given.",
    "mean squared error (MSE)": "The average of squared residuals across a dataset. Squaring kills the sign, punishes large misses disproportionately, and leaves a smooth surface that gradient methods can descend.",
    "residual": "The gap between a model's prediction and the true label for one example, h(x) \u2212 y. MSE is the average of squared residuals; visually, the vertical stalk from a point to the fitted curve.",
    "generalization": "Performance on data the model never saw during training \u2014 the only property a deployed model is actually paid for. Measured by held-out test loss, never by training loss.",
    "overfitting": "When a model uses its flexibility to memorize training data rather than capture the underlying pattern: training loss falls while test loss rises. The gap between the two is overfitting made visible.",
    "train/test split": "Partitioning data before any fitting so the model is tuned on one part and judged on an untouched part. The certificate is conditional: it assumes test data comes from the same distribution, and it weakens every time the test score influences a modeling decision.",
    "Gradient Descent": "The iterative optimization loop at the heart of all modern ML: compute the gradient of the loss with respect to the parameters, step a small distance in the opposite direction, repeat. Every optimizer in this encyclopedia \u2014 SGD, momentum, Adam \u2014 is a decoration of this one update.",
    "Learning Rate (\u03b7)": "The scalar multiplying the gradient in each descent step, controlling how far the parameters move. Too small wastes compute; past the critical value 2/\u03bb set by the loss surface's steepest curvature, every step overshoots and the loss diverges exponentially.",
    "Normal Equation": "The closed-form solution w = (X\u1d40X)\u207b\u00b9X\u1d40y that lands exactly at the bottom of linear regression's loss bowl in one matrix solve. Unusable at scale (the d\u00b3 solve) and unavailable the moment the model becomes nonlinear \u2014 which is why the rest of ML iterates instead.",
    "Convexity": "The property that a loss surface has no false valleys: the line between any two points on it never dips below the surface, so every downhill path reaches the same global minimum. Linear regression with MSE has it; deep networks do not.",
    "Standardization": "Rescaling each feature to zero mean and unit variance, x\u2032 = (x \u2212 \u03bc)/\u03c3, computed on the training set only. It rounds out the loss bowl's curvature so one shared learning rate serves all weights \u2014 frequently the difference between gradient descent converging and exploding.",
    "logistic regression": "A linear classifier that converts the score w\u00b7x + b into a probability via the sigmoid. Still linear \u2014 but in the log-odds, which is why each weight reads as an interpretable odds multiplier.",
    "sigmoid": "The S-shaped squash \u03c3(z) = 1/(1+e\u207b\u1dbb) mapping any real score to (0,1). The exchange rate between evidence and probability \u2014 and softmax's two-class special case.",
    "decision boundary": "The surface where a classifier's predicted probability crosses 0.5 \u2014 for logistic regression, the flat hyperplane w\u00b7x + b = 0. The sigmoid bends probabilities, never the boundary.",
    "precision": "Of everything the model flagged positive, the fraction that was actually positive: TP/(TP+FP). The metric that exposes false alarms.",
    "recall": "Of everything actually positive, the fraction the model caught: TP/(TP+FN). Trades off against precision through the decision threshold.",
    "confusion matrix": "The 2\u00d72 (or K\u00d7K) table splitting predictions into true/false positives and negatives. The raw accounting from which precision, recall, and every honest classification metric derive.",
    "class imbalance": "When one class vastly outnumbers another, so raw accuracy measures the imbalance rather than the model \u2014 a 1-in-1,000 disease makes 'always healthy' 99.9% accurate. Handled by reweighting, resampling, or threshold moving, judged by precision/recall.",
    "k-nearest neighbors (k-NN)": "A classifier with no training step: store the dataset, and label a new point by majority vote of its k closest training examples under a distance metric. All modeling assumptions hide in the distance function, and all compute moves to query time.",
    "curse of dimensionality": "The collapse of 'nearness' as dimensions grow: data becomes exponentially sparse and pairwise distances concentrate, so the gap between nearest and farthest neighbor shrinks toward nothing. Real data often escapes it by lying near lower-dimensional structure.",
    "Gini impurity": "A node-purity score for tree splits: the probability that two random draws from a node carry different labels, 1 \u2212 \u03a3 p_c\u00b2. CART picks the feature\u2013threshold split that reduces it most; the entropy alternative almost never changes the tree.",
    "decision stump": "A depth-1 decision tree \u2014 one feature, one threshold, two predictions. Barely better than chance alone, but it is the standard weak learner that gradient boosting stacks by the hundreds.",
    "bagging": "Bootstrap aggregating: train many high-variance models on bootstrap resamples of the data (each bag holds \u224863.2% of unique points) and average their votes. Averaging n uncorrelated predictors divides error variance by n.",
    "random forest": "Bagging over deep trees plus one decorrelation trick: each split may only consider a random subset of features (\u2248\u221ap), lowering inter-tree correlation and thus the variance floor that plain averaging cannot remove. Out-of-bag points give free validation.",
    "gradient boosting": "An ensemble built sequentially: each shallow tree is fit to the residuals \u2014 more generally the negative gradient of the loss \u2014 of the ensemble so far, scaled by a shrinkage rate \u03b7. XGBoost, LightGBM and CatBoost are its production forms and the default winners on tabular data.",
    "bias\u2013variance decomposition": "The exact split of expected squared error into systematic error of the average fit (bias\u00b2), sensitivity to the particular training sample (variance), and irreducible noise. Capacity buys down bias by paying in variance; the trade-off governs every model-selection decision.",
    "regularization": "Any technique that trades a little bias for a lot of variance reduction by penalizing or constraining model complexity \u2014 L2/weight decay, L1, early stopping, dropout, and data augmentation are all the same idea in different uniforms.",
    "weight decay": "Shrinking weights toward zero by a factor each optimizer step; identical to an L2 penalty under plain SGD but not under adaptive optimizers, which is why AdamW decouples the decay from the adaptive machinery.",
    "cross-validation": "Estimating generalization by splitting data into k folds, training k times with a different fold held out each time, and averaging the held-out scores \u2014 a lower-variance estimate than any single split, at k\u00d7 the compute.",
    "data leakage": "Information from the evaluation side contaminating the training side \u2014 preprocessing fit on the full dataset, duplicates across splits, temporal or group leaks, or features that echo the label. Produces beautiful validation scores and production disasters.",
    "double descent": "The modern amendment to the classical U-curve: push capacity past the point of exact interpolation and held-out error often falls a second time, because gradient descent implicitly prefers low-norm solutions among the many that fit perfectly. The regime modern LLMs train in.",
    "early stopping": "Halting training when validation error stops improving and restoring the best checkpoint. Training time is itself a capacity dial \u2014 for linear least squares, stopping gradient descent at step t is approximately ridge regression with \u03bb \u221d 1/(\u03b7t).",
    "perceptron": "Rosenblatt's 1958 single-layer classifier: a thresholded weighted sum. It can only draw one flat decision boundary \u2014 its provable inability to compute XOR helped trigger the first AI winter.",
    "hidden layer": "Any layer between input and output whose values are learned intermediate features rather than data or targets. The network decides for itself what each hidden unit means.",
    "activation function": "The elementwise nonlinearity applied after a linear layer. Without it, stacked layers collapse algebraically into a single linear model.",
    "ReLU": "max(0, z) \u2014 the activation that made deep networks trainable: its derivative is exactly 1 on the entire active half, so gradients pass through layers unshrunk.",
    "vanishing gradient": "The shrinkage of the learning signal as it is multiplied through many layers of saturating activations \u2014 sigmoid's max derivative of 1/4 compounds to ~10\u207b\u2076 over ten layers. The failure mode that kept pre-2012 networks shallow.",
    "universal approximation": "The theorem that one sufficiently wide hidden layer can approximate any continuous function on a bounded region. An existence result only: it promises nothing about how many units, whether gradient descent finds the weights, or generalization.",
    "dead ReLU": "A ReLU unit whose pre-activation is negative for every input; its gradient is exactly zero and plain gradient descent can never revive it.",
    "backpropagation": "The algorithm that computes the gradient of the loss with respect to every parameter in one backward sweep of the computational graph \u2014 the chain rule applied in reverse topological order so each edge is touched exactly once, at roughly twice the cost of a forward pass.",
    "computational graph": "A directed acyclic graph whose nodes are primitive operations and whose edges carry values forward and local derivatives backward. Autodiff frameworks build it implicitly as your code runs; backprop is a walk over it.",
    "reverse-mode autodiff": "Automatic differentiation that records each operation's inputs and local derivative during the forward pass (PyTorch's grad_fn tape), then computes \u2202loss/\u2202(everything) in a single backward pass \u2014 the property that makes training billions of parameters affordable. Pays its bill in memory: every activation must be\u2026",
    "SGD": "Stochastic gradient descent: update parameters using the gradient averaged over a random minibatch rather than the full dataset. The estimate is unbiased and a step's cost is independent of dataset size \u2014 the fact that makes internet-scale training possible.",
    "minibatch": "The random subset of examples whose averaged gradient drives one SGD step. Gradient-estimate variance falls as 1/|B|, so batch size trades estimation noise against compute per step and hardware utilization; past a critical batch size the extra averaging buys little.",
    "momentum": "An exponential moving average of gradients used as the update direction (v \u2190 \u03b2v + g). Oscillating components cancel and consistent ones accumulate, giving up to a 1/(1\u2212\u03b2) speedup along ravine floors and enough stored velocity to coast over small bumps that trap plain SGD.",
    "gradient check": "Verifying an analytic (backprop) gradient against central finite differences, parameter by parameter. The standard contract: agreement to ~1e-7 in float64 or the backward pass is wrong. Mandatory whenever a gradient is written by hand.",
    "chat template": "The per-model recipe that serializes a messages array (system/user/assistant) into one flat token stream stitched together with special tokens. Serving a model with the wrong template still produces answers \u2014 just silently worse ones.",
    "system prompt": "The standing-instruction region of the context, read before all turns. Its authority over user content is installed by post-training, not enforced by the architecture \u2014 the gap prompt injection exploits.",
    "special token": "A reserved vocabulary item (e.g. <|im_start|>, <|eot_id|>) that delimits turns and signals stops; ordinary text can never tokenize into one. Trained delimiters, not punctuation.",
    "generation cue": "The trailing assistant header a chat template appends so the highest-probability continuation is the model's own reply; generation ends when the model itself emits the end-of-turn token.",
    "lost in the middle": "The empirical U-shape in retrieval accuracy over context position: facts at the start or end of a long prompt are used far more reliably than facts buried mid-context (Liu et al. 2023). Newer long-context training flattens the U without erasing it.",
    "conditioning": "Holding the prompt fixed as the x in p(y | x). Everything prompting achieves is a change of condition over a frozen network \u2014 selection among behaviors the weights can already express, never creation of new capability.",
    "magic words": "Folklore incantations (\"take a deep breath\", offering tips) claimed to boost quality. Measured effects are small, model-specific, and routinely evaporate across versions; they survive because single runs are anecdotes.",
    "Prompt scaffold": "The five-part frame \u2014 Role, Task, Context, Format, Constraints \u2014 that converts a vague request into explicit conditioning evidence. A checklist, not a form: parts that add no information are omitted, not padded.",
    "Role prompting": "Conditioning the model's latent author-persona (\"you are a staff engineer reviewing for OWASP Top 10\") to load vocabulary, conventions, and evaluation criteria. Reliably shifts style and framing; controlled studies find no consistent accuracy gain on factual tasks.",
    "Conjunction tax": "The multiplicative reliability penalty of compound requests: a response that must satisfy k requirements at probability p each succeeds at roughly p^k \u2014 why single-deliverable prompts chained with verification beat one mega-prompt.",
    "Format anchoring": "Showing the output's shape \u2014 a template, labeled fields, structural length bounds \u2014 so the model pattern-completes into it rather than interpreting a prose description of the shape.",
    "Tie-breaker rule": "An explicit precedence clause (\"if brevity and completeness conflict, prefer brevity\") that prevents the model from hedging between two competing goals and serving neither.",
    "Negative constraint": "A prohibition (\"do not mention X\") whose tokens become attendable context, raising the salience of the very topic being forbidden. Best practice pairs every don't with a do \u2014 the boundary plus the preferred alternative.",
    "few-shot prompting": "Including worked input\u2192output examples in the prompt so the model continues the pattern rather than interpreting a description. The strongest single prompting lever, with the largest gain coming from zero to one shot.",
    "zero-shot": "Prompting with instructions only, no examples. The baseline modern instruct models are tuned to excel at \u2014 which is why adding examples to a simple task can drag a strong model below its own default.",
    "recency bias": "The skew of a few-shot prediction toward the label or style of the final example in the block. Permuting the same examples can change the answer; it is why the last slot should hold your most representative demo.",
    "majority-label bias": "Drift of few-shot predictions toward whichever label appears most often among the demonstrations, independent of the test input. Balanced label counts across shots are the first-line mitigation.",
    "format leakage": "The copying of every surface detail of few-shot examples \u2014 key order, casing, response length, punctuation \u2014 into model outputs. A hazard when accidental; when deliberate, the most reliable format-specification mechanism available.",
    "contrastive examples": "Paired good and bad outputs for the same input, each labeled with an explicit why. The annotation converts an instance into a transferable rule and teaches task boundaries that positive examples alone cannot.",
    "exemplar retrieval": "Selecting few-shot examples per query by embedding similarity \u2014 nearest neighbors from a candidate pool \u2014 instead of a fixed set. Reliably raises accuracy but collapses demo diversity and invalidates prefix caching.",
    "many-shot in-context learning": "Few-shot prompting scaled to hundreds or thousands of examples in long contexts. Some tasks keep improving well past the classic saturation point, occasionally approaching fine-tuning quality at fine-tuning-like token economics.",
    "self-consistency": "Sampling N reasoning chains at nonzero temperature and taking the plurality of their final answers \u2014 a Monte-Carlo estimate of the model's marginal answer distribution. Gains saturate around N \u2248 10\u201320 while cost stays linear, and correlated errors across chains cap the benefit.",
    "least-to-most prompting": "A decomposition pattern that first breaks a problem into subquestions ordered easiest to hardest, then solves them sequentially with each answer fed forward. Its signature win is compositional generalization \u2014 solving test problems harder than any demonstration.",
    "step-back prompting": "Asking the model for the governing abstraction ('what principle applies here?') before the specific question. Targets knowledge-heavy reasoning where retrieving the right principle, not applying it, is the bottleneck.",
    "test-time compute": "Computation spent at inference rather than training to improve answers \u2014 serially via longer thinking chains, or in parallel via sampling and voting/verification. On verifiable domains, accuracy rises roughly log-linearly with thinking tokens until the task's ceiling.",
    "thinking budget": "An API-level cap on how many reasoning tokens a reasoning-class model may spend before answering \u2014 explicit token ceilings (budget_tokens, thinking_budget) or categorical effort tiers (reasoning_effort). The control surface that replaced 'think step by step' for models that internalized CoT via RLVR.",
    "chain-of-verification": "A verification protocol: draft an answer, generate verification questions about it, answer them independently without the draft in context, then revise. The independence is load-bearing \u2014 a model shown its own draft tends to confirm it.",
    "CoT faithfulness": "The degree to which a model's emitted reasoning chain reflects the computation that actually produced its answer. Studies show chains can be fluent post-hoc rationalizations \u2014 e.g. never mentioning a planted bias that demonstrably drove the answer \u2014 so a chain buys accuracy more reliably than it buys explanation.",
    "Prefilling": "Starting the assistant turn yourself so the model must continue from your text rather than begin fresh. Forcing the first tokens (e.g. an opening brace) makes preambles impossible by construction \u2014 hard conditioning, not persuasion.",
    "Constrained decoding": "Generation in which a grammar compiled from a schema or regex masks every token that would produce invalid output, making well-formedness a property of the decoder rather than of the model's cooperation. Guarantees syntax, never semantics.",
    "Logit masking": "Setting the logits of disallowed tokens to negative infinity before softmax, so sampling renormalizes over the legal moves only. The mechanism underneath constrained decoding and structured-output APIs.",
    "JSON Schema": "A declarative specification of a JSON object's types, enums, ranges, and required fields. In a prompt it is documentation the model probably follows; compiled into the decoder it becomes an enforceable contract \u2014 and its description strings act as per-field mini-prompts.",
    "Stop sequence": "A string at which the API cuts generation before the model emits it. Paired with a prefilled opening tag, it brackets the response so the payload arrives whole and nothing but.",
    "Defensive parsing": "A pipeline \u2014 extract, repair, parse, validate, retry \u2014 that turns probably-formatted model output into trustworthy data. Mechanical syntax repairs are safe; semantic repairs must be logged or sent back to the model as a correction prompt.",
    "generator\u2013verifier gap": "The empirical asymmetry between a model's ability to produce a correct output and its (usually higher) ability to judge whether a candidate output is correct. When the gap is positive, extra compute is better spent checking and selecting than generating longer.",
    "Reflexion": "An inference-time loop (Shinn et al., 2023) where a model attempts a task, fails against an external signal, distills the failure into a short verbal lesson, and retries conditioned on the accumulated lessons rather than the failed transcripts \u2014 a gradient step taken in natural language, no weights touched.",
    "pre-mortem": "A planning-stage critique that presupposes failure: 'it is six months later and this plan failed \u2014 write the post-incident report.' The tense shift (prospective hindsight) reliably extracts more specific failure causes, early-warning metrics, and plan changes than asking what could go wrong.",
    "council of judges": "N independent LLM judges, each evaluating an artifact through a distinct lens in a separate context, plus an aggregator that tallies verdicts and surfaces disagreements. Reduces single-judge variance the way GRPO's group baseline reduces reward noise \u2014 provided the judges are actually decorrelated.",
    "Condorcet jury theorem": "If n voters decide independently and each is correct with probability p > 1/2, the majority's accuracy rises toward 1 as n grows \u2014 and falls toward 0 if p < 1/2. The mathematical case for judge councils, and the warning that majorities of bad judges converge confidently on wrong answers.",
    "self-preference bias": "The tendency of LLM judges to rate their own generations above equally good alternatives, partly driven by recognizing their own style. The reason a critique pass must run in a fresh context \u2014 ideally a different model \u2014 rather than in the author's own conversation.",
    "AI debate": "An oversight protocol (Irving, Christiano & Amodei, 2018) where two models argue opposing sides and a judge \u2014 possibly weaker than either \u2014 picks the side whose evidence survived rebuttal, on the theory that refuting a lie is easier than detecting one.",
    "golden set": "A small, curated collection of inputs with known-correct or mechanically checkable outputs, used to score every prompt or model change. The unit-test suite of prompt engineering: twenty real-traffic cases beat zero by more than a thousand beat twenty.",
    "LLM-as-judge": "Using a language model to grade or compare other model outputs. Agreement with human majority preference reaches roughly human-human levels on chat-quality tasks, but the judge carries systematic biases \u2014 position, length, self-preference, style-over-substance \u2014 that the eval protocol must cancel.",
    "position bias": "A judge's systematic preference for a response based on the slot it occupies in a pairwise comparison rather than its content. Audited by swapping presentation order and measuring the verdict flip rate; debiased to first order by averaging both orders.",
    "win rate": "The fraction of pairwise comparisons in which one prompt or model beats another \u2014 the standard scalar for A/B evaluation where no single gold answer exists. Subject to the same binomial noise floor as any pass rate.",
    "prompt regression": "A quality drop introduced by editing a prompt \u2014 or by upgrading the underlying model while the prompt stays fixed \u2014 that an eval gate is designed to catch before production. The reason prompts deserve version control, CI, and pinned model IDs.",
    "BYOK": "Bring your own key: a client-side pattern in which the reader's own API key, held only in their browser tab, authorizes requests sent directly to the model provider with no intermediary server.",
    "agentic loop": "The control cycle at the core of every agent: the model emits a tool call, the harness executes it, the observation is appended to context, and the model is called again on the longer transcript. The transcript is the entire runtime state \u2014 the weights never change mid-episode.",
    "tool call": "A structured, schema-conforming action request emitted by the model, naming a function and its arguments. Once a prompting convention parsed out of free text, now a trained behavior with dedicated output formats.",
    "observation": "Whatever the environment returns after an action \u2014 tool output, an error trace, a search result, a screenshot \u2014 appended to context as the model's only window onto the world. Tools that turn silent errors into observations are the cheapest reliability an agent can buy.",
    "computer use": "Driving a graphical interface through screenshots in and clicks or keystrokes out \u2014 the actuator of last resort that turns any application into an agent environment, no API required. Slower and more fragile than native tools, but universal.",
    "trajectory": "The full action\u2013observation sequence of one agent episode, from goal to termination. The unit that long-horizon RL rewards and that agent evals must grade \u2014 expensive, nondeterministic, and different on every run.",
    "context engineering": "The discipline of curating everything a model sees on each call of an agentic loop \u2014 instructions, tools, memory, retrieval, history, notes \u2014 treating the window as a budget rather than a bucket. The successor frame to prompt engineering.",
    "context rot": "The degradation of a model's effective attention as the window fills: facts present in context are used less reliably long before the hard token limit is reached, especially mid-window and amid distractors.",
    "signal-to-token ratio": "Of the tokens about to be added to context, the fraction that changes what the model will do. The working metric of curation \u2014 low-ratio content keeps charging on every subsequent call until something removes it.",
    "compaction": "Replacing the oldest span of an agent's history with a structured summary so the session continues under budget. A lossy codec whose loss function must protect decisions, constraints, and identifiers over chatter.",
    "just-in-time retrieval": "Keeping lightweight references (paths, titles, ids) in context and letting the agent fetch full content through tools when its current hypothesis demands it, instead of front-loading top-k chunks.",
    "write-back discipline": "Updating persistent memory at decision points \u2014 small, structured, dated, reviewed \u2014 so memory tracks reality instead of decaying into fiction. The property that separates working memory systems from decorative ones.",
    "sub-agent": "A fresh context window dedicated to a single concern, spawned with a self-contained brief. It absorbs the token cost of its own exploration and returns a compressed result \u2014 never its transcript.",
    "stable prefix": "The slow-changing front of an agent's context (system prompt, tool schemas, memory file), ordered first so prompt caching can replay its KV state across steps. One changed byte invalidates everything after it.",
    "Description-as-prompt": "The principle that a tool's name, description, and parameter schema are the model's entire understanding of it \u2014 the model never sees the implementation, so tool design is literally prompt engineering with a type signature.",
    "Task-level tool": "A tool sized to a step in the user's intent (e.g. find_orders_for_customer) rather than mapped one-to-one onto a backend endpoint (get_user, get_orders). Task-level tools move orchestration into reliable code and out of the token stream.",
    "Model Context Protocol (MCP)": "An open standard (released late 2024) that lets any agent host connect to any tool/data server through one connector, collapsing an N\u00d7M matrix of bespoke integrations into N+M. Servers expose three primitives: tools (model-invoked), resources (host-attached data), and prompts (user-invoked workflows).",
    "Prompt injection": "The core vulnerability of tool-using systems: because a model cannot reliably distinguish instructions it was given from text it merely read, any untrusted content reaching its context (web pages, emails, tool results) can carry instructions it then follows.",
    "Lethal trifecta": "Simon Willison's framing for when prompt injection escalates to exfiltration: an agent has (1) access to private data, (2) exposure to untrusted content, and (3) an outbound channel. Risk is the product of the three \u2014 zero any one factor and the exploit is defused.",
    "Tool poisoning": "An MCP-specific attack where a malicious server hides hostile instructions inside a tool's description or results; because those words flow into the model's context, the server steers the agent \u2014 prompt injection delivered through an authenticated connection.",
    "blast radius": "The worst-case cost of the most damaging action an agent's environment permits. Sandboxes, write scopes, and checkpoints exist to shrink it \u2014 alignment training alone cannot, because agent inputs are adversarial.",
    "approval fatigue": "The decay of human scrutiny under repeated permission prompts: the first ask of the day gets read, the thirtieth gets reflex-approved in 400 ms. Well-designed harnesses make asks so rare that each one is news.",
    "verifier": "Any ground-truth check a harness can run on an agent's output \u2014 tests, compilers, linters, screenshot diffs. If the harness can check it, the agent can fix it; the verifier's false-pass rate caps achievable reliability no matter how many retries.",
    "idempotent": "A step that lands in the same state whether run once or twice: f(f(s)) = f(s). Idempotent steps make retry-after-partial-failure safe, which matters because agents fail mid-step constantly and get restarted blindly.",
    "git worktree": "A second working directory sharing one repository's object store \u2014 the cheapest unit of agent workspace isolation. Not a security boundary, but it makes parallel attempts and total rollback nearly free: cleanup is deleting a branch.",
    "best-of-N": "Running N parallel attempts at a task and shipping the one a selector prefers. A ground-truth verifier is a perfect selector; an LLM judge is a noisy one whose accuracy multiplies \u2014 and caps \u2014 the whole pipeline.",
    "orchestrator\u2013worker pattern": "Multi-agent topology in which one agent decomposes a task, fans subtasks out to parallel workers, and owns the synthesis of their results. Workers hand back artifacts and structured summaries \u2014 results, not transcripts.",
    "council/judge pattern": "Parallel, isolated agents produce independent judgments on the same input; a judge aggregates by deduplicating, ranking, and discarding outliers. Wins where diversity of judgment is the product; loses wherever a ground-truth verifier exists \u2014 tests beat votes.",
    "watchdog": "A supervisor outside the agent's context window that enforces budgets, detects stalled progress and repeated actions, and can kill the loop. Placed externally because a looping model's own context normalizes the repetition \u2014 you do not ask the loop whether it is a loop.",
    "compaction checkpoint": "A deliberate pause at a clean task boundary \u2014 typically after a verify-pass \u2014 where the agent writes a durable record of goal, decisions, verified state, and next action before its context is compacted, so a fresh instance can resume from the file alone.",
    "heartbeat loop": "A long-horizon pattern in which an agent is re-invoked on a schedule: each beat reads durable state, does one bounded, verified unit of work, writes state back, and exits. A crash costs one beat, not the mission.",
    "model-tier routing": "Assigning each loop step to the cheapest model tier that clears its required success probability \u2014 typically a cheap drafter paired with a strong verifier or escalation model. Speculative decoding's economics lifted from the token level to the task level.",
    "pass@k": "The probability that at least one of k sampled attempts solves a task. Estimated without bias from n samples with c successes as 1 \u2212 C(n\u2212c,k)/C(n,k); the naive plug-in 1\u2212(1\u2212c/n)^k is biased low.",
    "failure taxonomy": "A fixed classification of agent failure modes \u2014 wrong tool, bad args, hallucinated state, gave up, loop \u2014 that turns 'the agent is flaky' into a measurable distribution with an owner per class.",
    "cost per resolved task": "Total spend divided by tasks actually solved: cost-per-run over the resolution rate. The agent KPI that correctly punishes cheap models with collapsed success rates.",
    "eval gate": "A CI rule that blocks any prompt, model, or tool change from shipping unless golden-set and regression scores clear the suite's measured noise floor.",
    "supervised learning": "Learning from (input, correct answer) pairs that someone, somewhere, already produced. The regime where ML's vocabulary is cleanest \u2014 the other regimes reuse nearly all of it.",
    "unsupervised learning": "Extracting structure from inputs alone, with no labels anywhere in the problem \u2014 groups, directions, densities. Every method optimizes a proxy (compactness, variance, reconstruction), and judging whether the proxy matches the purpose is your job, not the algorithm's.",
    "self-supervised learning": "Manufacturing labels out of the raw data itself \u2014 mask a word and predict it, take a prefix and predict the next token. Supervised machinery, free labels, internet scale: how every modern language model pre-trains.",
    "reinforcement learning": "Learning from trial-and-error reward instead of labeled answers: act, get scored, shift toward the actions that scored well. No one shows the model the right answer \u2014 only how good its attempt was.",
    "distribution shift": "When the data a deployed model meets stops resembling the data it trained on \u2014 certified on last year's emails, facing next year's spammers. The train/test certificate assumes the world holds still; it doesn't.",
    "hyperparameter": "A knob you set rather than one the optimizer learns \u2014 learning rate, tree depth, penalty strength \u03bb. Tuned against a validation set, never against the test set.",
    "feature scaling": "Putting features on comparable numeric ranges so no column dominates by accident of units. Distance methods and gradient descent demand it; trees genuinely do not care.",
    "one-hot": "Encoding a category as a vector of zeros with a single 1 in that category's slot. Also the shape of the truth in classification losses: probability 1 on the right class, 0 everywhere else.",
    "Adam": "The adaptive optimizer that gives every parameter its own effective learning rate by tracking running averages of gradients and of squared gradients. Robust to badly conditioned loss surfaces \u2014 the default until AdamW fixed how it handles weight decay.",
    "maximum likelihood": "Choose the parameters that make the observed data most probable. Take the negative log and the standard losses fall out \u2014 minimizing cross-entropy is maximum likelihood in disguise.",
    "hyperplane": "A flat boundary in d dimensions \u2014 a line in 2-D, a plane in 3-D, and the same object beyond visualization. The only decision surface a linear classifier can ever draw.",
    "feature engineering": "Hand-crafting input transformations \u2014 products, squares, ratios \u2014 so a simple model can fit what its raw inputs cannot. Neural networks' entire pitch is learning those transformations instead of waiting for you to invent them.",
    "linearly separable": "A dataset whose classes can be split perfectly by one flat boundary. XOR is the famous four-point proof that not all data is \u2014 and the reason single-layer models hit a wall.",
    "F1 score": "The harmonic mean of precision and recall, 2PR/(P+R) \u2014 one number for one operating point on the precision\u2013recall trade-off. Harsh when the two diverge, which is exactly the point.",
    "Euclidean distance": "Straight-line distance: the square root of summed squared coordinate differences. The default notion of 'near' in k-NN and k-means \u2014 which is why an unscaled feature silently rigs both.",
    "CART": "Classification and regression trees \u2014 the greedy tree-builder: at every node, try each feature and threshold, keep the split that most purifies the children, recurse. The globally optimal tree is NP-complete to find; nobody builds it.",
    "ensemble": "Many models combined \u2014 averaged, voted, or stacked in sequence \u2014 to beat any single member. Forests average away variance; boosting stacks away bias.",
    "XGBoost": "The gradient-boosting library (2016) that added second-order gradients and explicit regularization on leaf weights. With LightGBM and CatBoost, the production face of boosting \u2014 and the baseline any fancier model must beat on tabular data.",
    "inductive bias": "What a model family assumes about the world before seeing any data \u2014 smoothness for neural networks, axis-aligned cuts for trees. The right bias is worth more than data; the wrong one squanders it.",
    "k-means": "The standard clustering loop: place k centroids, assign every point to its nearest, move each centroid to the mean of its points, repeat until nothing changes. Fast and everywhere \u2014 and it silently assumes clusters are round, compact, and similar-sized.",
    "centroid": "A cluster's center of mass \u2014 the mean of the points currently assigned to it. k-means alternates between assigning points to centroids and recomputing centroids from the assignments; the mean is exactly the point that minimizes total squared distance.",
    "silhouette score": "A clustering-quality heuristic comparing each point's distance to its own cluster against the nearest foreign one. One of the standard ways to choose k \u2014 and a judgment call dressed as a number.",
    "dimensionality reduction": "Re-describing each point with fewer coordinates while keeping what matters \u2014 possible because real data is redundant and hugs lower-dimensional structure inside its nominal space. PCA is the linear classic.",
    "PCA": "Principal component analysis \u2014 center the data, then keep the orthogonal directions along which it varies most. Maximizing variance kept and minimizing reconstruction error are provably the same criterion, not two.",
    "covariance matrix": "The d\u00d7d ledger of how every pair of features moves together, variances on the diagonal. PCA is nothing more than the eigendecomposition of this one object.",
    "eigenvector": "A direction a matrix only stretches, never rotates: \u03a3u = \u03bbu. The covariance matrix's top eigenvector is the direction of greatest variance \u2014 PCA's first axis.",
    "eigenvalue": "The stretch factor \u03bb paired with an eigenvector. For a covariance matrix, each eigenvalue is exactly the variance captured along its direction \u2014 and the eigenvalues you drop sum to precisely your reconstruction error.",
    "autoencoder": "A network trained to reproduce its own input through a narrow bottleneck, with reconstruction error as the loss. A linear one provably recovers PCA; nonlinear ones learn the curved sheets PCA cannot.",
    "t-SNE": "A nonlinear 2-D map for looking at high-dimensional data (UMAP is its faster cousin): local neighborhoods survive, global geometry does not. Use it for eyes, never arithmetic \u2014 cluster sizes and distances in the plot are artifacts of the optimizer.",
    "underfitting": "Too little capacity (or training) to capture even the signal: training and held-out error both high and close together. The fix is a bigger model or better features \u2014 more data will not help.",
    "ridge regression": "Least squares plus an L2 penalty \u03bb\u2016w\u2016\u00b2: every weight shrinks toward zero, none reach it, and the closed form just fattens the diagonal of X\u1d40X \u2014 curing its numerical fragility for free. A capacity dial with infinite resolution.",
    "lasso": "Least squares plus an L1 penalty \u03bb\u2016w\u2016\u2081. The kink at zero sets weights with weak evidence to exactly zero \u2014 selection, not just shrinkage \u2014 so the surviving feature set is often the deliverable.",
    "dropout": "During training, zero each hidden unit at random with probability p (scaling the survivors), so no unit can rely on a partner that might vanish. Approximately an ensemble of exponentially many subnetworks; retired from LLM pre-training, alive and well in small-data fine-tunes.",
    "epoch": "One full pass of training over the dataset. Also a capacity dial in disguise: validation error traces a U over epochs, which is exactly what early stopping exploits.",
    "validation set": "The middle split: data used to choose hyperparameters and stopping points, so the test set stays untouched for one final, honest reading. Tune on validation, report on test, never confuse the two.",
    "multi-layer perceptron": "The original neural network: linear layer, elementwise nonlinearity, linear layer. The bend is load-bearing \u2014 delete it and the whole stack collapses algebraically into one linear model.",
    "XOR": "Exclusive-or: true exactly when its two inputs differ. Four points no straight line can separate \u2014 the 1969 proof that froze neural-network research until multi-layer training arrived.",
    "tanh": "The zero-centered sigmoid, squashing scores to (\u22121, 1) with slope 1 at the origin. The RNN-era default hidden activation; it still saturates at both ends, so deep stacks of it starve for gradient.",
    "forward pass": "Running inputs through the network to produce predictions and the loss \u2014 for an MLP, a couple of matrix multiplications. Its values must be kept around: the backward pass consumes them.",
    "backward pass": "The sweep that carries gradients from the loss back through every layer, reusing the values the forward pass stored \u2014 roughly twice the forward FLOPs, every edge of the graph touched exactly once.",
    "chain rule": "Calculus's composition rule: the derivative through nested functions is the product of the local derivatives along the path. Backpropagation is the chain rule scheduled on a graph so that nothing is ever computed twice.",
    "credit assignment": "The central question of learning: when the loss is bad, which of the millions of weights is at fault, and by how much? Backpropagation answers it exactly, for every weight at once, at roughly the cost of one extra forward pass.",
    "residual connections": "Reformulating each layer as h + F(h), so the identity term gives gradients a multiplication-free expressway through depth. The trick that took networks from 20 trainable layers to 152 \u2014 and the spine of every transformer.",
    "exploding gradients": "The mirror image of vanishing: per-layer factors slightly above 1 compound geometrically until one update flings the weights to infinity. Held in check by sane initialization and gradient clipping.",
    "unembedding": "The final projection (the LM head, W_U) that maps the last hidden state back to one logit per vocabulary token. Some models tie it to the embedding matrix to save parameters; most recent large models untie the two for quality.",
    "base model": "A pre-trained LLM before any post-training: a simulator of its training distribution that completes text rather than answering. All capability, no manners \u2014 it will happily continue a question with three more questions.",
    "decoder-only": "The architecture of every modern LLM: one stack of causally-masked transformer blocks that only ever predicts the next token. No encoder, no second sequence to attend to \u2014 the design that won by being the simplest thing that scales.",
    "pre-norm": "Placing normalization at the input of each sub-layer instead of after it, leaving a clean gradient path through the residual additions. The arrangement that made 100+-layer stacks trainable without the original post-norm design's fragile warmup gymnastics.",
    "SiLU": "The smooth activation z\u00b7\u03c3(z), also called swish \u2014 the squash inside SwiGLU's gate path in nearly every modern LLM MLP.",
    "logit lens": "Applying the unembedding to intermediate residual-stream states to watch the model's next-token guess sharpen layer by layer \u2014 direct evidence that the stream is a progressively refined prediction, not an opaque scratchpad.",
    "RoPE base": "The constant b in RoPE's frequency spectrum \u03b8\u1d62 = b^(\u22122i/d): 10,000 originally, 500,000 in Llama 3. Raising it slows every rotation dial at once \u2014 the first ingredient of long context.",
    "online softmax": "Update rules that correct a running max, normalizer, and output as each new tile of scores arrives \u2014 the exact softmax computed without ever holding the full score matrix. The identity that makes FlashAttention possible.",
    "SRAM": "The small, very fast on-chip memory sitting next to a GPU's compute units. FlashAttention's entire trick is keeping attention tiles resident there instead of round-tripping the T\u00d7T score matrix through HBM.",
    "linear attention": "Replacing softmax with feature maps so attention becomes associative and runs in O(T) with a fixed-size state. Historically a quality trade-off; now resurfacing inside SSM-attention hybrid architectures.",
    "NVLink": "NVIDIA's high-bandwidth GPU-to-GPU interconnect inside a server \u2014 the island within which tensor parallelism is affordable, since splitting matmuls costs an all-reduce every single layer.",
    "all-reduce": "The collective operation that sums a tensor across devices and hands every device the full result \u2014 how data-parallel replicas merge gradients each step and tensor-parallel shards merge activations each layer.",
    "micro-batches": "The small slices of a batch streamed through pipeline-parallel stages so all stages stay busy at once. More micro-batches per step shrink the idle 'bubble' at the pipeline's ramp-up and drain.",
    "context parallelism": "Splitting the sequence dimension itself across GPUs \u2014 ring attention passes KV blocks between them \u2014 so million-token training fits in memory. The fourth axis alongside data, tensor, and pipeline parallelism.",
    "master weights": "The FP32 copy of the parameters kept alongside the BF16 compute weights in mixed-precision training. Updates accumulate there, so millions of tiny optimizer steps aren't silently rounded away.",
    "FP16": "16-bit float with a 5-bit exponent \u2014 range capped at \u00b165,504, which forced the loss-scaling dance during training. Displaced by BF16 for training; still common in inference.",
    "WSD": "Warmup\u2013stable\u2013decay: hold the learning rate flat after warmup and decay only in a final phase. Any plateau checkpoint can be branched into its own decay run \u2014 why continual-pre-training shops prefer it to cosine.",
    "GAE": "Generalized advantage estimation \u2014 PPO's method for scoring how much better each token was than expected, computed against a learned value model. The machinery GRPO deletes by substituting a group-mean baseline.",
    "value network": "The learned critic in PPO that predicts expected reward so per-token advantages can be computed. One of RLHF-PPO's four networks in flight \u2014 and the one GRPO's group baseline renders unnecessary.",
    "sycophancy": "Telling the user what they want to hear \u2014 a classic harvest of over-optimizing a learned reward, since agreement rates higher than correction. Scales with capability, which is exactly the worry.",
    "red-teaming": "Deliberate adversarial probing of a model for harmful, deceptive, or policy-breaking behavior before release. The release gate at the end of every production post-training pipeline.",
    "double quantization": "QLoRA's second-order trick: quantize the per-block scale factors themselves, clawing back another ~0.4 bits per parameter on top of NF4.",
    "eval contamination": "Your test set leaking into training data, producing benchmark numbers that are fiction. The reason fine-tuning data must be decontaminated against your evals before a single step is taken.",
    "PTQ": "Post-training quantization \u2014 compressing a finished model with a small calibration set and no retraining. Minutes to hours of work, and how virtually every deployed quantized LLM is made.",
    "GGUF": "The single-file model format of llama.cpp and Ollama: group-wise quantized weights (Q4_K and friends) packed with tokenizer and metadata. The lingua franca of local inference.",
    "exposure bias": "The train/test mismatch baked into teacher forcing: a model trained only on perfect prefixes never learns to recover from its own mistakes. On-policy distillation exists largely to fix it.",
    "calibration set": "The few hundred representative samples a post-training quantization method runs through the model to observe real activations \u2014 the only data GPTQ or AWQ ever see.",
    "tensor cores": "The GPU units that execute small matrix multiplies natively and deliver nearly all of an accelerator's peak FLOPs. If an operation can't be phrased as a matmul, it doesn't get the speed \u2014 which is why 2:4 sparsity is the only sparsity they reward.",
    "pruning": "Zeroing connections outright \u2014 by magnitude, by activation-weighted ranking (Wanda), or with GPTQ-style reconstruction (SparseGPT). Cheap to do, hard to monetize: random zeros don't speed up dense matmul hardware.",
    "draft model": "The small, fast model in speculative decoding that proposes several tokens for the target model to verify in one parallel pass. Pays off when it agrees often \u2014 predictable text like code is its happy place.",
    "rejection sampling": "Accept a drafted token with probability min(1, p/q); on rejection, resample from the corrected residual distribution. The rule that makes speculative decoding provably preserve the target model's exact output distribution.",
    "SLO": "Service-level objective \u2014 the latency promise (TTFT, TPOT) a serving stack commits to per request. Goodput counts only the requests served inside it, which is why schedulers ride the throughput\u2013latency curve explicitly.",
    "vLLM": "The open-source serving engine that introduced PagedAttention and made continuous batching the industry default \u2014 the reference implementation for nearly everything in modern LLM inference.",
    "MTP": "Multi-token prediction \u2014 auxiliary heads trained to guess several future tokens per position. DeepSeek-V3 ships them as a built-in drafter for speculative decoding, no separate draft model needed.",
    "all-to-all": "The collective where every GPU sends a different slice to every other GPU \u2014 the communication pattern expert parallelism pays at each MoE layer to route tokens to their experts and gather the results back.",
    "NTK-aware scaling": "RoPE context extension that raises the base b so fast dimensions are barely touched while slow ones stretch to cover the longer window \u2014 extension without retraining from scratch. YaRN refines the idea with per-frequency interpolation.",
    "cross-attention": "Attention where queries come from one sequence and keys/values from another \u2014 how Flamingo-lineage multimodal models let a language stack tap a vision encoder mid-layer.",
    "scalable oversight": "The open problem of supervising models more capable than their supervisors \u2014 the point past which human ratings stop being a trustworthy training signal. The live research front of alignment.",
    "circuit tracing": "Interpretability work that maps one specific behavior end-to-end through identified attention heads and features. Works for small behaviors today; certifying a frontier model's reasoning remains far out of reach.",
    "VAE": "Variational autoencoder \u2014 an encoder\u2013decoder trained so its compressed latent space is smooth enough to sample from. In the image stack it's the compressor: Stable Diffusion denoises in a VAE latent, and the decoder restores pixels at the end.",
    "ELBO": "The evidence lower bound \u2014 the tractable surrogate for log-likelihood that variational methods maximize. Masked diffusion's weighted unmasking loss is a principled ELBO, not a heuristic.",
    "DiT": "Diffusion transformer \u2014 the backbone that replaced U-Nets for denoising (SD3, Sora-class video runs DiT over spacetime patches), so both great generative families now share one architecture.",
    "U-Net": "The encoder\u2013decoder CNN with skip connections that served as diffusion's denoising backbone from DDPM through Stable Diffusion \u2014 multi-scale by construction, which denoising needs: global layout and local texture at once.",
    "rectified flow": "Flow matching with deliberately straight noise\u2192data paths: regress the constant velocity x\u2081 \u2212 x\u2080 along the line between them. Straighter paths need fewer integration steps at sampling \u2014 the formulation behind SD3 and Flux.",
    "DDIM": "The deterministic, skippable reformulation of DDPM sampling: same trained network, but the reverse walk takes ~50 steps instead of 1,000. The first big step-count collapse, and the on-ramp to ODE-based samplers.",
    "implicit Bayesian inference": "The leading account of why in-context learning works: the model behaves as if it infers which latent document type produced the prompt, then continues accordingly (Xie et al. 2021). A behavioral description, not an architecture fact \u2014 no posterior is computed anywhere in the network.",
    "positional priors": "The trained tendencies that make location in context matter: strong at the start, strong at the end, a trough in the middle. Attention could reach anywhere; training data taught it where to look.",
    "needle-in-a-haystack": "The long-context benchmark family: plant one fact in a huge context and ask for it back. Frontier models now ace it \u2014 which says little about multi-fact reasoning over the same window.",
    "held-out set": "Evaluation cases deliberately kept out of the tuning loop and consulted only to confirm a change before shipping. The moment you iterate against it, it stops measuring generalization.",
    "post-training": "Everything done to a model after pre-training \u2014 SFT, RLHF, RLVR \u2014 that turns a document-completer into an assistant. System-prompt authority, chat formatting, and instruction-following are all installed here; none are architectural.",
    "instruction-tuned model": "A model post-trained on instruction\u2192response data so plain requests work zero-shot. The reason expert-flattery roles add little: post-training already collapsed the persona prior onto competent-expert.",
    "compound tasks": "Prompts demanding several deliverables in one response. Joint success is roughly the product of per-requirement probabilities \u2014 six 90% requirements make a coin flip \u2014 so decompose and verify between steps instead.",
    "pink-elephant problem": "The salience trap of prohibitions: every token of \"do not mention the outage\" places the outage squarely in attendable context. Mitigated by pairing every don't with a do.",
    "XML tags": "Angle-bracket delimiters (<analysis>\u2026</analysis>) marking regions of a prompt or output. Rare token sequences attention can bind to exactly, no escaping rules, parseable the moment they close \u2014 and Claude-family models are conspicuously trained on them.",
    "decomposition": "Splitting one hard prompt into subproblems solved in sequence, each verified output feeding the next. Converts a single low-probability mega-task into several high-probability steps with inspection gates between them.",
    "task recognition": "What few-shot examples mostly transmit: which task \u2014 format, label space, input distribution \u2014 rather than how to do it. Min et al. (2022) showed random labels in the demos barely dent accuracy; larger models add genuine rule extraction on top.",
    "semantic priors": "What a model already believes a label or word means from pre-training. Small models lean on them and ignore your flipped few-shot labels; frontier models override them and follow the demonstrations.",
    "saturation curve": "The shape of accuracy versus example count: a steep rise that flattens fast, with the largest single jump from zero to one shot. Format tasks saturate by two examples, classification by four to eight, reasoning barely moves.",
    "common-token bias": "The few-shot skew toward labels made of frequent tokens, independent of the input. One of Zhao et al.'s three demonstration biases, alongside majority-label and recency.",
    "cosine similarity": "The standard closeness measure between embedding vectors \u2014 the cosine of the angle between them, length ignored. The metric behind nearest-neighbor example retrieval and most RAG ranking.",
    "label space": "The set of allowed outputs for a classification task. Few-shot examples transmit it implicitly \u2014 show three sentiment labels and the model stops inventing a fourth.",
    "contextual calibration": "Few-shot debiasing: measure the model's prediction on a content-free input like \"N/A\" and divide that skew out. Recovers most of the accuracy lost to ordering and label-frequency biases \u2014 when you control the decoding stack.",
    "scratchpad": "The intermediate tokens a model writes while reasoning \u2014 not commentary on the computation but the computation itself: each emitted token buys another serial pass through the layers and becomes readable working memory for every later step.",
    "latent variable": "A quantity the math sums over but nobody observes \u2014 in CoT analysis, the reasoning path between question and answer. Chain-of-thought samples one path explicitly and conditions on it instead of averaging them all away.",
    "Monte Carlo": "Estimating a quantity by random sampling rather than exact computation. Self-consistency is Monte Carlo over reasoning paths: sample N chains and let the plurality vote approximate the model's marginal answer.",
    "Tree-of-Thoughts": "Test-time search over partial reasoning chains: branch at intermediate steps, score the branches, expand the promising ones. Self-consistency's more ambitious cousin \u2014 rarely worth the orchestration below frontier-hard tasks.",
    "cons@64": "Consistency at 64: accuracy when 64 sampled reasoning chains vote and the plurality answer is graded. The standard eval flavor of self-consistency on frontier reasoning benchmarks.",
    "effort dial": "The API control that replaced \"think step by step\" on reasoning models: a categorical tier (minimal \u00b7 low \u00b7 medium \u00b7 high) under which the model budgets its own thinking tokens. You stopped steering the path and started budgeting it.",
    "reasoning model": "A model RL-trained against verifiable rewards until long internal chains \u2014 backtracking, self-checks \u2014 became default behavior. Prompt the outcome and dial the effort; manual CoT instructions fight the trained policy and often hurt.",
    "plan-then-solve": "The decomposition pattern that asks for a plan first, then its execution step by step. Fixes diving in mid-problem; shines on multi-constraint tasks where missed requirements, not bad arithmetic, kill you.",
    "self-correction": "Asking a model to review and fix its own answer. With an external signal \u2014 tests, validators, retrieval \u2014 it works; without one it frequently talks itself out of correct answers, measured as net-negative on reasoning benchmarks (Huang et al. 2024).",
    "compositional generalization": "Solving problems built from familiar pieces combined in harder ways than anything demonstrated. The signature win of least-to-most prompting.",
    "structured output": "Model output shaped for a parser rather than a person: fixed fields, schemas, machine-checkable syntax. The moment output feeds code, formatting stops being style and becomes contract.",
    "function calling": "The API pattern where the model emits a schema-validated call to a named tool instead of prose \u2014 structured output wearing a dispatcher. The description strings in the tool schema are the highest-leverage prompt tokens you own.",
    "context-free grammar": "A formal ruleset defining which strings are legal \u2014 JSON, SQL, your DSL. Constrained decoding compiles one into an automaton that masks every token the grammar forbids.",
    "self-critique": "A second pass in which the model grades a draft against explicit criteria before revising. Works only when the critic runs in a fresh context \u2014 an author still warm in its own transcript reliably approves its own work.",
    "red team": "A review run as an attack: a hostile-reviewer persona hunting failure modes, edge cases, and abuse paths instead of gentle fixes. Findings are candidates, not confirmations \u2014 demand a concrete reproduction trigger per finding.",
    "rubric": "A short list of checkable criteria \u2014 each quotable, falsifiable, pass/fail \u2014 that converts \"make it better\" into verdicts a critic must defend by pointing at text. Many small booleans beat one holistic 1\u201310.",
    "revision drift": "The failure where a model \"improving\" a draft quietly rewrites the parts that were already right. Leashed with one instruction: change nothing the critique did not flag.",
    "quote-to-convict": "The critique rule that every verdict must cite the exact text earning it. Doubles as a hallucination filter: a criticism that cannot point at words is usually invented.",
    "prospective hindsight": "The pre-mortem's engine: presuppose the failure already happened \u2014 \"it is six months later; explain\" \u2014 instead of asking what could go wrong. The tense shift measurably increases the number and specificity of failure causes generated.",
    "HumanEval": "OpenAI's benchmark of small Python functions graded by hidden unit tests \u2014 the standard scoreboard for code generation, reported as pass@k.",
    "noise floor": "How much an eval score wobbles when nothing changes \u2014 binomial noise at small n, sampling variance always. At n = 20 the 95% interval spans roughly \u00b120 points; gating on movements smaller than the floor breeds alarms nobody trusts.",
    "standard error": "The expected wobble of an estimated rate: \u221a(p(1\u2212p)/n) for a pass rate over n cases. The reason a 20-case eval catches a collapse but cannot certify a 5-point refinement.",
    "flip rate": "The fraction of pairwise verdicts that change when the two candidates swap presentation order. A judge audit needing zero ground truth: every flip means the seating chart, not the quality, got read.",
    "length bias": "The LLM-judge tendency to reward longer answers regardless of content \u2014 verbosity reads as effort. Countered with length-controlled win rates and an explicit do-not-reward-length rubric line.",
    "MT-Bench": "The 2023 benchmark (Zheng et al.) that legitimized LLM-as-judge: frontier judges agreed with human majority preference about as often as humans agree with each other. Its strict variant counts only wins that survive an order swap.",
    "reference answer": "A known-good answer handed to an LLM judge as the comparison anchor. The cheapest fix for style-over-substance bias: correctness gets graded against something, not against polish.",
    "mega-prompt": "The 3,000-word accumulation of patches where the actual task hides on line 41 and two format rules contradict. Refactor it like legacy code \u2014 dedupe, delete rules that cite no failure \u2014 with an eval to prove the refactor safe.",
    "ground truth": "The verified correct answer an evaluation compares against \u2014 tests pass, label matches, number checks. Whatever an eval cannot anchor to ground truth it must anchor to a judge, who then needs auditing in turn.",
    "sandbox": "The bounded environment an agent's tool calls execute in \u2014 filesystem, process, and network walls sized so the worst permitted action is affordable. It protects the host from the agent, not the sandbox's contents from the agent: secrets mounted inside are inside the blast radius.",
    "allowlist": "A permission policy that enumerates the finite set of safe actions and refuses everything else. The alternative \u2014 denylisting bad commands \u2014 is a parlor game against an attacker who can base64-encode.",
    "kill switch": "One flag that halts new agent runs and drains in-flight ones. Fire-drill it quarterly: a kill switch that has never been pulled is a hypothesis, not a control.",
    "regression suite": "The golden set plus one new task per fixed incident, run nightly and pre-deploy. It only grows; deleting a task requires a written reason.",
    "span tree": "The nested structure of an agent trace: each step is a timed span, and sub-agent work nests under the step that spawned it. Borrowed from distributed-systems tracing, which solved the same problem first.",
    "orchestrator": "The agent that owns the plan in a multi-agent system: it decomposes the task, briefs the workers, and holds only their results in its window. Also the serial bottleneck at the end of every parallel fan-out.",
    "scaffold": "Everything wrapped around the model in a benchmark or product run \u2014 tools, prompts, retry budget, verifiers. A leaderboard number is a property of model plus scaffold together; nothing about the model alone transfers.",
    "task horizon": "METR's capability metric: the longest task, in human time, a model completes at 50% reliability. The fitted curve doubles roughly every seven months \u2014 and shrinks about 5\u00d7 when the success bar moves to 80%.",
    "memory file": "A curated, project-scoped document of conventions, decisions, and preferences (the CLAUDE.md pattern), loaded into the stable prefix of every session. Stale entries get treated as live truth, which is why writes go through review.",
    "progressive disclosure": "Keeping lightweight references in context \u2014 file paths, titles, schema names \u2014 and letting the agent fetch full content on demand. The context holds the map; tools fetch the territory.",
    "BM25": "The classic keyword-ranking function for lexical search. Paired with embeddings in hybrid retrieval because it trivially catches exact identifiers \u2014 error codes, function names \u2014 that semantic similarity famously misses.",
    "single-writer rule": "One agent per mutable resource. Two agents editing the same file is a merge-conflict generator with extra steps; the stable multi-agent shape is read-heavy fan-out feeding a single writer.",
    "fan-out": "Dispatching independent subtasks to parallel workers at once. It multiplies token spend but collapses wall-clock to the slowest branch plus synthesis \u2014 and only pays when the subtasks are genuinely independent.",
    "actionable density": "Of the tokens a tool returns, the fraction that bears on the model's next decision. Raw API payloads sit near 0.05; good tools filter, rename, round, and summarize at the boundary to push it toward 1.",
    "cross-server shadowing": "An MCP attack where one server's tool descriptions manipulate how the model uses another server's tools \u2014 possible because every connected server's words land in the same context and steer the same policy.",
    "MCP server": "A separate process, local or remote, exposing tools, resources, and prompts to any MCP-speaking host over JSON-RPC. Its descriptions and results flow straight into your model's context \u2014 treat an untrusted server exactly like untrusted code.",
    "content quarantine": "An injection defense that tracks the provenance of untrusted text and fences it off from acting as instructions. The most principled of the defenses \u2014 and still not airtight, since cleanly separating data from commands remains an open problem.",
    "CaMeL": "A defense design that splits the agent into a privileged model that plans and a quarantined model that reads untrusted content, so injected text never reaches the part that can act.",
    "defense in depth": "Stacking imperfect defenses \u2014 quarantine, allowlists, human gates \u2014 so an attack must beat all of them, while designing so the lethal trifecta never assembles in one agent in the first place.",
    "accessibility tree": "The structured, named-element view of a UI that screen readers consume. For computer-use agents it beats raw pixels: elements to act on instead of coordinates to guess.",
    "exfiltration": "Smuggling private data out through any channel an attacker can observe \u2014 a URL, an email, a webhook. The payoff of prompt injection, and the reason an agent's outbound channels deserve the most paranoia.",
    "microVM": "A minimal virtual machine (Firecracker is the canonical one) that gives each agent its own guest kernel. The isolation tier for untrusted code at scale, where a shared-kernel container escape would be fatal.",
    "default-deny": "The network posture for agent sandboxes: block all egress, then allowlist a short list of package registries and APIs. An injected agent with no egress can only corrupt its own cell; the same agent with open egress can exfiltrate everything in it.",
    "human gate": "A hard stop that routes an irreversible action \u2014 deploy, send, delete, pay \u2014 through a human before it executes. Gate by undo cost, not anxiety: gating the recoverable mints fatigue, not safety.",
    "plan gate": "A mechanical check of the plan before the first expensive action: do the referenced files exist, are all constraints covered, is the step count inside budget? A verifier for intentions \u2014 it catches the failure class where every step succeeds toward the wrong goal.",
    "stop condition": "An explicit answer to when the loop ends that does not rely on the model's own judgment: budget caps, progress windows, loop detection, an external watchdog. 'When the model decides it's done' is the thing being supervised, not an answer.",
    "loop detection": "Hashing recent (tool, arguments) pairs to catch an agent repeating itself \u2014 the same call N times, or A\u2192B\u2192A oscillation. External by necessity: a looping model's own context normalizes the repetition.",
    "budget caps": "Hard per-run ceilings on steps, tokens, dollars, and wall-clock, enforced by the harness inside the loop \u2014 never merely requested in the prompt. A cap hit should end in a graceful summarize-and-stop, logged as its own failure class.",
    "critical path": "The longest chain of serially dependent steps, which sets wall-clock latency regardless of total work. Cost follows the sum; latency follows the critical path \u2014 fan-out shortens the second while growing the first.",
    "state amnesia": "The long-horizon failure mode where compaction and restarts shed the agent's decisions and their reasons until it relitigates or contradicts its own past. The cure is moving program state out of the window into durable files.",
    "ratchet": "The recovery discipline of committing after every verified-green state and never on red, so history is a monotone sequence of working states and undo is one git reset. Cheap rollback is what makes aggressive attempts affordable.",
    "eval pyramid": "The layered eval stack: deterministic prompt asserts at the base, tool-call accuracy, judged trajectories, and expensive end-to-end task success at the tip. Volume falls as fidelity rises, and each layer catches what the one below cannot see.",
    "pass@1": "Success probability with a single attempt \u2014 what a production agent actually experiences. A pass@8 headline is legitimate only when a real verifier picks the winner among eight; otherwise the k is doing the marketing.",
    "pass^k": "The probability that all k runs succeed \u2014 the reliability view, punishing variance where pass@k rewards it. The number an operator who must trust every run should be asking for.",
    "outcome leakage": "A judge bias unique to trajectories: if the judge can see the run ended in success, it retroactively scores every step as reasonable. Strip the final outcome when you want a genuine process grade.",
    "cache hit rate": "The fraction of input tokens served from the provider's prefix cache, billed at roughly a tenth of the fresh-token rate. A prompt edit that silently breaks the stable prefix shows up here first \u2014 and doubles the bill.",
    "resolution rate": "The fraction of agent runs that actually solve the task \u2014 the denominator that converts cost per run into cost per resolved task. Sloppy model down-tiering destroys it quietly, which is why routing changes are approved on cost per resolved task, never cost per run.",
    "SWE-bench Verified": "The human-validated subset of SWE-bench: real GitHub issues an agent must patch inside a containerized repo, graded by the repo's own tests. Resolution is verified by execution, not judgment \u2014 but the score belongs to model plus scaffold, not the model alone.",
    "OSWorld": "A benchmark of real desktop tasks driven through screenshots, clicks, and keystrokes \u2014 the standard yardstick for computer-use agents. Success rates went from roughly 15% to above 60% in two years, against a human baseline near 72%.",
    /* ---- V2 expansion terms ---- */
    "ANOVA": "Analysis of Variance: an omnibus test that splits total variation into between-group and within-group sums of squares and compares them via the F-ratio F = MS_between / MS_within, testing whether three or more group means are equal.",
    "Backdoor criterion": "Pearl's rule for choosing an adjustment set: control for a set of variables that blocks every non-causal 'backdoor' path from X to Y without opening a collider. Doing so lets observational data recover the true causal effect.",
    "Base-rate neglect": "The error of judging P(H|E) from the likelihood P(E|H) while ignoring the prior P(H). It is why a 99%-accurate test for a 1%-prevalence disease is correct only about one in six times it fires positive.",
    "Bayes' theorem": "The rule that inverts a conditional: P(H|E) = P(E|H)P(H)/P(E). It updates a prior belief into a posterior by scaling it with how well the hypothesis predicts the evidence, then renormalizing.",
    "Borderline-SMOTE / ADASYN": "SMOTE variants that spend synthetic points where they help most: Borderline-SMOTE only interpolates from minority points near the decision boundary, while ADASYN generates inversely to local density, pouring more synthetic mass where the minority is hardest to learn.",
    "Box-Cox transform": "A one-parameter family of power transforms, (x^lambda - 1)/lambda (log at lambda=0), applied to strictly positive data with lambda chosen by maximum likelihood to make the distribution as Gaussian as possible. Yeo-Johnson extends it to zero and negative values.",
    "Central Limit Theorem": "The result that the average of many independent draws from any distribution with finite mean and variance becomes approximately Normal as the sample size grows — which is why the bell curve appears everywhere a quantity is a sum of small effects.",
    "Class weights": "Cost-sensitive learning that multiplies each example's loss by a class-dependent weight, typically the inverse-frequency w_c = N / (C · N_c). It is the loss-level twin of over-sampling — it amplifies the minority's voice in the gradient without adding rows — and effectively moves the decision threshold toward the rare class.",
    "Conditional probability": "The probability of A given that B has occurred, P(A|B) = P(A∩B)/P(B). It renormalizes belief to the smaller world where B is known to hold, and is the engine of all learning from evidence.",
    "Confidence interval": "A frequentist interval whose stated level describes the long-run coverage of the procedure across repeated experiments, not the probability that this particular interval contains the fixed parameter.",
    "Confounder": "A hidden variable Z that causes both X and Y, manufacturing a correlation between them even when no direct X→Y effect exists. Adjusting (conditioning) on the confounder removes the spurious association.",
    "Conjugate prior": "A prior whose family is preserved under the likelihood, so the posterior stays in the same family and updating is pure arithmetic on the parameters. Beta–Binomial and Normal–Normal are the canonical pairs.",
    "Credible interval": "An interval that contains the parameter with a stated posterior probability given the data, e.g. P(θ ∈ [L,U] | D) = 0.95 — the direct probability statement a confidence interval is often mistaken for.",
    "Cyclical encoding": "Representing a periodic quantity (hour, day-of-week, month) as a sine/cosine pair, sin(2πt/P) and cos(2πt/P), so that the end of the cycle sits next to its start. It removes the false discontinuity a raw integer encoding places between, e.g., hour 23 and hour 0.",
    "Decontamination": "The first-class pipeline step of verifying that no training example, or a trivial variant of one, also appears in the validation or test set — typically via row hashing. Eval contamination silently turns measured generalization into memorization and is the same discipline that fine-tuning a model demands against its benchmarks.",
    "Detailed balance": "The reversibility condition π_i P_ij = π_j P_ji for all i, j. It is a stronger, local sufficient condition that implies stationarity, and is the property Metropolis–Hastings engineers to make a chain target any chosen π.",
    "Directed acyclic graph (DAG)": "A causal diagram whose nodes are variables and whose arrows are direct causal effects, with no cycles. The DAG's structure (forks, chains, colliders) dictates which variables must be adjusted for to estimate a causal effect.",
    "do-operator": "Notation P(Y | do(X=x)) for the distribution of Y when X is set by intervention rather than merely observed. Intervening severs all arrows pointing into X — exactly what a randomized controlled trial does physically.",
    "Eckart–Young theorem": "The result that truncating an SVD to its top k singular values gives the best possible rank-k approximation of a matrix, with Frobenius error exactly √(Σ_{i>k} σᵢ²). It underlies PCA, image compression, and latent-factor recommenders.",
    "Entropy": "The average surprisal of a random source, H(p) = -Σ p(x) log p(x). It measures uncertainty in bits (log base 2) and is the irreducible lower bound on how many bits per symbol any lossless code can use. Maximal for the uniform distribution, zero for a point mass.",
    "Ergodicity": "The property of a chain that is irreducible (every state reachable from every other) and aperiodic (not locked into a cycle). Ergodic finite chains converge to a unique stationary distribution from any start, and time-averages equal space-averages.",
    "Estimator": "A rule that maps a sample to a guess about a population parameter (e.g. the sample mean for the population mean). Being a function of random data, it has its own distribution, summarized by its bias and variance.",
    "Feature-selection bias": "The upward bias in a performance estimate that occurs when features are chosen using the entire dataset before cross-validation, leaking the test folds' labels into the selection. With p≫n it can fake high accuracy on pure noise; nested cross-validation, which selects inside each fold, removes it.",
    "Focal loss": "A modified cross-entropy, FL = −α_t (1 − p_t)^γ log p_t, whose modulating factor (1 − p_t)^γ down-weights easy, already-correct examples (p_t → 1) and keeps the gradient focused on hard ones. With γ = 0 it is plain cross-entropy; γ = 2 lets a flood of easy negatives stop drowning the rare positives.",
    "Group leakage": "Leakage caused by a random split scattering rows that belong to the same entity (patient, user, document) across train and test, so the model is tested on entities it has effectively already seen. The fix is a grouped split that keeps every entity wholly on one side of the boundary.",
    "Heavy tail (fat tail)": "A distribution whose probability of extreme values decays far more slowly than a Normal's — polynomially rather than exponentially. Financial returns are heavy-tailed, so Normal-based risk models systematically under-price catastrophic moves.",
    "Hidden Markov Model (HMM)": "A Markov chain whose states are unobserved; you see only emissions whose distribution depends on the current hidden state. Likelihood (forward), decoding (Viterbi), and learning (Baum–Welch) are solved by dynamic programming in O(K²T).",
    "Hierarchical model": "A multi-level model in which group parameters are drawn from a shared hyper-prior, letting estimates borrow strength across groups (partial pooling) and shrink noisy small samples toward the population mean.",
    "Independence": "Two events are independent when knowing one tells you nothing about the other, equivalently when their joint probability factors: P(A∩B) = P(A)P(B). It is a property of the probabilities, not of the physical situation.",
    "Interaction feature": "A new feature formed by combining two or more inputs (most commonly the product x1·x2) so that a model can express effects in which one variable's influence depends on another. A single interaction term can make XOR-like data, which no straight line can separate, linearly separable.",
    "Kendall's τ": "A rank-correlation coefficient defined as the difference between concordant and discordant pairs divided by the total number of pairs. It equals P(concordant) − P(discordant), is highly robust to outliers, and behaves well in small samples.",
    "kNN imputation": "Filling a hole with the (distance-weighted) average of the k most similar rows, where similarity is computed over the columns both rows observe. It preserves local structure and inter-column correlation but needs features on a comparable scale and degrades in high dimensions.",
    "Kolmogorov's axioms": "The three rules all probabilities obey: non-negativity, total probability one, and additivity over mutually exclusive events. Every theorem in probability follows from them.",
    "Kurtosis": "The standardised fourth moment, measuring how much probability sits in the tails. The Normal has kurtosis 3, so practitioners report excess kurtosis (kurtosis minus 3): zero for a Normal, positive for heavy-tailed distributions that throw extreme values more often.",
    "L2 norm": "A vector's Euclidean length, √(Σ vᵢ²) = √(v·v). The norm of (3,4) is 5. Its companions are the L1 norm (sum of absolute values, source of sparsity) and the max norm (largest absolute entry).",
    "Lasso (L1 regularization)": "Linear regression with a penalty proportional to the sum of absolute coefficients (λΣ|βj|). The corners of the L1 constraint region drive many coefficients to exactly zero, so the fit performs feature selection and estimation in one optimization; L2 (ridge) only shrinks, never zeros.",
    "Law of large numbers": "As independent samples accumulate, their running average converges to the true expectation E[X]. The convergence is slow, with error shrinking like 1/√n, and it links Kolmogorov's abstract probability to long-run frequency.",
    "Likelihood": "The probability a model assigns to the observed data as a function of the parameter, p(D | θ). It is the channel through which evidence pulls the prior toward whatever the data support.",
    "MAP estimate": "Maximum a posteriori: the mode of the posterior, equal to the MLE with the log-prior added back in. It coincides with the MLE under a flat prior and is the Bayesian reading of regularized estimation.",
    "MAR": "Missing at random: the probability of missingness depends only on observed data, not on the missing value itself. Despite the name it is not 'random' — it is recoverable by conditioning on the observed predictors, which is what kNN, MICE, and model-based imputation exploit.",
    "Markov Chain Monte Carlo (MCMC)": "A family of methods that sample from a target distribution by constructing a Markov chain whose stationary distribution is that target, then running it. It needs the target only up to a normalizing constant, which is why it dominates Bayesian computation.",
    "Markov property": "The memorylessness assumption: the probability of the next state depends only on the current state, not on the full history of how the chain arrived there. It collapses a sequence into a transition matrix.",
    "Maximum likelihood (MLE)": "An estimation method that picks the parameter value making the observed data most probable, by maximizing the log-likelihood. MLEs are consistent, asymptotically normal, and asymptotically efficient, underpinning regression and most ML loss functions.",
    "MCAR": "Missing completely at random: the probability of a value being missing is independent of every value, observed or unobserved. The observed rows are then an unbiased subsample, so complete-case analysis is valid (only less efficient).",
    "Mean imputation": "Filling every missing entry of a column with the mean of its observed values. Simple and unbiased for the column mean under MCAR, but it shrinks variance by a factor (n−m)/n and erases the column's correlations with other features.",
    "Memorylessness": "The property that elapsed waiting time gives no information about remaining waiting time. The Exponential is the only continuous distribution with it, and the Geometric the only discrete one.",
    "Metropolis–Hastings": "The canonical MCMC algorithm: propose a move from q, then accept it with probability min(1, [π(θ')q(θ|θ')]/[π(θ)q(θ'|θ)]). The target's unknown normalizer cancels in the ratio; Gibbs sampling is the special case with acceptance always 1.",
    "MICE": "Multiple Imputation by Chained Equations (fully conditional specification): iteratively regress each column with missing data on all the others and draw new fills from that conditional model, sweeping until convergence. Run M times and pool with Rubin's rules to carry imputation uncertainty into final standard errors.",
    "Minority prevalence (π)": "The base rate of the rare positive class, π = N_min / N. A constant majority-class predictor scores accuracy 1 − π while detecting nothing, which is why accuracy is meaningless when π is small.",
    "Missing-indicator method": "Adding a binary 'was-this-missing' column alongside an imputed feature so a flexible model can learn whether the fact of missingness is itself predictive — frequently useful under MNAR and with tree-based models.",
    "MNAR": "Missing not at random: missingness depends on the unobserved value itself (e.g. high earners hide their income because it is high). It cannot be fixed from the data alone and cannot be distinguished from MAR by any statistic on the observed data; it requires an explicit model of the missingness.",
    "Multiple comparisons": "Running many tests inflates the chance of at least one false positive (family-wise error). Corrections such as Bonferroni (test at alpha/m) or false-discovery-rate control restore error control; ignoring the problem is the core of p-hacking.",
    "Multiple imputation": "Generating M complete datasets with plausibly different fills, analysing each, and combining the results so the disagreement between imputations inflates the reported variance. Unlike single imputation, it does not pretend the filled values are certain.",
    "Mutual information": "I(X;Y) = H(Y) - H(Y|X), the reduction in uncertainty about one variable from observing another. It equals the KL divergence between the joint distribution and the product of marginals, is symmetric, and is zero exactly when X and Y are independent — capturing nonlinear dependence that correlation misses.",
    "Null space": "The set of input vectors a matrix sends to zero, Ax = 0. Its dimension (the nullity) plus the rank equals the number of columns — the rank–nullity theorem. A square matrix is invertible exactly when its null space is just the origin.",
    "One-hot encoding": "Turning a categorical column of K distinct levels into K binary indicator columns, exactly one of which is 1 per row. It implies no ordering between categories but widens the feature matrix linearly with cardinality.",
    "Ordinal encoding": "Mapping ordered categories to ascending integers (small=0, medium=1, large=2). Correct only when the categories are genuinely ranked; applied to nominal data it invents a false order the model will exploit.",
    "Out-of-fold encoding": "Computing a target-dependent encoding for a row using only the other cross-validation folds, so no row ever contributes to its own encoded value. The standard defence against target-encoding leakage.",
    "p-value": "The probability, computed assuming the null hypothesis is true, of a test statistic at least as extreme as the one observed. It is not the probability that the null is true, nor that the result is a fluke.",
    "Pearson correlation (r)": "A unitless measure in [-1, +1] of the strength and direction of the linear relationship between two variables, equal to their covariance divided by the product of their standard deviations. Geometrically it is the cosine of the angle between the two mean-centred data vectors.",
    "Polynomial feature expansion": "Augmenting the inputs with all monomials up to a chosen degree d — squares, cubes and cross-terms — to let a linear model fit curvature. The term count grows as the binomial coefficient C(n+d, d), so the expansion buys flexibility at the cost of dimensionality.",
    "Posterior": "The updated belief about a parameter after seeing data, p(θ | D) ∝ p(D | θ) p(θ). Unlike a point estimate it is a full distribution, so uncertainty is reported directly.",
    "Precision–Recall (PR) curve": "The curve of precision against recall as the threshold sweeps, summarized by PR-AUC (average precision). Because neither precision nor recall uses the true-negative count, PR-AUC exposes the false-positive cost that prevalence-insensitive ROC-AUC hides — the preferred summary metric under heavy imbalance.",
    "Prior": "The probability distribution over a parameter before observing data, encoding what you believe (or assume) at the outset. With little data it dominates the posterior; with enough data any non-dogmatic prior washes out.",
    "Probability density function (PDF)": "For a continuous random variable, a curve f(x) whose area between two points equals the probability of landing in that range; the total area under it is one. No single point carries positive probability.",
    "Probability mass function (PMF)": "For a discrete random variable, the rule p(x) giving the probability of each individual outcome, with all the masses summing to one. Bernoulli, Binomial, Poisson and Geometric are all specified by a PMF.",
    "Projection": "The point in a subspace closest to a given vector — its 'shadow' — leaving a residual orthogonal to that subspace. Projecting targets onto a design matrix's column space is exactly ordinary least-squares regression.",
    "Prosecutor's fallacy": "Confusing P(evidence|innocent) with P(innocent|evidence). A one-in-a-million random-match probability is not a one-in-a-million chance of innocence; the two differ by the prior-over-evidence factor.",
    "Random over-/under-sampling": "Two data-level rebalancing moves: over-sampling duplicates minority examples (with replacement) up to the majority count, while under-sampling discards majority examples down to the minority count. Both shift the effective prevalence the optimizer sees but add no new information.",
    "Rank": "The number of genuinely independent directions a matrix produces — the dimension of its column space, equal to the count of nonzero singular values. Real data matrices are typically near low-rank, which is what compression and LoRA exploit.",
    "Recursive feature elimination (RFE)": "A wrapper selection method that repeatedly fits the model, drops the feature the refit model ranks least important, and refits, until the desired number remains. Recomputing importances after each removal lets it keep features that only become useful once their redundant partners are gone.",
    "Robust scaling": "Centering by the median and scaling by the interquartile range instead of the mean and standard deviation, so outliers in the tails barely affect the transform. Preferred when the data has fat tails or known errors.",
    "Sample space": "The set of all possible outcomes of an experiment, written Ω. An event is any subset of it, and a probability assigns each event a number in [0, 1].",
    "Simpson's paradox": "A reversal in which a statistical trend present in every subgroup of the data flips direction once the subgroups are pooled. Both views are arithmetically correct; the pooled view is usually answering the wrong causal question.",
    "Singular Value Decomposition (SVD)": "The factorization A = UΣVᵀ that exists for every matrix: a rotation, an axis-aligned scaling by the singular values σᵢ, then another rotation. It generalizes eigen-decomposition to rectangular and rank-deficient matrices.",
    "SMOTE": "Synthetic Minority Over-sampling Technique: instead of duplicating minority points it creates new ones by interpolating, x_new = x_i + λ(x_nn − x_i) with λ ~ U(0,1), along the segment to a minority k-nearest neighbor. The synthetic points lie inside the minority's convex hull, densifying its region rather than memorizing copies.",
    "Source coding theorem": "Shannon's result that a source with entropy H needs at least H bits per symbol to encode losslessly, and can be compressed arbitrarily close to H. Entropy is therefore a hard compression limit no algorithm can beat; Huffman coding constructively approaches it.",
    "Spearman's rank correlation (ρ)": "Pearson correlation computed on the ranks of the data rather than the raw values. It measures monotone (order-preserving) association rather than linearity, reaching +1 for any strictly increasing relationship and shrugging off outliers.",
    "Standardization (z-score)": "Subtracting the mean and dividing by the standard deviation so a feature has mean 0 and unit variance. The default scaler for linear models, SVMs, PCA and neural nets; not robust to outliers and does not bound the range.",
    "Stationary distribution": "A distribution π left unchanged by the chain, πP = π — the left eigenvector of P for eigenvalue 1. For an ergodic chain it is unique and is the long-run fraction of time spent in each state.",
    "Statistical power": "The probability (1 minus the Type II error rate) of correctly rejecting a false null — i.e. detecting a real effect. It rises with effect size, sample size, and a more lenient significance level alpha.",
    "Student-t distribution": "A symmetric bell that matches the Normal in the centre but has heavier, polynomially-decaying tails controlled by the degrees of freedom nu; small nu means fat tails and it converges to the Normal as nu grows. The standard model for daily and weekly asset returns.",
    "Surprisal": "The self-information of a single outcome, I(x) = -log₂ p(x), measured in bits. Rare events carry high surprisal; certainties carry zero. It is the optimal codeword length for that outcome under source coding.",
    "Target (mean) encoding": "Replacing each category with the mean of the target for that category, usually smoothed toward the global mean. It compresses high-cardinality columns to one informative feature but leaks the label unless fit out-of-fold.",
    "Target leakage": "A specific leak where a feature is a consequence of the label rather than a cause knowable beforehand (e.g. a treatment column used to predict the diagnosis that prompted it). The feature is enormously predictive on held-out data yet useless in deployment, because at prediction time the label has not yet been realized.",
    "Temporal leakage": "Information from the future bleeding into the past — most often by fitting a scaler, imputer, or encoder on the full dataset before splitting, so training rows are transformed using statistics that include the test rows. The cure is to split first and fit all preprocessing on the training partition only.",
    "TF-IDF": "Term frequency × inverse document frequency: a text feature that weights each term by how often it appears in a document and down-weights terms common across the whole corpus. It is a cheap, interpretable baseline that distinctive words dominate and ubiquitous words barely affect.",
    "Threshold moving": "Choosing the classify-as-positive cutoff τ rather than defaulting to 0.5. Sweeping τ traces the full precision–recall trade-off from one trained model; the Bayes-optimal cut for asymmetric costs is τ* = C_FP / (C_FP + C_FN).",
    "Train/validation/test split": "A disjoint three-way partition of a dataset: training fits parameters, validation selects hyperparameters and models, and test — touched exactly once — estimates generalization. Tuning against the test set destroys its value; its entire worth is that nothing downstream of it ever saw the test data.",
    "Transition matrix": "A row-stochastic matrix P whose entry P_ij is the probability of moving from state i to state j. Every row is a probability distribution summing to 1, and one step of the chain is the multiply π ← πP.",
    "Variance inflation factor (VIF)": "VIF_j = 1/(1 − R²_j), where R²_j is the R² from regressing feature x_j on all the other features. It is the factor by which collinearity inflates that coefficient's variance; values above 5 warrant a look and above 10 signal serious multicollinearity. At R²=0.8, VIF=5.",
    "Weight of evidence (WOE)": "An encoding for binary targets that replaces each category with the log-ratio of its share of positives to its share of negatives. It lives on the log-odds scale and underpins the Information Value used in credit scoring.",
    /* ---- V2 expansion terms ---- */
    "Accuracy paradox": "On imbalanced data, a model that always predicts the majority class can score very high accuracy while catching no minority cases, so accuracy looks excellent yet the model is useless. This is why accuracy should never be reported alone on imbalanced problems.",
    "Acquisition function": "The rule that turns a surrogate's posterior mean and uncertainty into a single score for choosing the next query, balancing exploitation (go where the mean is good) against exploration (go where uncertainty is high). Common choices are confidence bounds (mu - kappa*sigma) and Expected Improvement.",
    "AdaBoost": "The original boosting algorithm (1997): it reweights training examples so that misclassified ones grow heavier each round, and votes the weak learners by α = ½·ln((1−ε)/ε). It is exactly forward stagewise additive modeling under the exponential loss exp(−yF), which also makes it sensitive to mislabeled points and outliers.",
    "AdaBoost / SAMME": "The original adaptive-reweighting boosting algorithm: misclassified points are up-weighted so the next weak learner focuses on them, and each learner gets a vote α = log((1−err)/err) + log(K−1). SAMME is the multiclass form; for K=2 it reduces to classic AdaBoost. It is sensitive to label noise because its exponential loss punishes outliers harshly.",
    "Agglomerative hierarchical clustering": "A bottom-up clustering method that starts with every point as its own cluster and repeatedly merges the two closest clusters until one remains, producing a full nested hierarchy rather than a single flat partition. The complete sequence of n-1 merges is recorded as a dendrogram.",
    "AUC (AUROC)": "The area under the ROC curve. By the Wilcoxon-Mann-Whitney identity it equals the probability that a random positive is scored above a random negative (ties split evenly): 1.0 is a perfect ranker, 0.5 is a coin flip, and below 0.5 means the score is reversed.",
    "Bagging (bootstrap aggregating)": "Breiman's method of fitting one high-variance, low-bias learner on each of k bootstrap resamples of the data and averaging (or voting) their predictions. It reduces the variance term toward the correlation floor ρσ² while leaving bias essentially unchanged.",
    "Bayesian optimization": "Informed, sequential tuning: fit a cheap probabilistic surrogate (often a Gaussian process) to past trials, then query where an acquisition function predicts the best trade-off between low predicted loss and high uncertainty. Sample-efficient when each evaluation is expensive.",
    "Bias-variance decomposition": "The exact splitting of expected squared-error test loss into bias² (how far the average model is from the truth), variance (how much it jitters as the training set is resampled), and irreducible noise σ². It is the lens that explains every ensemble method: bagging shrinks variance, boosting shrinks bias, and no method can beat the noise floor.",
    "Boosting": "An ensemble built sequentially, where each new weak learner is trained to correct the running ensemble's mistakes. Unlike bagging, it attacks the bias term by composing many high-bias weak models into one strong one; its members are correlated by construction, so it forgoes variance reduction.",
    "Brier score": "The mean squared error of predicted probabilities against binary outcomes, mean((p - y)^2). It is a strictly proper scoring rule (uniquely minimized by the true probabilities) that bundles calibration and refinement, so it is read alongside the reliability curve, never alone.",
    "Calibration": "The property that a predicted probability matches the observed frequency: among cases assigned probability p, a fraction p are truly positive. It is orthogonal to discrimination - a model can rank perfectly yet emit dishonest probabilities - and is inspected with a reliability curve.",
    "Calibration (of probabilities)": "How well a model's stated confidence matches empirical frequency. Naive Bayes is famously well-classified but poorly calibrated — correlated features make it double-count evidence and push posteriors toward 0 or 1 — so Platt scaling or isotonic regression is needed when calibrated probabilities matter.",
    "Champion/challenger": "A promotion rule in which a newly trained challenger replaces the live champion only if it beats it on the same frozen holdout metric by a margin larger than the metric's noise, and breaks no guardrail. The incumbent is the default; the challenger must earn its place.",
    "Characteristic Stability Index (CSI)": "The PSI formula applied to a single input feature rather than to the model's output score. A drifting CSI with a stable PSI says an input moved but the score has so far absorbed it.",
    "Concept drift": "A change in the relationship P(y|x) itself, so the learned function becomes wrong rather than merely under-sampled. It can be invisible in the inputs and surface only as falling accuracy, which is why it needs error monitoring and fresh labelled data to fix.",
    "Core / border / noise point": "DBSCAN's three point types. A core point has at least minPts neighbours within radius eps; a border point is within eps of a core point but not itself dense; a noise point is neither and is excluded from every cluster — the built-in outlier handling that distance-to-centre methods lack.",
    "Cost-optimal threshold": "The decision cutoff that minimizes expected misclassification cost. For calibrated probabilities it has the closed form t* = c_FP / (c_FP + c_FN), depending only on the ratio of error costs; the default 0.5 is correct only when the two error types cost the same.",
    "Covariate shift": "A change in the input distribution P(x) while the input-to-label rule P(y|x) stays fixed. It is visible from features alone and can sometimes be corrected by importance weighting without any new labels.",
    "Data drift vs concept drift": "Data drift is a change in the input distribution P(x); concept drift is a change in the input-to-label relationship P(y|x). Only concept drift necessarily degrades accuracy, but both warrant monitoring because labels often arrive too late to watch error directly.",
    "DBSCAN": "Density-Based Spatial Clustering of Applications with Noise: defines a cluster as a connected region of high point density of any shape, controlled by a radius eps and a minimum-neighbour count minPts. It needs no preset cluster count, finds arbitrarily shaped clusters, and uniquely assigns low-density points an explicit noise label.",
    "Dendrogram": "The binary tree output of hierarchical clustering: leaves are the data points and each internal node is a merge drawn at a height equal to the linkage distance at which it occurred. Cutting it with a horizontal line at some height yields a flat clustering, with large vertical gaps marking the most stable places to cut.",
    "Discriminative classifier": "A model that learns the boundary p(y | x) directly and never models how the inputs are generated. Logistic regression, SVMs and neural nets are discriminative; they usually win with abundant data, generative models with scarce data.",
    "Distance concentration": "The phenomenon, for data with independent coordinates, where the relative contrast (max−min)/min between pairwise distances tends to zero as dimension grows (Beyer et al., 1999). Lower-order norms such as Manhattan concentrate more slowly than Euclidean.",
    "Drift Detection Method (DDM)": "An online concept-drift detector that treats per-example errors as a Bernoulli stream, tracks the running error rate and its standard deviation, and alarms when the rate climbs two (warning) or three (drift) standard deviations above its best-so-far minimum.",
    "Dual problem": "The Lagrangian reformulation of the SVM in terms of the per-point multipliers alpha, in which the data appears only as inner products and the support-vector sparsity emerges from the KKT conditions. Solving the dual is what makes the kernel trick possible and yields the decision function as a weighted vote over support vectors.",
    "Energy retained (explained variance)": "The fraction Σᵢ≤ₖ σᵢ² / Σ σᵢ² of total squared singular value kept by a rank-k approximation — identical to PCA's explained-variance ratio. Plotting it against k (the cumulative scree curve) and cutting at the elbow is the standard way to choose how many components to keep.",
    "Expectation-Maximization (EM)": "The iterative algorithm that fits a GMM by alternating an E-step (fix parameters, compute each point's responsibilities) and an M-step (fix responsibilities, re-estimate weights, means and covariances as weighted statistics). Each full iteration provably never decreases the data log-likelihood, converging to a local maximum that depends on initialization.",
    "Experiment tracking": "Logging every training run's parameters, metrics, data hash, code commit, and artifacts so past results can be reproduced and compared. It answers 'what did we try and what happened?' — the searchable lab notebook the literal notebook never was.",
    "Explainability": "The discipline of answering 'why this output?' for a model in terms a human can check. It serves trust (should I act on this?), debugging (why is this wrong?), and regulation (can you justify this decision?), and is increasingly a legal compliance artifact rather than a research nicety.",
    "Forward chaining": "The rule for time-series cross-validation: every training timestamp must precede every validation timestamp in each fold (also called walk-forward or rolling-origin validation). Standard shuffled k-fold violates it and is invalid for temporally ordered data.",
    "Funk SVD": "Matrix factorization fit by gradient descent on only the observed entries of a sparse ratings matrix, minimizing regularized squared error. Named for Simon Funk's Netflix-Prize method, it sidesteps plain SVD's need for a complete matrix and is still the textbook collaborative-filtering algorithm.",
    "Gaussian Mixture Model (GMM)": "A probabilistic clustering model that treats the data as generated by k weighted Gaussian components, each with its own mean and (optionally full) covariance, so clusters can be tilted ellipses of any aspect ratio. It assigns each point a soft, fractional responsibility to every component rather than a hard label; k-means is its spherical, hard-assignment limit.",
    "Gaussian Naive Bayes": "The continuous-feature variant: each per-feature likelihood is a 1-D normal whose mean and variance are estimated per class. Its per-class density is an axis-aligned Gaussian, making it exactly Quadratic Discriminant Analysis with off-diagonal covariances forced to zero.",
    "Generalization error": "The expected loss of a model over the entire data-generating distribution, not just the rows you observed. It is the quantity every validation scheme tries to estimate; you can only ever approximate it from a finite sample.",
    "Generative classifier": "A model that learns p(x | y) and p(y) — a full account of how each class produces its data — then applies Bayes' rule to recover p(y | x). It can be sampled from to synthesize new examples. Naive Bayes, LDA/QDA and HMMs are generative.",
    "Gini coefficient": "AUC rescaled so a random model scores 0 and a perfect model scores 1, via Gini = 2*AUC - 1. It is the ratio of the area between the ROC curve and the diagonal to the area for a perfect model, and is reported alongside KS in banking model documentation.",
    "Global vs local explanation": "Scope of an explanation. A global explanation describes the model's behaviour over the whole input distribution ('income matters most on average'); a local explanation describes one prediction ('this applicant was denied chiefly for three late payments'). Right-to-explanation laws demand the local kind.",
    "Grid search": "Exhaustive tuning: pick a finite set of values per hyperparameter, evaluate every point in the Cartesian product, keep the best. Simple and reproducible, but its cost is exponential in the number of hyperparameters and it wastes budget re-testing axes that do not move the score.",
    "Grouped k-fold": "k-fold that keeps every group of related rows (same patient, video, or sensor) entirely on one side of each split. It prevents leakage in which a row and its sibling straddle the train/validation boundary and inflate the score.",
    "Hard margin vs soft margin": "The hard-margin SVM demands every point be correctly classified with margin at least 1, which is infeasible when classes overlap. The soft margin (Cortes & Vapnik, 1995) adds slack variables and a penalty C, allowing some violations in exchange for a usable, wider boundary.",
    "Hinge loss": "The loss max(0, 1 - y·f(x)) used by the SVM, where y·f(x) is the signed margin. It is zero once a point is correctly classified with margin at least 1 (giving sparsity) and rises linearly for points inside the margin or misclassified; it is the convex surrogate that makes max-margin training tractable.",
    "Histogram split finding": "LightGBM's trick of pre-binning each feature into a fixed number of buckets (default 255) and accumulating per-bin gradient and Hessian histograms, so finding the best split costs O(#bins·d) instead of O(n·d). Histogram subtraction (a child's histogram = parent − sibling) halves the work again; the cost is a slightly coarser grid of candidate cut points.",
    "Holdout": "The cheapest validation scheme: split the data once into train and test, fit on train, score once on test. Unbiased for that particular trained model but high-variance — a single random split that can swing several accuracy points on luck alone.",
    "Hyperband": "Runs successive halving across several brackets with different exploration/budget trade-offs, hedging against the unknown of how well early performance predicts final performance. The bracket idea (often as the asynchronous ASHA variant) is the default scheduler in modern tuners.",
    "Individual conditional expectation (ICE)": "A per-row version of partial dependence: one curve for each instance showing how its prediction would move as a feature sweeps. The PDP is the average of all ICE curves; when ICE lines fan out or cross, the feature interacts and the averaged PDP is misleading.",
    "Jaccard similarity": "Set overlap, |A ∩ B| / |A ∪ B|, ranging from 0 (disjoint) to 1 (identical). The matching Jaccard distance 1−J is a true metric. It ignores shared absences, making it ideal for sparse binary or set data and near-duplicate detection (via MinHash at scale).",
    "k-fold cross-validation": "Partition the data into k equal disjoint folds; in turn, each fold is the validation set while the other k-1 train the model. The mean of the k fold scores is the CV estimate, and their spread gives it error bars; k = 5 or 10 is the usual default.",
    "Kernel trick": "The observation that an SVM uses the data only through inner products, so replacing the dot product x·x' with a kernel K(x,x') = phi(x)·phi(x') trains the model in a high- or infinite-dimensional feature space without ever computing the coordinates phi(x). Mercer's theorem characterizes which functions are valid kernels.",
    "KS statistic": "The Kolmogorov-Smirnov statistic in scoring: the maximum gap between the cumulative distributions of the score among positives and negatives, equivalently the largest vertical distance between the ROC curve and the chance diagonal. A standard credit-scoring measure of separation ranging 0 to 1.",
    "Laplace / Lidstone smoothing": "Adding a pseudo-count α to every category so no estimated probability is ever zero: p(w | y) = (N_{y,w} + α) / (N_y + αV). It cures the zero-frequency problem (one unseen word vetoing a class) and is equivalent to a Dirichlet prior; α = 1 is Laplace, α = 0.5 is Jeffreys.",
    "Latent-factor model": "A recommender that assigns each user a vector pᵤ and each item a vector qᵢ in a shared k-dimensional space and predicts a rating as r̂ᵤᵢ = μ + bᵤ + bᵢ + pᵤᵀqᵢ. The dot product is the personalized interaction; the latent vectors are exactly the rows of U and V from the factorization, learned on observed entries only.",
    "Leaf-wise tree growth": "Growing a tree by always splitting the single leaf with the highest gain anywhere in the tree (best-first), as LightGBM does, versus XGBoost's level-wise growth that splits a whole depth before going deeper. Leaf-wise reaches a lower training loss for the same leaf budget but overfits more, so it is capped with num_leaves well below 2^max_depth.",
    "Likelihood (class-conditional)": "p(x | y): how plausible the observed features are under each class's generative story. In Gaussian NB it is a product of per-feature normals; in multinomial NB a product of word probabilities. The classifier multiplies it by the prior and picks the argmax.",
    "LIME": "Local Interpretable Model-agnostic Explanations. Explains one prediction by sampling perturbations around the instance, weighting them by proximity, and fitting a sparse linear surrogate to the black box's responses. Faithful only locally, and notoriously sensitive to the neighbourhood width and random seed.",
    "Linkage": "The rule for measuring the distance between two clusters (not two points) in agglomerative clustering. Single linkage uses the nearest pair (chains along filaments), complete linkage the farthest pair (forces compact balls), and Ward linkage the pair whose merge increases within-cluster squared error least.",
    "Log loss (binary cross-entropy)": "A proper scoring rule that grades predicted probabilities, not just labels: it penalizes each row by minus the log of the probability assigned to the true class. The penalty is zero for a confident-correct prediction and unbounded for a confident-wrong one, so it rewards confidence only when earned.",
    "MAE (mean absolute error)": "The mean of the absolute residuals. It punishes every unit of error equally and is far more robust to outliers than RMSE; the estimator that minimizes it is the conditional median, so MAE-tuned models favor the typical case.",
    "Mahalanobis distance": "Distance measured in units of the data's own spread: d_M = √((x−μ)ᵀ Σ⁻¹ (x−μ)), where Σ is the covariance. It deflates high-variance directions and inflates low-variance ones, reducing to Euclidean distance when Σ = I. Its constant-distance contours are ellipses aligned with the data cloud.",
    "Manhattan distance": "The Minkowski distance of order 1: the sum of absolute coordinate differences, as if walking along a city grid. More robust to outliers than Euclidean and concentrates more slowly in high dimensions.",
    "MAPE (mean absolute percentage error)": "The average absolute error expressed as a percentage of the true value, which makes error comparable across series of different scale. It explodes when any true value is near zero and is asymmetric, biasing forecasts low, so it must never be used on data containing zeros.",
    "Margin": "The distance from a classifier's decision boundary to the nearest training point of either class. A support vector machine chooses the boundary that makes this distance as large as possible; under canonical scaling the half-width margin equals 1/||w||, so maximizing the margin is the same as minimizing the weight norm.",
    "Matrix rank": "The number of linearly independent rows (equivalently, columns) of a matrix — the count of genuinely distinct patterns it contains. A rank-r matrix can be written exactly as a product of an m×r and an r×n matrix, so it carries only r(m+n) degrees of freedom instead of mn.",
    "Metric": "A distance function satisfying four axioms: non-negativity, identity of indiscernibles (zero distance means the same point), symmetry, and the triangle inequality. Euclidean, Manhattan, Mahalanobis and Jaccard distance are metrics; cosine and squared-Euclidean distance are not.",
    "Minkowski distance": "A family of distances d_p = (Σ|xᵢ−yᵢ|^p)^(1/p) controlled by an order p. p=1 gives Manhattan, p=2 gives Euclidean, and p→∞ gives Chebyshev (the largest single coordinate gap).",
    "ML pipeline": "A directed acyclic graph of typed, re-runnable stages from raw data to served prediction, where every edge is a content-addressed artifact and every node is pinned to a code commit and config. The shipped asset is the recipe that regenerates the model, not the weights file alone.",
    "MLOps": "The discipline of taking a model from notebook to a reliable production asset: versioned pipelines, experiment tracking, a model registry, CI/CD, monitoring, and the governance that makes the whole system accountable. The model is a small part of the system; MLOps is everything around it.",
    "Model registry": "A state machine over model versions with gated stages (None → Staging → Production → Archived). It enforces that at most one version is live per deployment slot, records who approved each transition, and makes rollback a one-line operation.",
    "Model risk management (SR 11-7)": "The governance framework — anchored by the US Federal Reserve/OCC's SR 11-7 (2011) — treating models as a source of risk from both error and misuse, and prescribing robust development & documentation, independent validation, and governance with sign-off and monitoring.",
    "Naive (conditional-independence) assumption": "The defining shortcut of naive Bayes: features are assumed mutually independent given the class, so the joint likelihood factors as p(x | y) = ∏_j p(x_j | y). This collapses an exponential number of parameters to O(d) per class. Almost never literally true, yet the basis of the whole method.",
    "Nested cross-validation": "Two CV loops: an inner loop selects hyperparameters and an outer loop, whose folds the selection never touches, estimates performance. It removes the optimistic selection bias that arises when you tune and report on the same folds.",
    "Non-negative Matrix Factorization (NMF)": "Factoring a non-negative matrix as A ≈ WH with both factors constrained to be ≥ 0. Because nothing can be subtracted, the data must be built as a sum of parts, so the factors come out interpretable — strokes, facial features, or text topics — fit by multiplicative update rules that preserve non-negativity automatically.",
    "Ordered target statistic": "CatBoost's leakage-free way of encoding a categorical value by the smoothed mean target of only the rows that precede it in a random permutation: (Σ_{j<i} y_j + a·p)/(count + a). Because a row's own label never enters its own encoding, the target cannot leak; the same prefix-ordering idea, applied to residuals, is 'ordered boosting'.",
    "Out-of-bag (OOB) error": "A validation estimate that comes free with bagging: since each bootstrap sample omits about 36.8% (e⁻¹) of the points, averaging each point's prediction over only the trees that did not see it gives an unbiased error estimate with no separate holdout set.",
    "Partial dependence plot (PDP)": "A global plot of the model's average prediction as one feature is swept across its range, with the other features marginalized out. It reveals the shape of a feature's effect (linear, threshold, U-shaped) but can hide subgroup heterogeneity and create off-manifold inputs for correlated features.",
    "Permutation importance": "A model-agnostic global importance measure: shuffle one feature's column to break its link to the target, and record how much the model's score drops. Large drop means the model relies on the feature. Correlated features split and hide each other's importance, so it under-reports under collinearity.",
    "Population Stability Index (PSI)": "A scalar drift measure: bin a score on a reference period (expected proportions E_i) and on a live period (actual A_i), then sum (A_i − E_i)·ln(A_i/E_i) over bins. It equals the symmetrized KL divergence; the rule of thumb is <0.1 stable, 0.1–0.25 moderate, >0.25 significant.",
    "Precision and recall": "Precision is the fraction of predicted positives that are truly positive (TP/(TP+FP)); recall is the fraction of true positives that are caught (TP/(TP+FN)). Precision matters when false alarms are costly, recall when misses are costly, and the threshold buys one at the expense of the other.",
    "Precision-recall curve": "A plot of precision against recall across thresholds, with no-skill baseline equal to the positive rate. Because precision's denominator includes false positives, the PR curve is acutely sensitive to prevalence and is the more informative summary when positives are rare.",
    "Pseudo-residual": "The negative gradient of the loss at each training point, −∂L/∂F evaluated at the current model, which gradient boosting regresses on instead of the raw labels. It is the steepest-descent direction in function space; for squared loss it equals the ordinary residual, for log-loss it is the label minus the predicted probability.",
    "Random search": "Sample each hyperparameter independently from a distribution for a fixed number of trials. At equal budget it matches or beats grid search when only a few hyperparameters matter, because it tests far more distinct values of the important axes (Bergstra & Bengio, 2012).",
    "RBF (Gaussian) kernel": "The default nonlinear kernel K(x,x') = exp(-gamma·||x - x'||^2), a smooth measure of similarity that decays with distance and corresponds to an infinite-dimensional feature map. The width gamma controls reach: small gamma gives a smooth, near-linear boundary; large gamma wraps the boundary tightly around individual points and overfits.",
    "Reference window": "The baseline distribution a monitor compares the live stream against. A fixed reference (the training set) answers 'is the model still valid?'; a sliding reference detects change but normalizes away slow incremental drift, letting a model boil like a frog.",
    "Regularization parameter C": "The soft-margin hyperparameter trading margin width against training-error tolerance. Large C punishes every violation harshly (narrow margin, low bias, high variance, approaching the hard margin); small C tolerates mistakes for a fatter, smoother margin (high bias, low variance). It is the standard regularization knob in disguise.",
    "Retrain cadence": "How often a deployed model is refit. Too often wastes compute; too rarely carries accumulating decay. Balancing amortized retrain cost against carried decay gives a square-root optimum T* = sqrt(2·c_retrain/d), the economic-order-quantity shape.",
    "RMSE (root mean squared error)": "The square root of the mean of the squared residuals. Reported in the target's own units and dominated by large errors because squaring inflates them, so it is the metric to choose when big misses are disproportionately costly. RMSE is always greater than or equal to MAE.",
    "ROC curve": "A plot of true positive rate against false positive rate as the decision threshold sweeps from high to low. Because both axes condition on the true class, the ROC curve is invariant to class prevalence and summarizes a model's discrimination independent of how positives and negatives are mixed.",
    "Search space": "The set of allowed hyperparameter configurations, usually the Cartesian product of each knob's range. Its design — log vs linear scales, sensible bounds, and which knobs to include — quietly determines how easy or impossible the tuning problem is.",
    "Second-order (Newton) boosting": "XGBoost's use of both the gradient g and the Hessian h of the loss in a second-order Taylor expansion of the objective. The closed-form optimal leaf value is w* = −G/(H+λ) and a split's gain is the children's structure scores minus the parent's, less a per-leaf cost γ — letting the model weight each example by how curved the loss is there.",
    "SHAP / efficiency axiom": "SHapley Additive exPlanations applies Shapley values to feature attribution. Its key property, efficiency (local accuracy), forces the base value plus the SHAP values to sum exactly to the prediction, so the explanation is a literal audit trail. KernelSHAP and TreeSHAP make it tractable.",
    "Shapley value": "From cooperative game theory, the unique fair way to split a payout among players, here the prediction among features. A feature's Shapley value is its average marginal contribution over all orderings in which features are added, and it uniquely satisfies efficiency, symmetry, dummy, and additivity.",
    "Shrinkage (learning rate)": "The factor ν ∈ (0,1] multiplying each new tree before it is added to the ensemble: F_m = F_{m−1} + ν·h_m. Smaller ν takes gentler steps, requiring more trees to fit but generalizing better; ν and the number of trees trade off, roughly, as a fixed product.",
    "Singular values": "The diagonal entries σ₁ ≥ σ₂ ≥ … ≥ 0 of Σ in the SVD — the factors by which the matrix stretches the unit sphere along its principal axes. They are square roots of the eigenvalues of AᵀA, hence always non-negative; their squares σᵢ² are the energy (variance) each component carries.",
    "Stacked generalization (stacking)": "Wolpert's method of training a second-level meta-learner whose inputs are the predictions of several diverse base models. The base predictions must be out-of-fold (cross-validated) to avoid leakage; a simple regularized meta-model (e.g. ridge) then learns, per region, which base model to trust.",
    "Stratified k-fold": "k-fold that partitions within each class so every fold mirrors the overall label distribution. The default for classification and essential under class imbalance, where a blind random fold might contain few or no minority examples.",
    "Successive halving": "A tournament on budget: start many configurations with a tiny budget, cull the worst fraction, give survivors geometrically more budget, and repeat. Total compute per round stays roughly constant, concentrating spend on configurations that prove themselves early.",
    "Support vector": "A training point that lies exactly on the margin (or inside it, for the soft margin) and so has a nonzero dual weight alpha. Only the support vectors determine the boundary; deleting any other point leaves the trained SVM unchanged, which is why the solution is sparse.",
    "Truncated SVD": "Keeping only the top-k singular values and vectors to form the rank-k matrix Aₖ = Σᵢ₌₁ᵏ σᵢuᵢvᵢᵀ. By Eckart–Young this is the best possible rank-k approximation in Frobenius and spectral norm, with leftover error equal to the square root of the discarded energy.",
    "Zero-frequency problem": "When a feature value never co-occurs with a class in training, its unsmoothed conditional probability is 0, which drives the entire product likelihood to zero and unconditionally vetoes that class. Smoothing exists to keep every probability strictly positive.",
    /* ---- V2 expansion terms ---- */
    "1/√N convergence": "The defining and unforgiving rate of plain Monte Carlo: error falls as the reciprocal square root of the sample size. Halving the error costs 4× the paths and gaining one decimal digit costs 100×, which is why variance reduction matters more than raw compute.",
    "ACF and PACF": "The autocorrelation function (correlation between y_t and y_{t-k}) and the partial autocorrelation function (the same after removing the intervening lags). Their cutoff/tail-off patterns are the fingerprints used to identify orders: PACF cuts off for AR(p), ACF cuts off for MA(q), both tail off for ARMA.",
    "Affine term-structure model": "A model whose zero-coupon bond price has the form P(t,T) = A(t,T) e^{−B(t,T) r_t}, making the yield an affine (linear-plus-constant) function of the short rate. Vasicek, CIR and Hull–White are all affine, which is precisely why each admits a closed-form bond price obtained from Riccati ODEs.",
    "Antithetic variates": "Pairing each Gaussian shock Z with its mirror −Z and averaging the two payoffs into one sample. For a payoff monotone in Z the pair is negatively correlated, so variance falls by a factor (1+ρ) with ρ<0; for non-monotone payoffs it can backfire.",
    "ARCH model": "Engle's 1982 Autoregressive Conditional Heteroscedasticity model, in which today's conditional variance is a constant plus a weighted sum of recent squared shocks. It captures clustering directly but needs many lags to express realistic persistence, motivating its GARCH generalization.",
    "ARIMA(p,d,q)": "An ARMA(p,q) model fitted to a series after d differences: Phi(L)(1-L)^d y_t = c + Theta(L) e_t. Special cases include AR(p) = ARIMA(p,0,0), MA(q) = ARIMA(0,0,q), and the random walk = ARIMA(0,1,0).",
    "Autocorrelation function (ACF)": "The correlation of a series with a lagged copy of itself, ρ_k = γ_k / γ_0, plotted against the lag k as a correlogram. Its shape is a fingerprint: geometric decay signals autoregressive memory, a sharp cut-off signals a moving-average process, and a tall spike at lag m signals seasonality of period m.",
    "Autoregressive model (AR)": "A model that predicts the current value as a weighted sum of its own past p values plus a white-noise shock: y_t = c + sum phi_i y_{t-i} + e_t. The coefficient of AR(1), phi, is the one-step persistence of the series; stationarity requires the roots of the characteristic polynomial to lie outside the unit circle.",
    "Backward induction": "The algorithm that prices a tree from the leaves to the root: set terminal payoffs, then repeatedly replace each node by the discounted risk-neutral average of its two children. For American options each node also takes the max of that continuation value and immediate exercise.",
    "Basel traffic light": "The supervisory backtest bucketing a bank by 99% VaR exceptions over 250 days: green (0–4, accepted), yellow (5–9, capital multiplier raised), red (10+, model presumed flawed). The boundaries follow the Binomial(250, 0.01) distribution.",
    "Box-Jenkins methodology": "The iterative identify -> estimate -> diagnose loop for building ARIMA models: make the series stationary and read the ACF/PACF to propose orders, fit by maximum likelihood, then check that residuals are indistinguishable from white noise (Ljung-Box). If not, revise the orders and repeat.",
    "Box–Cox transform": "A one-parameter family of power transforms, (y^λ − 1)/λ for λ ≠ 0 and ln y for λ = 0, used to stabilize a variance that grows with the level of the series. The log case (λ → 0) also turns a multiplicative seasonal pattern into an additive one.",
    "Brownian motion (Wiener process)": "The continuous-time limit of a random walk: a path that starts at zero, has independent Gaussian increments with variance equal to the elapsed time, and is continuous everywhere yet nowhere differentiable. Its variance is exactly the clock, Var(W_t) = t.",
    "Coherent risk measure": "A risk measure satisfying Artzner et al.'s four axioms: monotonicity, translation invariance, positive homogeneity, and subadditivity. Expected Shortfall is coherent; VaR is not, because it can violate subadditivity.",
    "Cointegration": "A property of two or more individually I(1) (random-walk) series for which some linear combination beta'y is stationary (I(0)); the series share a common stochastic trend and cannot drift apart without bound.",
    "Cointegration rank": "The number r of linearly independent cointegrating vectors, equal to the rank of the matrix Pi in a VECM (0 <= r < K); estimated by the Johansen trace and maximum-eigenvalue likelihood-ratio tests.",
    "Companion form": "A rewrite of a VAR(p) as an equivalent VAR(1) on a stacked state vector; the VAR is stationary exactly when every eigenvalue of its companion matrix lies strictly inside the unit circle.",
    "Conditional heteroscedasticity": "A time-varying variance that depends on the past — the variance of the next observation is predictable from previous data even when the observation's level is not. It is the property classical constant-variance (homoscedastic) models cannot represent and the entire ARCH/GARCH family was built to capture.",
    "Conditional Value-at-Risk (parametric VaR)": "A loss threshold a portfolio will not exceed with a given probability over a horizon, computed as minus the mean plus the lower-tail quantile of the innovation distribution times the GARCH conditional volatility. Because the volatility is conditional it widens automatically in turbulent regimes and tightens in calm ones, unlike a static historical VaR that lags the regime.",
    "Conformal prediction": "A distribution-free wrapper that turns any point forecaster into one with finite-sample coverage guarantees, by calibrating interval widths on held-out residuals under an exchangeability assumption. A practical alternative to trusting a Gaussian error model for prediction intervals.",
    "Control variate": "Subtracting a correlated quantity X with a known mean, Y_cv = Y − c(X − E[X]), leaving the price unchanged but cutting variance by a factor (1−ρ²). A control 0.99-correlated with the payoff reduces variance roughly 50×; the geometric-Asian price is the classic control for the arithmetic Asian.",
    "Cox–Ingersoll–Ross (CIR) model": "A 1985 short-rate model that multiplies Vasicek's noise by √r_t, so volatility vanishes as the rate approaches zero and the rate can never go negative. Its terminal distribution is non-central chi-squared, and it captures the empirical link between the level of rates and their volatility.",
    "Cox–Ross–Rubinstein (CRR) tree": "A recombining binomial lattice with u = e^{σ√Δt}, d = 1/u, priced by backward induction. The choice ud = 1 makes 'up then down' land on the same node as 'down then up', so N steps give only N+1 terminal nodes, and the price converges to Black–Scholes as N grows.",
    "Damped trend": "A modification of Holt's method that multiplies the projected trend by a factor φ<1 each step, so long-horizon forecasts bend toward a finite asymptote instead of running off linearly — a perennial forecasting-competition benchmark.",
    "Differencing / integrated order I(d)": "Subtracting consecutive values, Delta y_t = y_t - y_{t-1} = (1-L) y_t, to remove a trend. A series that becomes stationary after d differences is integrated of order d, written I(d); the 'I' in ARIMA. Over-differencing injects spurious negative autocorrelation, so difference the minimum needed.",
    "Differencing / integration order d": "Replacing a series with its step-to-step changes ∇y_t = y_t − y_{t-1} to remove a trend; the number of differences d needed to reach stationarity is the integration order, written I(d). It is the 'I' in ARIMA — but over-differencing injects artificial negative autocorrelation, so difference only as much as required.",
    "Early-exercise boundary": "The frontier in the (time, stock-price) plane separating the nodes where exercising an American option immediately beats holding it from the nodes where holding is optimal. For a put it is the curve of highest stock prices at which early exercise still pays; high rates push it upward.",
    "Early-exercise premium": "The amount by which an American option exceeds its otherwise-identical European twin, V_American − V_European ≥ 0 — the value of the right to exercise before expiry. It is zero for a call on a non-dividend stock and strictly positive for a sufficiently in-the-money put at a positive interest rate.",
    "ETS state-space model": "The innovations state-space framework (Error, Trend, Season) that gives every exponential-smoothing method an underlying probability model with a single source of error — yielding a likelihood, AIC-based model selection, and exact prediction intervals.",
    "Expected Shortfall (ES / CVaR)": "The average loss conditional on being in the worst (1−α) tail — the mean of all losses beyond VaR. It is always at least as large as VaR at the same level and, unlike VaR, is a coherent risk measure.",
    "Feller condition": "The CIR inequality 2ab ≥ σ², under which the short rate stays strictly positive and never even touches zero. If it is violated the rate can reach zero and reflect, but the square-root diffusion still keeps it non-negative.",
    "Forecast-error variance decomposition (FEVD)": "The share of each variable's h-step-ahead forecast-error variance attributable to each (orthogonalized) structural shock; like the IRF it depends on the identifying ordering imposed on the shocks.",
    "GARCH(1,1)": "Bollerslev's 1986 model that sets today's conditional variance to omega + alpha·(yesterday's squared shock) + beta·(yesterday's variance). With just three parameters it captures slowly-decaying volatility persistence and is equivalent to an infinite exponentially-weighted ARCH, making it the field's default workhorse.",
    "Geometric Brownian motion (GBM)": "The standard stock model, dS = mu*S dt + sigma*S dW, in which randomness acts on returns rather than the price level. Its solution makes prices lognormal (never negative) and its log drifts at mu − ½σ² rather than mu.",
    "Granger causality": "A statement of predictive content: x Granger-causes y if past values of x improve the forecast of y beyond y's own past, tested by an F-test comparing restricted and unrestricted equations. It is not a claim of structural or mechanistic causation.",
    "Hedge ratio (delta)": "The number of shares Δ = (V_u − V_d)/(S₀(u − d)) held in the replicating portfolio to offset an option's exposure over one step — the spread of option values divided by the spread of stock values. It is the discrete ancestor of the Black–Scholes delta.",
    "Historical simulation": "Estimating VaR/ES directly from the empirical sample of past returns by sorting and reading off the order statistic, with no distributional assumption. It captures real fat tails and skew but is blind to any risk the lookback window never contained.",
    "Holt-Winters seasonal method": "Triple exponential smoothing: level, trend, and a vector of m seasonal indices updated by γ. Comes in additive (constant-size season) and multiplicative (season grows with the level) variants.",
    "Holt's linear trend method": "Double exponential smoothing: alongside the level it smooths a trend component (change per period) with its own parameter β, so the forecast is a straight line rather than a flat one.",
    "Hull–White model": "The extended-Vasicek model dr = (θ(t) − a r)dt + σ dW, in which the drift target θ(t) is a time-dependent function chosen to fit today's observed yield curve exactly. This no-arbitrage construction retains Gaussian tractability — closed-form bonds, bond options, and swaptions — and is the production workhorse of interest-rate desks.",
    "Impulse-response function (IRF)": "The time path of a system's variables following a one-off unit shock to one equation; for a VAR it equals the moving-average coefficients Psi_i (Psi_i = A1^i for a VAR(1)) and turns a coefficient matrix into an interpretable dynamic story.",
    "Itô's lemma": "The chain rule of stochastic calculus. For a function of an Itô process it keeps an extra second-order term, ½σ²·∂²f/∂x², that ordinary calculus discards — the term born from quadratic variation that produces every ½σ² correction in quantitative finance.",
    "Kupiec POF test": "A likelihood-ratio test of a VaR model's unconditional coverage: it compares the model's claimed exception rate p against the observed rate x/T, with the statistic distributed χ²(1). Reject the model when LR exceeds 3.841 (the 95% critical value).",
    "Leverage effect": "The asymmetry in equity volatility whereby a negative return raises future volatility more than a positive return of equal size. Plain GARCH squares the shock and so ignores its sign; GJR-GARCH adds a term that switches on only for down days, and EGARCH models log-variance with a sign-dependent news term.",
    "Look-ahead bias (data leakage)": "Letting any post-origin information into a pre-origin decision — scaling or imputing across the train/test seam, using revised figures known only after the target, or tuning on the test set. It inflates offline scores into fiction; the fix is to fit every transform inside each fold on past data alone and simulate production exactly.",
    "MAPE": "Mean Absolute Percentage Error: the average of |actual − forecast| / |actual|, expressed as a percent. Scale-free and intuitive, but it explodes near zero actuals, is undefined at zero, and penalizes over-forecasts more than under-forecasts (asymmetric).",
    "Martingale": "A process whose expected future value given all past information equals its present value, E[M_{t+s} | F_t] = M_t. It is the formal model of a fair game; under the risk-neutral measure a discounted asset price is a martingale, which is why options price as discounted expectations.",
    "MASE": "Mean Absolute Scaled Error (Hyndman & Koehler, 2006): the model's mean absolute error divided by the in-sample mean absolute error of the one-step naive forecast. It is unitless, defined even at zero, and symmetric; MASE < 1 means the model beats the naive forecast, MASE > 1 means it loses to copy-the-last-value.",
    "Mean reversion": "The tendency of a process to be pulled back toward a long-run level whenever it strays, via a drift proportional to the gap (level minus current value). In short-rate models the reversion speed a sets the pull strength and 1/a its time constant, so a shock decays with half-life ln2/a.",
    "Monte Carlo estimator": "An option price approximated as the discounted average of its payoff over many simulated futures, V̂ = e^{-rT}·mean(payoff). It is unbiased for any number of paths, so its only error is statistical noise, and its per-path cost is independent of how complex the payoff is.",
    "Moving-average model (MA)": "A model that writes the current value as the current shock plus a weighted sum of the last q shocks: y_t = mu + e_t + sum theta_j e_{t-j}. It has finite memory, so it is always stationary and its autocorrelation function cuts off sharply after lag q.",
    "Naive forecast": "The benchmark that copies the last observed value forward (the seasonal variant copies one season back). It is the yardstick every model must beat, and the denominator of MASE; a model that cannot beat it is not worth deploying.",
    "News-impact curve": "A plot of next period's conditional variance against the current shock, holding the prior variance fixed. Symmetric GARCH traces a parabola centred at zero; asymmetric models (GJR, EGARCH) tilt it so the loss (left) arm rises more steeply, visualizing the leverage effect.",
    "No-arbitrage (law of one price)": "The principle that two portfolios paying identical amounts in every future state must cost the same today; otherwise a riskless profit could be locked in by buying the cheap one and selling the dear one. It is the only economic assumption the binomial model needs.",
    "One-step SSE estimation": "The standard way to fit smoothing parameters and initial states: numerically minimize the in-sample sum of squared one-step-ahead forecast errors, equivalent to maximizing the Gaussian likelihood of the ETS model.",
    "Ornstein–Uhlenbeck process": "A mean-reverting SDE, dX = kappa(theta − X) dt + sigma dW, pulled back toward a long-run level theta at speed kappa. Unlike Brownian motion its variance saturates at σ²/2κ, making it the canonical model for rates, spreads, and mean-reverting pairs.",
    "Partial autocorrelation (PACF)": "The correlation between y_t and y_{t-k} after removing the linear influence of all the lags in between — the direct dependence at range k, with relayed paths stripped out. Read alongside the ACF, it identifies the autoregressive order p, since the PACF of an AR(p) cuts off after lag p.",
    "Path-dependent option": "A derivative whose payoff depends on the whole trajectory of the underlying, not just its final value — e.g. an Asian (average price) or a barrier (knock-in/knock-out at a level). These rarely admit closed forms, making them the natural domain of Monte Carlo, but they require simulating full paths and incur a discretization bias from the time step.",
    "Pathwise & bump-and-revalue Greeks": "Two ways to get sensitivities from a simulation. Bump-and-revalue takes a finite difference of two re-priced scenarios and only works reliably with common random numbers; the pathwise (infinitesimal-perturbation) estimator differentiates the payoff itself for an unbiased, single-pass Greek when the payoff is smooth enough.",
    "Persistence (alpha + beta)": "In GARCH(1,1), the sum of the reaction and memory coefficients, governing how slowly a volatility shock decays back toward its long-run level. Values near 1 (typical for daily equity indices, 0.95–0.99) mean shocks fade only over many sessions; at exactly 1 the model becomes IGARCH and the unconditional variance is undefined.",
    "Prediction interval coverage": "The fraction of realized outcomes that fall inside a model's prediction intervals. A calibrated 90% interval covers the truth about 90% of the time; coverage well below nominal means over-confident (too-tight) intervals — the common failure — while coverage above nominal means needlessly wide bands.",
    "Quadratic variation": "The limit of the sum of squared increments of a path. For a smooth curve it is zero, but for Brownian motion it equals t, giving the rule (dW)^2 = dt — the single fact that makes stochastic calculus differ from ordinary calculus.",
    "Random walk / unit root": "A series y_t = y_{t-1} + ε_t formed by cumulating white noise; the AR(1) at its boundary φ = 1, a unit root. Its variance grows as t·σ², so it is non-stationary with no mean to revert to, and its first difference is exactly white noise — the canonical I(1) process.",
    "Replicating portfolio": "A position in the underlying stock and a risk-free bond, rebalanced so it reproduces an option's payoff in every state of the world. By the law of one price the option must cost exactly what the replicating portfolio costs — pricing is replication, not prediction.",
    "Risk-neutral probability": "The synthetic probability p = (e^{rΔt} − d)/(u − d) under which the discounted price of every traded asset is a martingale and the stock drifts at the risk-free rate. It is set entirely by the up/down factors and the rate; the stock's real-world expected return never enters.",
    "Risk-neutral valuation": "Pricing a derivative as the discounted expectation of its payoff under the risk-neutral measure ℚ, rather than under real-world probabilities. The stock's drift μ cancels out, so two traders who disagree about direction still agree on the option price.",
    "SARIMA": "Seasonal ARIMA, written SARIMA(p,d,q)(P,D,Q)_s, which adds a second ARIMA acting at the seasonal lag s (12 for monthly-yearly, 7 for daily-weekly). The uppercase orders capture the season via seasonal differencing (1-L^s)^D and seasonal AR/MA terms; the airline model (0,1,1)(0,1,1)_12 is the canonical baseline.",
    "Seasonal index": "A per-period adjustment (one per slot in the seasonal cycle) that captures the recurring calendar pattern; additive indices are normalized to sum to zero per cycle, multiplicative ones to average one.",
    "Short rate": "The instantaneous risk-free interest rate r_t for borrowing over the next infinitesimal moment — the front end of the yield curve and the single quantity a short-rate model evolves stochastically. From its dynamics the whole curve follows as a risk-neutral expectation of the discount factor.",
    "Simple exponential smoothing (SES)": "A one-parameter forecaster that maintains a level as a weighted average of past observations whose weights decay geometrically into the past; the level itself is the (flat) forecast for every horizon.",
    "sMAPE": "Symmetric Mean Absolute Percentage Error: |actual − forecast| divided by the average of |actual| and |forecast|, averaged and scaled to percent. Bounded and less one-sided than MAPE, but only approximately symmetric, undefined when both values are zero, and convention-dependent (some forms cap at 100%, others at 200%).",
    "Smoothing parameter (α)": "The learning rate of an exponential smoother, between 0 and 1. Large α gives short memory and tracks recent data closely; small α gives long memory and behaves like a slow long-run average.",
    "Standard error (Monte Carlo)": "The standard deviation of the Monte Carlo estimate itself, SE = σ_Y/√N, where σ_Y is the spread of the discounted payoffs and N the number of paths. It is estimated from the same run that estimates the price and sets the 95% confidence interval at ±1.96·SE.",
    "Stationarity": "The property that a series' statistical behavior (mean, variance, autocovariances) does not change over time. ARMA models require it; an AR process is stationary iff every root of its characteristic polynomial lies strictly outside the unit circle (for AR(1), |phi| < 1).",
    "Stationarity (weak)": "The property that a series' mean, variance, and autocovariance do not change over time — the autocovariance depending only on the lag between points, never their absolute position. It is the substitute for i.i.d. that lets the past stand in for the future, and most forecasting assumes it holds after a transform.",
    "Stochastic differential equation (SDE)": "An equation dX = a(X,t) dt + b(X,t) dW expressing a process's infinitesimal change as a deterministic drift plus a random diffusion. Choosing a and b selects the model; most SDEs are solved numerically by the Euler–Maruyama scheme.",
    "Stress testing": "Repricing a portfolio under specific historical or hypothetical scenarios — or, in reverse stress testing, solving for the scenario that breaks the firm — without attaching a probability. It is the deliberate complement to statistical VaR/ES, covering events the distribution never sampled.",
    "Subadditivity": "The axiom ρ(A+B) ≤ ρ(A)+ρ(B): combining portfolios cannot increase total risk, so diversification is never penalized. VaR can break this — reporting a merged book as riskier than the sum of its parts — which is the central case against it.",
    "Term structure of interest rates": "The relationship between the yield on default-free debt and its maturity — equivalently the discount curve of zero-coupon bond prices P(t,T). It is usually upward-sloping, occasionally flat, and inverts (short rates above long rates) ahead of recessions; reproducing all of these shapes from a small parameter set is the goal of every model in this chapter.",
    "Time series": "A sequence of observations indexed by time, where the ordering carries information: neighbouring points are dependent, so the rows are not interchangeable the way i.i.d. data is. This dependence is what makes time series a distinct discipline.",
    "Trend / seasonality / remainder": "The three parts of the classical decomposition y_t = T_t + S_t + R_t: the slow drift (trend), the fixed-period repeating pattern (seasonality), and the structureless leftover (remainder). A multiplicative variant y = T x S x R fits when seasonal swings scale with the level, and taking logs converts it to the additive form.",
    "Value at Risk (VaR)": "A quantile of the loss distribution: the loss a portfolio will not exceed with probability α over a chosen horizon. The 99% one-day VaR is the threshold worse than only 1 day in 100 — a single number that says nothing about how bad the breaches themselves are.",
    "Variance reduction": "Any technique that shrinks the payoff spread σ_Y rather than growing N, buying accuracy almost for free. The main families are antithetic variates, control variates, importance sampling, and low-discrepancy (quasi-random) sequences.",
    "Vasicek model": "A 1977 short-rate model in which r_t is an Ornstein–Uhlenbeck process: mean-reverting drift a(b−r) plus constant Gaussian noise σ dW. It is affine, giving closed-form bond prices, but its Gaussian terminal law assigns positive probability to negative rates.",
    "Vector Autoregression (VAR)": "A multivariate time-series model in which each of K variables is regressed on the lagged values of all K variables (itself included), so the coefficient matrices encode mutual feedback and lead-lag structure.",
    "Vector Error-Correction Model (VECM)": "A differenced VAR augmented with a level term Pi*y_{t-1}, where Pi = alpha*beta' has rank equal to the cointegration rank; the term alpha*(beta'y) pulls the system back toward long-run equilibrium at the speed-of-adjustment loadings alpha.",
    "Volatility clustering": "The empirical regularity that large asset-price changes tend to be followed by large changes (of either sign) and small by small, so periods of turbulence and calm arrive in bunches. Formally, returns are nearly uncorrelated while squared or absolute returns show strong, slowly-decaying positive autocorrelation.",
    "Volatility drag (Itô correction)": "The ½σ² gap by which the log-drift of GBM, mu − ½σ², falls below the arithmetic drift mu. It is why a volatile asset with positive expected return can have a typical (median) path that still loses money: the mean is pulled up by the lognormal's fat right tail while the median lags.",
    "Walk-forward validation": "Time-respecting cross-validation for forecasting: fit on data up to an origin t, forecast the next h steps, score them, then slide the origin forward and repeat. An expanding window keeps all history (best when stationary); a sliding window of fixed length forgets old data (best when the process drifts). The model at origin t may use nothing dated after t.",
    "White noise": "A sequence of uncorrelated, zero-mean, constant-variance shocks with every autocorrelation past lag 0 equal to zero. It is stationary and unforecastable beyond its mean, and it is the target for model residuals — white residuals mean all linear structure has been extracted.",
    /* ---- V2 expansion terms ---- */
    "A2C / A3C": "Advantage Actor-Critic and its asynchronous predecessor (Mnih et al., 2016): run many actor-learners in parallel so their gradients are decorrelated — the on-policy substitute for a replay buffer — using an n-step advantage plus an entropy bonus. A2C is the synchronous, more GPU-friendly variant that matches A3C's performance.",
    "Actor-critic": "An architecture with two learned components: an actor (the policy π_θ) that selects actions and is updated by the policy gradient, and a critic (a value function V_w) that estimates expected return and supplies the baseline and bootstrap target. Both are driven by the shared TD error δ_t = r + γV_w(s′) − V_w(s).",
    "Additive (Bahdanau) attention": "The original 2014 attention: a small feedforward network scores each encoder annotation against the decoder state via v·tanh(W·s + U·h). More robust when query and key dimensions differ, at the cost of an MLP per pair.",
    "Advantage": "A^π(s, a) = Q^π(s, a) − V^π(s), how much better an action is than the policy's own average from that state. Using the advantage (or its one-sample TD-error estimate δ_t) as the policy-gradient weight is the standard variance-reduction tool, asking only whether an action beat expectations rather than its absolute value.",
    "Adversarial training": "A robust-optimization scheme that hardens a model by minimizing its loss on the worst-case perturbation of each input within a small budget — an inner maximization over an epsilon-ball wrapped in an outer minimization over weights. It manufactures a self-generating curriculum of hard examples, but usually trades away clean accuracy and only defends the narrow threat model the perturbation set encodes.",
    "Agent": "The learner and decision-maker in reinforcement learning — the only part of the system whose behavior is changed by training. It observes states, selects actions according to its policy, and receives rewards; everything outside its direct control is the environment.",
    "Alignment model": "The learned scorer that decides how much each source position contributes to the current output step. It is trained jointly with the translator from the translation loss alone — alignment emerges, it is never supervised.",
    "Attention mechanism": "A differentiable soft lookup in which a query is scored against a set of keys, the scores are softmaxed into weights that sum to one, and the output is the weighted sum of the corresponding values. Born in seq2seq translation as cross-attention between decoder and encoder.",
    "Attention weights (αᵢⱼ)": "The softmax-normalized alignment scores giving, for output step i, a probability distribution over the source positions j. They sum to one, making the context vector a convex combination — a true weighted average — of the encoder states.",
    "Backpropagation through time (BPTT)": "Training an RNN by unrolling it into its depth-T feed-forward equivalent and running ordinary backpropagation, summing each shared weight's gradient over all steps (EQ N3.7). Truncated BPTT cuts the sequence into chunks, backpropagating only within a chunk while carrying the hidden state forward, to bound memory and tame the gradient pathologies.",
    "Baseline": "A state-only reference value b(s) subtracted from the return before weighting the score. Because the expected score is zero, any action-independent baseline leaves the gradient unbiased while sharply reducing its variance; the near-optimal choice b(s) = V^π(s) turns the weight into the advantage.",
    "Batch normalization": "A layer that standardizes each feature channel to zero mean and unit variance using mini-batch statistics, then re-scales and re-shifts with learned parameters gamma and beta (EQ N1.6). It permits higher learning rates, reduces sensitivity to initialization, and mildly regularizes; at inference it switches to running-average statistics.",
    "Bellman expectation equation": "The recursive identity a value function satisfies for a fixed policy: V^π(s) equals the policy-averaged immediate reward plus the discounted value of the successor state. Because V^π appears on both sides, it is a system of |S| linear equations whose unique solution is the value function, and solving it is the task of policy evaluation.",
    "Bellman operator (contraction)": "The mapping T that takes a value table to a better one via one backup; the optimal value V* is its fixed point, T V* = V*. For γ < 1 it is a γ-contraction in the max-norm, ||TU − TV||∞ ≤ γ||U − V||∞, so the Banach fixed-point theorem guarantees a unique fixed point reached from any start — the reason value iteration converges.",
    "Bellman optimality equation": "The fixed-point equation the optimal value function satisfies: V*(s) = max_a Σ p(s',r|s,a)[r + γV*(s')]. Replacing the policy average with a maximum over actions makes it nonlinear, but it still has a unique solution from which the optimal policy is read off by acting greedily, π*(s) = argmax_a Q*(s,a).",
    "Best response": "The set of strategies that maximize a player's payoff given everyone else's choices held fixed. Almost every equilibrium concept is a fixed point of mutual best response.",
    "Bootstrapping": "Updating a value estimate using another current estimate rather than a fully observed outcome — the defining trick of temporal-difference learning, which replaces the unknown future return G_{t+1} with the agent's own guess V(s_{t+1}). It enables online, single-step learning even in tasks that never terminate, at the cost of introducing bias.",
    "Bottleneck (latent code)": "The narrow intermediate layer of an autoencoder whose width k is smaller than the input dimension d. It forces the network to discard everything except the few axes of greatest variation, so the code becomes a compressed coordinate system for the data manifold.",
    "Bradley-Terry model": "A model of paired comparisons that assigns each item a latent score and predicts the probability one beats another as the sigmoid of their score difference: P(y_w > y_l) = sigma(r(y_w) - r(y_l)). RLHF uses it to turn human 'A is better than B' choices into a trainable scalar reward; only the reward difference matters, so the scale is fixed only up to an additive constant.",
    "Cell state (constant error carousel)": "The LSTM's second memory track c_t, updated as c_t = f_t ⊙ c_{t-1} + i_t ⊙ c~_t. When the forget gate is near 1 and the input gate near 0 the cell is approximately unchanged, so the gradient flows back along it multiplied by ~1 instead of a contracting Jacobian — the mechanism that lets gradients survive across many steps.",
    "Centralized training, decentralized execution (CTDE)": "A multi-agent RL paradigm in which each agent's critic may observe the full joint state and actions during training — making its learning target stationary — while each agent's actor learns a policy that runs on its own local observation alone at deployment. MADDPG is the canonical instance; it is the standard remedy for the non-stationarity that plagues independent multi-agent learners.",
    "Context vector": "The summary the encoder hands to the decoder. In plain seq2seq it is a single fixed-length vector (the encoder's last state); with attention it is recomputed at every output step as a weighted sum of all encoder states.",
    "Convolution (cross-correlation)": "Sliding a small learnable kernel across an input and recording, at each position, the sum of element-wise products with the patch it overlaps. Deep-learning libraries skip the kernel flip of mathematical convolution and use cross-correlation; because the kernel is learned, the distinction does not matter. It encodes two priors: local connectivity (each output sees only a small window) and weight sharing (the same weights are reused everywhere).",
    "Cooperative (coalitional) game": "A game in which players can form binding agreements and pool their efforts, described not by a payoff matrix but by a characteristic function v(S) giving the value each coalition S can secure on its own. The question shifts from what players will do to how the joint payoff should be divided fairly.",
    "Cosine learning-rate schedule": "Decaying the learning rate from its peak to a floor along a half-cosine curve after warmup — gentle at first, steepest in the middle, flattening at the end. Its slow start buys exploration and its slow finish lets the model settle; it reliably beats step decay on large models.",
    "Deadly triad": "Sutton and Barto's name for the three ingredients that together risk divergence in value-based RL: function approximation, bootstrapping (a target that uses the network's own estimate), and off-policy learning. Each is benign alone and hard to give up; present together, value estimates can chase their own moving target without bound.",
    "Denoising autoencoder (DAE)": "An autoencoder fed a corrupted input and trained to output the clean original. Copying is impossible, so the network must learn the shape of the data and project corrupted points back onto the manifold; this implicitly estimates the score (the gradient of the log-density), the seed idea behind diffusion models.",
    "Discounted return": "The quantity an agent maximizes: the sum of future rewards, each weighted by γ raised to its number of steps away, G_t = Σ γ^k R_{t+k+1}. Discounting makes infinite-horizon returns finite, encodes the time value of reward, and sets the agent's effective horizon at roughly 1/(1−γ) steps.",
    "Discriminator / critic": "The adversary network. In the original GAN it outputs a probability D(x) in (0,1) that x is real; in WGAN it becomes a 1-Lipschitz critic outputting an unbounded real score. At the game's optimum D(x)=0.5 for every input — it can no longer distinguish real from generated.",
    "Dominant strategy": "A strategy that yields a strictly higher payoff than an alternative against every possible choice of the opponents. A rational player never plays a strictly dominated strategy, so reasoning about the opponent becomes unnecessary.",
    "DPO (Direct Preference Optimization)": "A method that optimizes the same KL-regularized RLHF objective without a reward model or RL loop. Using the closed-form optimum of that objective, the intractable partition function cancels in a preference pair, leaving a supervised loss over log-ratios of the policy to the reference: the policy is its own implicit reward model, r_hat = beta * log(pi_theta / pi_ref).",
    "Evidence lower bound (ELBO)": "The VAE's training objective: a lower bound on the data log-likelihood equal to the expected reconstruction term minus the KL divergence from the approximate posterior to the prior. Maximizing the ELBO is equivalent to minimizing reconstruction error plus KL-to-prior.",
    "Evolutionarily Stable Strategy (ESS)": "A strategy that, if adopted by an entire population, cannot be invaded by a small group of mutants playing anything else. Introduced by Maynard Smith and Price, it is a strict refinement of Nash equilibrium: every ESS is a Nash equilibrium, but not every Nash equilibrium is an ESS.",
    "Experience replay": "A circular buffer storing past transitions (s, a, r, s') from which DQN samples random minibatches for training. It decorrelates the highly similar consecutive frames that would otherwise violate the i.i.d. assumption SGD relies on, and lets each costly environment interaction drive many gradient updates.",
    "Exploration–exploitation dilemma": "The trade-off, unique to learning from interaction, between exploiting the action currently believed best and exploring uncertain actions to improve those beliefs. Because the agent's actions decide what data it sees, an action never tried is never learned from; ε-greedy is the simplest balance, annealing a random-action rate ε toward zero as estimates sharpen.",
    "Feature map": "The 2D output a single kernel produces by being applied across the whole input: a spatial record of where that kernel's pattern occurs. A convolutional layer outputs a stack of feature maps, one per output channel; early-layer maps respond to edges and textures, deep-layer maps to object parts.",
    "Fixed-vector bottleneck": "The failure mode of plain seq2seq: an entire source sentence must be compressed into one constant-width vector, so translation quality degrades as input length grows. Attention removes it by letting the decoder read all encoder states on demand.",
    "Function approximation (in RL)": "Replacing a tabular value function or policy with a parameterized model — almost always a neural network — so that learning in one state generalizes to similar unseen states. It is what makes 'deep' RL possible on pixel or continuous state spaces, and the price of admission for the deadly triad's instability.",
    "Gate": "A sigmoid-valued vector in (0,1) that acts as a soft, differentiable valve on a memory channel: 0 blocks it, 1 passes it untouched. An LSTM has three gates (forget, input, output); a GRU has two (update, reset). The candidate (a tanh) is content, not a gate.",
    "Generalized policy iteration (GPI)": "The unifying view of nearly all RL control as two interacting processes — evaluation, which makes the value consistent with the policy, and improvement, which makes the policy greedy with respect to the value — chasing each other until they agree, which can only happen at the optimal pair (V*, π*). Value iteration and policy iteration are endpoints of this spectrum.",
    "Generative Adversarial Network (GAN)": "A generative model trained as a two-player minimax game in which a generator turns noise into samples and a discriminator tries to distinguish those samples from real data. The generator is supervised only by gradients flowing back through the discriminator, so the loss function is itself learned and sharpens as the samples improve; its global optimum is reached when the generated and real distributions coincide.",
    "GRPO (Group Relative Policy Optimization)": "A PPO variant that deletes the value/critic network: for each prompt it samples a group of G responses, scores them, and standardizes the rewards within the group to form the advantage, A_i = (r_i - mean) / std. The group itself supplies the baseline PPO would otherwise spend a whole second model to estimate; introduced with DeepSeekMath and central to reasoning models.",
    "GRU (Gated Recurrent Unit)": "A lighter gated cell (Cho et al., 2014) with a single state vector and two gates: an update gate that interpolates between keeping the old state and overwriting it with a candidate, and a reset gate that controls how much past state feeds the candidate. It merges the LSTM's forget and input gates into one and drops the separate cell state and output gate.",
    "He (Kaiming) initialization": "The ReLU-specific init that sets Var(W) = 2/n_in (std = sqrt(2/n_in)). The extra factor of 2 over 1/n_in exactly cancels ReLU's variance-halving, so activation variance is preserved through depth. It is the framework default for ReLU-family networks.",
    "Hidden state": "The vector an RNN carries from one time step to the next as a running summary of the past; in EQ N3.1 it is updated by h_t = tanh(W_xh x_t + W_hh h_{t-1} + b). In an LSTM the hidden state is a gated, squashed view of a separate cell state, while in a GRU the hidden state is the only memory.",
    "Indifference principle": "In a mixed equilibrium, every action a player randomizes over must yield the same expected payoff, otherwise they would shift all weight to the better one. A player's mixing probabilities are therefore pinned down by making the opponent indifferent.",
    "Internal covariate shift": "The drift in the distribution of a layer's inputs as the layers below it update during training — the motivation Ioffe & Szegedy gave for batch normalization. Later work (Santurkar et al., 2018) argued BatchNorm's real benefit is a smoother loss landscape rather than reducing this shift; the mechanism remains debated.",
    "Kernel / filter": "The small tensor of weights a convolution slides over its input, typically 3x3 in modern networks. A kernel applied to a C-channel input is k x k x C and produces one output feature map; a layer runs many kernels in parallel, one per output channel. Its weights are the only parameters of the convolution and are reused at every spatial position.",
    "KL penalty / KL leash": "A term that penalizes the policy for diverging (in KL divergence) from the frozen reference (SFT) model, scaled by a coefficient beta. It keeps generations fluent and on-distribution and slows reward hacking, but only weakens the incentive to game the proxy reward rather than removing it.",
    "Latent space": "The space of all codes an encoder can produce. Distances in a good latent space track perceptual or semantic similarity far better than raw input distance, enabling interpolation, clustering, retrieval, and anomaly detection by reconstruction error.",
    "Learning-rate warmup": "Linearly ramping the learning rate from zero to its peak over the first 1–5% of training steps. It lets an optimizer's adaptive statistics and a network's fragile early layers stabilize before full-size updates, preventing the early divergence that large initial steps can cause.",
    "Log-derivative trick": "The identity ∇_θ E_{x∼p_θ}[f(x)] = E_{x∼p_θ}[ f(x) ∇_θ log p_θ(x) ], also called the score-function or likelihood-ratio estimator. It turns the gradient of an expectation into an expectation of a gradient, making it estimable by sampling and underpinning every policy-gradient algorithm.",
    "Loss scaling": "Multiplying the loss by a large factor S before backprop so every gradient is scaled by S, lifting tiny values out of fp16's underflow region, then dividing the gradients by S before the weight update. Dynamic loss scaling tunes S automatically, halving it whenever an inf/NaN appears.",
    "LSTM (Long Short-Term Memory)": "A gated recurrent cell (Hochreiter & Schmidhuber, 1997) that adds a cell state updated mostly additively, with three sigmoid gates — forget, input, output — controlling what to erase, write, and read. The additive cell path forms a 'constant error carousel' whose near-identity gradient defeats the vanishing-gradient problem.",
    "Markov Decision Process (MDP)": "The standard formalization of the RL problem: the tuple ⟨S, A, P, R, γ⟩ of states, actions, transition probabilities, rewards, and a discount factor. It is a Markov chain in which transitions depend on a chosen action and every transition emits a reward.",
    "Maximum-entropy RL (SAC)": "An objective that adds a per-step entropy bonus αH(π) to the return, paying the agent to stay as random as it can while still performing well. It turns exploration into a first-class term rather than a bolt-on heuristic and underpins Soft Actor-Critic, the sample-efficient off-policy default for continuous control.",
    "Minimax objective": "The single value function the two networks optimize in opposite directions: the discriminator maximizes it (scoring real high, fake low) while the generator minimizes it. With the optimal discriminator substituted in, the generator is provably minimizing the Jensen–Shannon divergence between the data and its samples.",
    "Minimax theorem": "Von Neumann's result that in any finite two-player zero-sum game, once mixed strategies are allowed, the maximin equals the minimax. Their common value is the value of the game, computable by linear programming.",
    "Mixed strategy": "A probability distribution over a player's pure actions. Payoffs become expected payoffs; randomizing can be strictly safer than any deterministic choice because it leaves the opponent nothing to exploit.",
    "Mixed-precision training": "Running most computation in 16-bit (fp16 or bf16) for speed and memory while keeping an fp32 master copy of the weights and fp32 reductions for numerical safety. fp16 needs loss scaling to avoid gradient underflow; bf16 keeps fp32's exponent range and usually needs none.",
    "Mode collapse": "A GAN failure in which the generator concentrates most of its probability mass on a small set of outputs that reliably fool the current discriminator, instead of covering the full diversity of the data. It is a symptom of the unstable, non-stationary optimization that adversarial games are prone to, and a major motivation for alternatives such as Wasserstein GANs.",
    "Model-free reinforcement learning": "A family of methods that learn values or policies directly from sampled experience without ever building or being given the environment's transition and reward model. The expectation that dynamic programming computes by summing against a known model is instead recovered by averaging actual transitions (s, a, r, s′).",
    "Momentum (optimizer)": "An optimizer modification that accumulates an exponentially-decaying running average of past gradients (a velocity) and steps along it. Consistent directions reinforce while oscillating ones cancel; for a steady gradient the effective step grows by 1/(1−μ), a 10× amplification at the usual μ = 0.9.",
    "Monte-Carlo prediction": "Estimating a value function by averaging the actual returns that follow each state under a fixed policy. It is unbiased and makes no Markov assumption, but must wait until an episode terminates to compute the return and tends to have high variance.",
    "Multiplicative (Luong) attention": "The 2015 simplification that scores alignment with a dot product (sᵀh), an optional learned matrix (sᵀW·h, the 'general' form), or a concat MLP. Faster and more memory-efficient; its scaled 'general' form became scaled dot-product attention in the Transformer.",
    "Nash equilibrium": "A strategy profile in which no single player can increase their payoff by unilaterally changing their own strategy. Every finite game has at least one, provided mixed (randomized) strategies are allowed; it predicts stability, not collective optimality.",
    "Non-saturating loss": "Goodfellow's practical reformulation in which the generator maximizes log D(G(z)) instead of minimizing log(1−D(G(z))). It shares the same fixed point but supplies strong gradients early in training, when the discriminator easily rejects the generator's outputs and the original loss is nearly flat.",
    "Normal-form game": "A model of strategic interaction given by a set of players, a strategy set for each player, and a payoff function for each player defined over the full profile of everyone's choices. Each player's reward depends on what all players do, not just on their own move.",
    "On-policy vs off-policy": "A method is on-policy if it learns about the same policy it uses to act, and off-policy if it can learn about one policy while behaving according to another. SARSA is on-policy (it bootstraps from the action it actually takes, learning the value of its own exploratory behavior); Q-learning is off-policy (it bootstraps from the greedy action, learning the optimal policy it does not follow).",
    "Policy": "The agent's behavior rule, a (possibly stochastic) mapping π(a | s) from states to actions. It is the object RL ultimately searches for; in a Markov environment an optimal policy that depends only on the current state — not on time or history — is guaranteed to exist.",
    "Policy evaluation": "The prediction step of dynamic programming: computing V^π for a given policy π, usually by iterating the Bellman expectation backup to convergence from any initial guess. It scores a policy but does not improve it; its value is as the inner loop of policy iteration and as the template every model-free prediction method imitates.",
    "Policy gradient": "A method that optimizes a parameterized policy π_θ(a | s) directly by gradient ascent on expected return J(θ), rather than learning a value function and acting greedily. It handles continuous actions and genuinely stochastic policies, at the cost of high-variance gradient estimates.",
    "Policy gradient theorem": "The result that ∇_θ J(θ) = E[ Σ_t ∇_θ log π_θ(a_t | s_t) · Ψ_t ], expressing the gradient of expected return as an expectation that can be estimated from sampled trajectories. The environment's transition probabilities drop out, so no model of the world is needed; algorithms differ only in their choice of the weight Ψ_t.",
    "Policy improvement theorem": "The guarantee that acting greedily with respect to V^π for one step and then following π yields a new policy π' with V^{π'}(s) ≥ V^π(s) for every state, strictly better somewhere unless π is already optimal. It is what makes the greedy step of policy iteration monotone and is the engine behind generalized policy iteration.",
    "Policy iteration": "A control algorithm that alternates full policy evaluation with a full greedy policy-improvement step until the policy stops changing. The policy improvement theorem guarantees each round is monotonically non-worse, and since a finite MDP has finitely many deterministic policies it terminates at the exact optimum in a finite number of rounds.",
    "Pooling": "A parameter-free operation that slides a window over a feature map and replaces each region with a single summary value, usually the maximum (max-pooling) or the mean. A 2x2 stride-2 pool halves each spatial dimension (quartering the area) and grants small-shift invariance. Modern networks often replace it with strided convolutions, but global average pooling remains the standard bridge from the final feature map to a linear classifier.",
    "Posterior collapse": "A VAE failure mode in which a powerful decoder learns to ignore the latent code; the KL term then drives the approximate posterior all the way to the prior, so z carries no information. KL annealing, free-bits, and weaker decoders are the usual remedies.",
    "PPO (Proximal Policy Optimization)": "A policy-gradient method that limits how far each update moves the policy via a clipped probability-ratio objective, min(rho*A, clip(rho, 1-eps, 1+eps)*A). In RLHF it optimizes the reward model's score minus a KL penalty to the reference, and its conservatism is what keeps the policy in the region where the reward model is still trustworthy.",
    "PPO clipped surrogate objective": "Proximal Policy Optimization's core loss: it multiplies the advantage by the new/old policy probability ratio r_t but clips r_t to [1−ε, 1+ε] and takes the pessimistic minimum, so once an update would move the policy too far in the rewarding direction the gradient switches off. A first-order, one-line approximation to TRPO's KL trust region; the default ε is 0.2.",
    "Prisoner's Dilemma": "The canonical two-player game in which defecting strictly dominates cooperating (T > R > P > S), so two rational one-shot players both defect and reach an outcome both would rather avoid. It is the cleanest demonstration of the conflict between individual and collective rationality.",
    "Q-learning": "An off-policy TD control algorithm that learns the optimal action-value function Q* by bootstrapping from the greedy next action, max_{a′} Q(s′, a′), regardless of how the agent actually behaves. It converges to Q* with probability 1 in finite MDPs under standard conditions, but the max operator induces a maximization bias that overestimates values.",
    "Receptive field": "The region of the original input that influences a single unit in a deep feature map. It grows with depth by the recursion r_l = r_{l-1} + (k-1) * j_{l-1}, where the jump j (feature stride) multiplies by the stride at each layer; stacking 3x3 convs grows it linearly, while inserting a stride-2 pool doubles the jump and makes every later layer reach twice as far. The effective receptive field is usually smaller than this theoretical one.",
    "Recurrent neural network (RNN)": "A network that processes a sequence one step at a time, maintaining a hidden state that summarizes everything seen so far and updating it with the same shared weights at every step. Unrolling the recurrence over T steps yields a depth-T feed-forward network whose layers share parameters.",
    "REINFORCE": "The original Monte-Carlo policy-gradient algorithm (Williams, 1992): roll out a full episode, compute the return-to-go G_t from each step, and weight the score ∇_θ log π_θ(a_t | s_t) by G_t. It is unbiased but high-variance and must wait for episodes to finish.",
    "Reparameterization trick": "Writing a latent sample as z = mu + sigma * eps with eps drawn from a fixed standard normal, so the only randomness sits in eps and gradients flow through mu and sigma. It makes the stochastic VAE trainable end-to-end by ordinary backpropagation.",
    "Repeated game": "A game in which the same players play a fixed one-shot stage game over and over, allowing strategies to condition on history. Repetition makes punishments credible, which is why cooperation that is impossible in a single play can become a stable equilibrium once the game repeats.",
    "Replicator dynamics": "The differential equation governing how strategy frequencies change under selection: a strategy's share grows in proportion to how much its fitness exceeds the population average. Its stable rest points are exactly the evolutionarily stable strategies, and on Hawk–Dove it converges to the mixed ESS at Hawk fraction V/C.",
    "Residual / skip connection": "Adding a block's input back to its output, y = F(x) + x, so the layers learn only a residual correction rather than the full mapping. Introduced by ResNet (2015), it lets unneeded layers default to the identity and gives gradients a direct path to early layers, defeating the degradation that stopped plain networks past ~20 layers. The residual stream it created underpins essentially every deep architecture today, Transformers included.",
    "Residual connection (skip)": "A shortcut that adds a block's input to its output, h_{l+1} = h_l + F(h_l) (EQ N1.7), so the block learns only a residual correction. Differentiating gives I + dF/dh, an additive identity path that lets the gradient reach early layers undiminished — the idea behind ResNets and the Transformer residual stream.",
    "Reward hypothesis": "The foundational claim that every goal can be cast as the maximization of expected cumulative scalar reward. It is what makes RL a single, general framework, and most practical RL failures — reward hacking, specification gaming — are failures of writing down the reward, not of optimizing it.",
    "Risk dominance vs payoff dominance": "Two competing criteria for selecting among multiple equilibria in a coordination game. A payoff-dominant equilibrium yields the highest payoff for all players; a risk-dominant one is the safer choice under uncertainty about the partner's action. Learners and populations frequently converge to the risk-dominant (worse) equilibrium when initial beliefs fall below the basin threshold.",
    "RLHF (Reinforcement Learning from Human Feedback)": "A three-stage alignment recipe: supervised fine-tune a base model, train a reward model on human preference comparisons, then optimize the policy against that reward model with an RL algorithm (usually PPO) under a KL penalty to the starting point. It is the technique behind InstructGPT and the first generation of aligned chat assistants.",
    "RLVR (RL from Verifiable Rewards)": "Training against a deterministic checker rather than a learned reward model: a math answer is graded right or wrong, code passes the unit tests or not. The reward is clean and (mostly) ungameable, and running GRPO on verifiable math and code is what made long-chain reasoning behavior emerge in models like DeepSeek-R1.",
    "Seed sensitivity": "The phenomenon, documented by Henderson et al. (2018), that identical deep-RL code with identical hyperparameters can yield wildly different learning curves when only the random seed changes — because the agent generates its own data and tiny early differences compound. It is why credible deep-RL results report many seeds with their spread, not a single curve.",
    "Self-play": "A training scheme in which an agent generates all of its own training data by playing against copies or past versions of itself, with no external dataset or teacher. Because the opponent improves whenever the agent does, the difficulty rises automatically, producing a self-generating curriculum — the mechanism behind AlphaZero, AlphaStar, and Pluribus.",
    "Sequence-to-sequence (seq2seq)": "An encoder-decoder architecture in which one network reads a variable-length input sequence into a state and a second network generates a variable-length output sequence from it. Introduced for machine translation, it underlies summarization, dialogue, captioning, and speech-to-text.",
    "Shadow of the future": "The weight a player places on payoffs in later rounds, governed by the discount factor δ. A long shadow (δ near 1) means future punishment outweighs the one-round gain from cheating, which is the lever that makes cooperation rational in repeated games.",
    "Stag Hunt": "A two-player coordination game with two pure Nash equilibria: hunting a stag together (payoff-dominant) and each hunting hare (risk-dominant, safe). With the payoffs (4,4)/(3,3), cooperation is rational only when you believe your partner cooperates with probability above 0.75 — a threshold, not a payoff comparison, which is why coordination in multi-agent systems is hard.",
    "StyleGAN / AdaIN": "A style-based generator that maps the latent z to an intermediate code w and uses it to modulate feature-map statistics (adaptive instance normalization) at every resolution. Coarse layers control pose and shape, fine layers control texture, enabling disentangled style mixing and the first widely photorealistic synthetic faces.",
    "Target network": "A periodically-frozen copy of the value network whose parameters compute the regression target in the DQN loss, so the bootstrap target does not move while the online network is trained toward it. Refreshed by a hard copy every C steps or by a slow Polyak (exponential moving average) update θ⁻ ← τθ + (1−τ)θ⁻.",
    "Temporal-difference (TD) error": "The quantity δ_t = R_{t+1} + γ V(s_{t+1}) − V(s_t): the gap between two successive predictions of the same return, before and after seeing one step of reward. Driving it toward zero is the engine of nearly every value method in modern RL, and a strikingly similar signal is encoded by dopamine neurons in the brain.",
    "Tit-for-tat": "The strategy that cooperates on the first move and thereafter copies the opponent's previous move. It won Axelrod's iterated-Prisoner's-Dilemma tournaments by being nice, retaliatory, forgiving, and clear — never beating any single opponent, yet scoring highest overall by eliciting mutual cooperation.",
    "Transfer learning": "Reusing a CNN pre-trained on a large dataset (typically ImageNet) instead of training from scratch. In feature-extraction mode the backbone is frozen and only a new classifier head is trained; in fine-tuning mode some or all of the backbone is unfrozen and adapted at a small learning rate. It works because early-layer features are near-universal and transferability falls with depth, so freezing the bottom and retraining the top reaches strong accuracy from hundreds rather than millions of examples.",
    "Translation equivariance vs invariance": "Convolution is equivariant: shift the input and the feature map shifts identically, because the same shared weights run at every location. Pooling converts a little equivariance into local invariance: shift the input slightly and the pooled output does not change, because the summary (e.g. the max) ignores where in the window the activation occurred. Equivariance preserves location; invariance discards it.",
    "Value bootstrap": "Estimating the value of a state from the (current, imperfect) value estimates of the states it leads to, so the estimates pull one another toward consistency rather than being supplied as labels. In two-player zero-sum games the backup is a minimax (negamax), and iterating it is a contraction that converges to the game's true values.",
    "Value function": "The expected return from a state (V^π(s)) or a state–action pair (Q^π(s, a)) under a given policy. Values are always relative to a policy; their difference Q^π − V^π is the advantage, and estimating them is how a good policy is found, since acting greedily with respect to Q needs no model of the environment.",
    "Value iteration": "A control algorithm that applies the Bellman optimality backup — a single greedy max over actions — to every state each sweep, driving V straight to V* without naming intermediate policies. It is policy evaluation truncated to one step before re-improving, and converges geometrically because the Bellman optimality operator is a γ-contraction.",
    "Vanishing / exploding gradient": "The failure mode of training deep or recurrent nets where the backpropagated gradient is a long product of Jacobians (EQ N3.2) that shrinks toward zero or grows without bound geometrically with distance. Vanishing gradients silently blind an RNN to long-range dependencies; exploding gradients are curable by norm clipping, but vanishing ones need an architectural fix.",
    "Vanishing / exploding gradients": "The geometric decay or blow-up of the backward signal in a deep network, because the gradient at a layer is a product of one Jacobian per layer (EQ N1.2). When the typical singular value is below 1 the product shrinks to zero and early layers stop learning; above 1 it explodes and training diverges. Init, normalization, and residuals all exist to keep that product near 1.",
    "Variational autoencoder (VAE)": "A probabilistic autoencoder whose encoder outputs a distribution (mean and variance) rather than a point, with a loss that regularizes that distribution toward a standard-normal prior. The result is a smooth, gap-free latent space you can sample from, turning the autoencoder into a generative model.",
    "Wasserstein distance (earth-mover's)": "The minimum average 'dirt times distance' cost of reshaping one probability distribution into another. Unlike Jensen–Shannon divergence it varies continuously even when the two distributions have disjoint support, so it provides a usable gradient where JSD is stuck at a flat ceiling — the basis of WGAN.",
    "Weight decay (L2) and AdamW": "An L2 penalty (lambda/2)·sum(w^2) that shrinks every weight toward zero each step (EQ N1.10), biasing the model toward smoother, lower-variance functions. With adaptive optimizers, classical L2 and true weight decay differ because the gradient is rescaled; AdamW decouples the decay from the adaptive step and is the modern default.",
    "WGAN / WGAN-GP": "GAN variants that replace the JS-divergence objective with the Wasserstein-1 distance via its Kantorovich–Rubinstein dual, turning the discriminator into a 1-Lipschitz critic. The Lipschitz constraint is enforced by weight clipping (WGAN) or, more stably, a gradient penalty (WGAN-GP), giving a loss that correlates with sample quality.",
    "Xavier (Glorot) initialization": "A variance-preserving weight init that sets Var(W) = 2/(n_in + n_out), the harmonic compromise between keeping forward and backward variance at 1. Derived assuming a roughly linear activation around zero, so it is the right default for symmetric, zero-centered nonlinearities such as tanh.",
    "Zero-sum game": "A two-player game of pure conflict in which one player's gain is exactly the other's loss, so the payoffs sum to zero in every cell. Describable by a single matrix where one player maximizes and the other minimizes.",
    "ε-greedy exploration": "An action-selection rule that takes the current greedy (best-estimated) action with probability 1−ε and a uniformly random action with probability ε. ε is usually annealed from high to low under a GLIE schedule — greedy in the limit with infinite exploration — so the agent explores widely early and exploits what it has learned later while keeping a small permanent exploration floor.",
    /* ---- V2 expansion terms ---- */
    "Autograd graph": "The directed acyclic graph PyTorch records on the fly during the forward pass whenever a tensor has requires_grad=True. Each node stores the op that produced it and a grad_fn for its local derivative. It is dynamic (define-by-run): control flow builds a fresh graph every iteration, and the graph is freed after the backward pass.",
    "BitNet b1.58": "A Transformer trained from scratch with weights constrained to the ternary set {-1, 0, +1}, about log₂3 ≈ 1.58 bits per weight. It reportedly matches full-precision models at billion-parameter scale while replacing most multiplications with additions; how far the result holds at the very largest scales remains contested.",
    "Broadcasting": "The rule that lets tensors of different shapes combine without explicit replication. Shapes are aligned from the right, each axis pair must be equal or have a 1 on one side, and a size-1 axis is virtually stretched (stride 0, no memory copied) to match. Getting it wrong yields a silently mis-shaped result rather than a crash — the most common source of shape bugs.",
    "Computation graph": "A directed graph whose nodes are operations and whose edges are tensors flowing between them; it is the data structure TensorFlow uses to represent a program. Seeing the whole graph before execution lets the runtime fuse ops, place them on devices, and serialize the model for deployment, and it is also exactly what makes backpropagation mechanical: each node records how to push a gradient from its output back to its inputs.",
    "Dataset / DataLoader": "A Dataset exposes __len__ and __getitem__(i) to return one example; a DataLoader wraps it to handle batching (collation), shuffling each epoch, and parallel prefetch via num_workers. One epoch yields ceil(N/B) minibatches and therefore that many optimizer steps, the number that sets the training budget.",
    "Dense (fully-connected) layer": "A layer computing y = phi(W x + b): an affine map from d_in inputs to u outputs followed by an activation. It holds a weight matrix of shape u x d_in plus a bias vector of length u, for (d_in + 1) * u trainable parameters. Keras infers d_in lazily from the first tensor that flows in, which is why a freshly built Dense layer reports zero parameters until it has seen an input shape.",
    "Dynamic batching": "A serving technique that holds incoming requests for a few milliseconds and runs them through the model together, exploiting the fact that a GPU processes a batch of N almost as fast as a single item. It trades a little tail latency for a large throughput gain and is the central lever of high-utilization inference servers.",
    "Eager vs graph execution": "Two execution modes. Eager runs each operation immediately like NumPy, so tensors hold real values you can print and debug; graph mode (entered in TensorFlow via tf.function) traces the Python into a static graph the first time it runs and then reuses that fused graph, paying a one-time tracing cost in exchange for near-zero per-call Python overhead. TensorFlow 2.0 made eager the default while keeping graph mode on demand; PyTorch's torch.compile mirrors the same write-eager-compile-later pattern.",
    "Extreme / sub-4-bit quantization": "Compressing a model's weights below the practical 4-bit floor — to 3, ~2.x, or even ~1.58 effective bits — where naive uniform rounding fails because of a few large outlier weights. It works only with rotation/incoherence preprocessing and learned codebooks (QuIP#, QuaRot) or by training at low precision (BitNet b1.58), trading model size against quality.",
    "Gradient accumulation / zero_grad": "PyTorch adds each backward pass's gradients into .grad rather than overwriting, which is why a fan-out node sums contributions over all paths and why you must call optimizer.zero_grad() every step. The same behavior lets you split a large effective batch across several backward passes before one optimizer step.",
    "Hybrid architecture": "A model that interleaves mostly linear-cost mixers (SSM or linear attention) with a thin fraction of full softmax-attention layers. The linear layers carry the bulk of token mixing cheaply while the few attention layers supply the exact long-range recall that linear mixers lack — the 2026 sweet spot, exemplified by Jamba and Griffin-style designs.",
    "Incoherence processing": "A quantization preprocessing step that multiplies weights and activations by random orthogonal or Hadamard rotations. The rotation preserves the matrix product but spreads concentrated outlier values across all dimensions, making the distribution more uniform and far easier to quantize accurately at very low bit-widths. Core to QuIP#, QuaRot, and SpinQuant.",
    "JAX": "A NumPy-compatible library of composable function transformations — jit (compile to XLA), grad (autodiff), vmap (auto-vectorization), pmap/shard_map (device parallelism) — that compose orthogonally, e.g. jit(grad(vmap(f))). Its purity requirement powers large-scale TPU training and routes deployment through StableHLO rather than ONNX.",
    "Keras": "A high-level neural-network API, created by Francois Chollet in 2015, designed around progressive disclosure of complexity: the common case is one line and customization is available exactly when needed. It is TensorFlow's official high-level API (tf.keras) and, since Keras 3, runs on a choice of TensorFlow, JAX, or PyTorch backends behind one identical interface.",
    "Model artifact": "A self-contained, versioned, serializable representation of just a model's forward computation and its trained weights, with the training scaffolding (autograd, optimizer state, Python imports) stripped away. Unlike a live notebook object it is portable, frozen, and optimizable — the thing deployment actually ships.",
    "model.fit / custom training loop": "model.fit is Keras's built-in training loop: after compile(optimizer, loss, metrics), one call iterates batches and epochs and runs the forward pass, loss, backpropagation, optimizer update, metric accumulation, and validation, while firing callbacks such as EarlyStopping and ModelCheckpoint. A fully custom loop (a tf.GradientTape plus optimizer.apply_gradients written by hand) trades that convenience for total control and is warranted only by genuinely non-standard control flow; overriding train_step is the usual middle ground.",
    "nn.Module": "The base class for PyTorch models. Subclass it, register child modules and nn.Parameter tensors in __init__, and define forward(); then parameters() recursively yields every learnable tensor for the optimizer, and to(device), state_dict(), and train()/eval() are handled for you. A raw tensor assigned as an attribute is invisible to the optimizer — use nn.Parameter or register_buffer.",
    "ONNX (Open Neural Network Exchange)": "A framework-agnostic graph format plus a versioned standard operator set that lets a model trained in one framework run on runtimes written for another. It turns an F×R matrix of bespoke converters into F+R hub-and-spoke connectors and is the canonical route for cross-framework and browser deployment.",
    "Opset version": "The version of the ONNX standard operator set a model is exported against. It is the portability contract: a model built for a given opset produces identical results on any runtime that implements that opset, which is what makes ONNX truly framework-neutral.",
    "prefetch / overlap": "The input-pipeline technique of producing batch t+1 on the CPU while the model computes batch t on the GPU, so data preparation is hidden behind computation. With balanced costs it roughly halves step time; once one side dominates the other, the win shrinks, which is why profiling decides whether you are input-bound or compute-bound. PyTorch's DataLoader achieves the same overlap via num_workers, pin_memory, and prefetch_factor.",
    "Reverse-mode autodiff (.backward)": "The algorithm loss.backward() runs: it walks the autograd graph in reverse topological order, applies the chain rule at each node, and deposits dloss/dtheta into each leaf tensor's .grad. One backward pass yields the gradient of a single scalar loss with respect to all parameters at once — the regime deep learning needs.",
    "SavedModel / TFLite (LiteRT)": "TensorFlow's serving artifacts. SavedModel is the complete language-neutral graph-plus-variables directory that TF Serving and TensorFlow.js load; TFLite (LiteRT) is the edge sibling — a compact, mmap-able FlatBuffer, usually int8/float16 quantized, built for phones, microcontrollers, and embedded accelerators.",
    "Selective SSM (Mamba)": "A state-space model whose write, read, and step-size parameters are functions of the current input rather than fixed constants. This input-dependence lets the model choose what to remember and how fast to forget per token, recovering much of attention's content-aware selectivity while keeping linear cost; it is computed on GPUs with a hardware-aware parallel scan.",
    "Sequential / Functional / Subclassing APIs": "Keras's three ways to define a model. Sequential is a plain list of layers for a single input-to-output chain; the Functional API expresses an arbitrary directed graph of layers, needed for multiple inputs/outputs, skip connections, or shared layers; subclassing writes an imperative call() method for models whose control flow depends on the data. Power increases left to right; most real models use the Functional API.",
    "State-space duality (SSD)": "The Mamba-2 result that a selective SSM (with scalar state decay) and a particular form of structured masked attention compute the same function by two routes. The quadratic 'attention' form is efficient for parallel training; the linear 'recurrent' form is efficient for constant-memory inference. SSD is why 'Transformers are SSMs.'",
    "State-space model (SSM)": "A sequence model built on a linear recurrence from control theory: a fixed-size hidden state is updated from each input token and read out as the output. Because the state never grows, an SSM processes a sequence in time linear in its length and decodes with constant memory, unlike attention's quadratic cost and growing KV cache.",
    "Stride / view": "Stride is the per-axis step count that maps a multi-dimensional index to a flat memory offset. Operations like view, transpose, permute, and most slices return a new tensor that shares the same storage and only reinterprets the strides, so they are zero-copy; a non-contiguous result sometimes needs .contiguous() before ops that demand a packed layout.",
    "Tensor": "PyTorch's core data structure: an n-dimensional array of a single dtype stored in a contiguous block of memory, described by a shape (logical dimensions) and a stride (elements to step per axis). It mirrors NumPy's ndarray but adds two superpowers — it can live on a GPU and it can record an autograd history for automatic differentiation.",
    "tf.data pipeline": "TensorFlow's declarative input API: a chain of transformations on a Dataset (map, shuffle, batch, prefetch, cache) that feeds the model. Its purpose is throughput, chiefly via prefetch, which lets the CPU prepare the next batch while the accelerator trains on the current one, turning a per-step cost of t_input + t_compute into max(t_input, t_compute).",
    "TorchScript / torch.export": "PyTorch's native artifact paths for running a model without Python. TorchScript (now in maintenance) captures the model into an IR for the libtorch C++ runtime; torch.export is its successor, producing an ahead-of-time ExportedProgram (FX graph) that feeds torch.compile and the ExecuTorch edge runtime.",
    "Tracing vs scripting": "The two ways to recover a static computational graph from eager Python. Tracing runs one example and records the operations it executed (fast, but bakes in that input's control flow); scripting parses the source and compiles loops and branches into the graph (preserves dynamism over a typed subset of the language).",
    "Triton Inference Server": "NVIDIA's framework-agnostic serving system that hosts models in many backends at once (TensorRT, ONNX Runtime, PyTorch, TensorFlow, vLLM) behind one HTTP/gRPC API, adding concurrent model execution, dynamic batching, ensembles, and metrics. The default when a fleet must serve a zoo of models from different frameworks on shared GPUs.",
    /* ---- V2 expansion terms ---- */
    "700M-MAU scale clause": "A provision in Meta's Llama community license requiring a separate agreement from Meta if the licensee's products exceed 700 million monthly active users. It is the canonical example of a community-license carve-out that only affects hyperscaler-grade deployments but constrains them sharply.",
    "Acceptable-use policy (AUP)": "A clause, attached to nearly every modern release whether open or closed, that forbids specific harmful uses of the model. It is a real, enforceable restriction that travels with even 'open' weights, which is why open does not mean rule-free.",
    "Action tokenization": "Discretizing a continuous robot action so a token model can produce it: each action dimension is clipped to a range, split into B uniform bins, and replaced by its bin index. Decoding returns the bin center, so the round-trip error is at most half a bin width — the resolution ceiling of a binned policy.",
    "Attack Success Rate (ASR)": "The fraction of attack attempts in a fixed, versioned suite that elicit prohibited behavior, as judged by a harm classifier or human review; robustness is 1 − ASR. It is only meaningful pinned to its suite version and its judge — a defense that drives a stale suite to zero can sit far higher on next month's attacks, and the judge itself has false positives and negatives. Credible safety claims state ASR as a number against a named suite plus a held-out novel-attack slice.",
    "Audio language model": "A transformer trained to predict the next audio token over a neural-codec vocabulary, exactly as a text LLM predicts the next word. AudioLM showed it can continue speech or music coherently — preserving speaker, prosody, and room acoustics — with no transcript. Models often split tokens into coarse semantic and fine acoustic streams, and text-conditioned variants (MusicGen, VALL-E) prepend text or a reference clip; frontier omni models emit audio tokens directly with no separate ASR or TTS stage.",
    "Behavior cloning (imitation learning)": "Training a policy by supervised regression of expert actions onto the observations the expert visited — essentially LLM pretraining with actions for tokens. It is sample-efficient and stable but suffers covariate shift: the policy's own small errors push it into states no demonstration covered, where errors compound.",
    "Classifier-free guidance (CFG)": "A sampling technique that runs the diffusion model both with and without the caption and extrapolates along their difference by a guidance scale s. Higher s increases prompt adherence at the cost of diversity (and, too high, of realism); s=1 is plain conditional sampling, s=0 ignores the prompt. No separate classifier is required.",
    "CLIP": "Contrastive Language-Image Pre-training: two encoders (image and text) trained on hundreds of millions of image-caption pairs to make a true image-caption pair score higher (cosine similarity) than all mismatched pairs in the batch. Its image encoder produces language-aligned visual features and is the standard vision front end for downstream VLMs.",
    "Closed / proprietary model": "A model reachable only as a hosted API — you send tokens in and get tokens out, billed per token, and never possess the weights. GPT, Claude, and Gemini flagships are closed; you rent frontier capability and managed operations in exchange for giving up possession, fine-tuning of the base, and version control.",
    "Continued pre-training (DAPT)": "Resuming a base model's self-supervised next-token objective on a large corpus of in-domain raw text before any task fine-tuning. Domain-adaptive pre-training installs vocabulary and distributional knowledge the original pre-training never built; the cheaper task-adaptive variant (TAPT) pre-trains on the unlabeled task data itself.",
    "Convolutional backbone": "The stack of convolution, normalization, and pooling blocks that turns an image into a feature volume, with a small task head bolted on top. It encodes the priors of locality and translation equivariance by sliding small shared kernels across the image, and typically shrinks the spatial grid while growing channel depth. The LeNet-to-ResNet lineage of backbones (AlexNet, VGG, GoogLeNet, ResNet) defined modern vision before the Vision Transformer.",
    "Cross-attention fusion": "Keeping the text sequence as the only main sequence and letting it attend into a separate image memory through dedicated cross-attention layers inserted between the LLM's blocks (the Flamingo recipe). Queries come from text, keys and values from the N image features, costing N*T and leaving the base LLM's weights and context length untouched.",
    "Cross-embodiment learning": "Training a single policy on demonstrations pooled across many different robot bodies, sensors, and action spaces so each robot benefits from data it could never collect alone. Open X-Embodiment was the landmark effort, pooling roughly a million trajectories across 22 embodiments to partially offset robotics' chronic data scarcity.",
    "Decode bandwidth bound": "The observation that single-stream autoregressive decoding is limited by memory bandwidth, not compute: generating each token reads essentially every weight once, so tokens-per-second is upper-bounded by the device's memory bandwidth divided by the bytes read per token. This is why quantizing 16-bit to 4-bit speeds up decode roughly 4x — it reads 4x fewer bytes per token — and why prefill, which is parallel and compute-bound, behaves oppositely.",
    "Denoising objective (noise prediction)": "The diffusion training loss in which the network ε_θ(x_t, t) predicts the exact noise that was added at a randomly chosen timestep, rather than the clean image. Because the target noise is unit-variance at every step, this regression is far easier to optimize than predicting pixels directly.",
    "Diffusion model": "A generative model that learns to reverse a fixed noising process: training adds Gaussian noise to data and a network learns to predict and remove it, so sampling starts from pure static and iteratively denoises a structured image out of it over a few dozen steps. Stable to train and mode-covering, unlike GANs.",
    "Diffusion transformer (DiT)": "A diffusion denoiser that replaces the convolutional U-Net with a transformer operating on patches of the (latent) image or video. It scales more cleanly with compute and is the backbone of Stable Diffusion 3 and Sora-class video models.",
    "Domain randomization": "Randomizing a simulator's parameters (masses, frictions, lighting, textures, sensor delays) so widely during training that the real world looks like just another sample. If the randomization distribution contains reality, the reality gap collapses into ordinary in-distribution generalization; too narrow overfits, too wide yields an over-conservative average policy.",
    "Early fusion": "Concatenating projected image tokens with text tokens into one sequence so the LLM's existing self-attention mixes both, in every layer. Maximally interactive and minimal to implement (the LLaVA recipe), but the image tokens consume context-window slots and the self-attention cost grows as (N+T)^2.",
    "Effective dataset diversity (N_eff)": "The exponential of the entropy of the source mixture, exp(-sum p_i log p_i): the perplexity of the source distribution after dedup. It collapses toward 1 as one source dominates and rises toward the source count when the mix is even, so it measures how evenly tokens are spread, not how many sources were collected.",
    "Elastic Weight Consolidation (EWC)": "A continual-learning regularizer that adds a quadratic penalty anchoring each weight to its old-task value, with stiffness set by that weight's Fisher-information importance. It approximates training on both tasks at once without keeping the old data, and matters most when the original corpus can no longer be revisited.",
    "Fine-tuning (vs prompting vs RAG)": "Continuing to train a pretrained model on task-specific examples so the desired behavior is baked into the weights. It is the third lever to reach for, after prompting and retrieval: prompting changes nothing, RAG changes the context, fine-tuning changes the weights. Use it for behavior, format, tone, domain dialect, or a narrow skill — not to inject facts, which RAG handles without going stale.",
    "Flow-matching action head": "A continuous alternative to action tokenization, used by π0, that learns a velocity field transporting Gaussian noise to an expert action chunk and integrates it at inference. It removes the quantization floor of binning and enables smooth high-frequency control, at the cost of a small iterative sampler instead of a single argmax.",
    "GCG (Greedy Coordinate Gradient)": "A white-box jailbreak that optimizes an adversarial token suffix to maximize the probability the model's reply begins affirmatively ('Sure, here is …') instead of refusing, using gradients of the loss with respect to one-hot input tokens to rank candidate swaps. It requires access to the weights, which makes it the canonical open-model threat, and its suffixes often transfer to closed models because aligned models share a similar refusal geometry.",
    "Gradual unfreezing": "A schedule, introduced with ULMFiT, that begins with everything frozen but the head and thaws blocks one at a time from the top down, each given a smaller learning rate than the layer above it (discriminative fine-tuning). It lets the task-specific top adapt on stable features before the deeper, more general representations are relaxed.",
    "Guard model": "A small, dedicated classifier (such as Llama Guard) that screens text for disallowed content — run on the incoming prompt and any retrieved/tool content as an input filter, and on the model's completion as an output filter. The output guard is powerful because it is content-addressed: it judges what actually came out regardless of how the attacker phrased the request, catching jailbreaks that defeated alignment. Guard models live in the system layer, which is exactly where durable safety belongs for open weights.",
    "ImageNet / ILSVRC": "A benchmark of roughly 1.2 million labelled training images across 1000 categories, used in the ImageNet Large Scale Visual Recognition Challenge. It gave the field a shared, hard, large-scale yardstick; AlexNet's 2012 win on it (cutting top-5 error from ~26% to ~16%) is the conventional start of the deep-learning era of vision.",
    "Imagined rollout": "A trajectory generated entirely inside a world model by feeding each predicted next state back into the transition function over a horizon, with no real environment steps. Dreamer trains an actor and critic on such rollouts; because a latent forward pass is far cheaper than a real step, this yields large sample-efficiency gains.",
    "Indirect prompt injection": "An attack where the adversary never talks to the model directly: they plant text in content the model later ingests as data — a web page, PDF, calendar invite, code comment — that the model then interprets as instructions. Because current models have no reliable in-band way to distinguish trusted developer instructions from untrusted retrieved content, it is treated as a structural problem solved with a hard trust boundary and least-privilege tools, not by prompt wording. It is the most important attack for any agentic or RAG system.",
    "Inference engine": "The software that turns a directory of open weights into generated text: it loads the tensors, applies the model's chat template, runs the forward pass, manages the KV cache, and samples tokens. Almost every practical choice — quantization format, batching strategy, GPU/CPU split — lives in the engine, not the weights, which are inert until something runs them. llama.cpp, vLLM, SGLang, TensorRT-LLM, and MLX are the common ones.",
    "Intersection over Union (IoU)": "The overlap of a predicted region and a ground-truth region divided by their combined area, |A ∩ B| / (|A| + |B| - |A ∩ B|), ranging from 0 (disjoint) to 1 (perfect match). It is the scale-free measure used to decide whether a detection counts (conventionally IoU ≥ 0.5) and, applied per-pixel, to score segmentation masks; averaging it over thresholds and classes gives mean Average Precision.",
    "Jailbreak": "Any input that elicits behavior a model's safety training was meant to prevent. Nearly every technique reduces to attacking the refusal decision in one of two ways: moving the prompt's internal representation off the learned 'harmful' direction (encoding, roleplay, translation), or drowning the harmful signal in benign context. Families include persona/roleplay, obfuscation, prefix/refusal suppression, many-shot, gradient-based suffixes, and indirect prompt injection.",
    "JEPA (Joint-Embedding Predictive Architecture)": "LeCun's architecture that predicts in representation space rather than pixel space: it encodes both an input and a target into embeddings and trains a predictor to map the input embedding to the target embedding, with no decoder or reconstruction loss. By predicting an embedding it can discard unpredictable detail, but it requires stop-gradient and EMA targets to avoid representation collapse.",
    "Latent action model": "Genie's mechanism for learning a controllable simulator from action-unlabelled video: for each pair of consecutive frames it infers a discrete latent action, from a tiny codebook, that best lets the dynamics model reconstruct the next frame. The small codebook forces the actions to capture controllable, recurring changes (jump, move) rather than memorize pixels.",
    "Latent dynamics": "A transition function that predicts the next state in a low-dimensional learned latent space rather than in raw observation (pixel) space. Working in the latent keeps only what is needed to predict the future, so the model spends capacity on behaviorally relevant structure instead of photo-realistic but irrelevant detail.",
    "Layer freezing": "Excluding a block's parameters from the optimizer so they keep their pre-trained values and receive no gradient, no optimizer state, and no backward pass. Freezing the lower (generic) blocks cuts trainable parameters and training memory and limits how far the weights can drift, which directly reduces catastrophic forgetting.",
    "llama.cpp": "A dependency-light C/C++ inference engine started by Georgi Gerganov in 2023 that runs LLMs on CPU, GPU (CUDA, Metal, Vulkan, ROCm), or any split of the two, and is the project that made local inference mainstream. Ollama and LM Studio are friendly wrappers over it, so when someone runs a model on a laptop, llama.cpp is usually the thing actually executing.",
    "LoRA (Low-Rank Adaptation)": "A parameter-efficient fine-tuning method that freezes the pretrained weight W0 and learns the update as a product of two thin matrices, W = W0 + (alpha/r)BA. For a square d x d layer it trains 2dr parameters instead of d-squared — a tiny fraction — so optimizer state and memory shrink proportionally. The adapter can be merged into W0 for zero inference overhead or kept separate and hot-swapped.",
    "LoRA rank (r)": "The inner dimension of a LoRA adapter, which sets its capacity and trainable-parameter count: a layer adds r*(d_in + d_out) parameters, growing linearly in r. Ranks 8-64 cover most tasks — style and format adaptations sit low, genuine new skills sit higher — with alpha = 2r a common scaling starting point and all linear layers the modern attachment default.",
    "Masked image modeling (MaskGIT/Muse)": "A non-autoregressive image generator that predicts many image tokens in parallel and reveals only the most confident ones each round, re-masking and repeating. It reaches a quality comparable to fast diffusion in roughly 8–12 rounds instead of hundreds of sequential autoregressive steps.",
    "Mel scale": "A perceptual frequency scale, m(f) = 2595 log10(1 + f/700), that approximates how human pitch perception compresses high frequencies. Filterbank bins spaced uniformly in mel widen geometrically in Hz, matching the ear's declining resolution. Warping a spectrogram onto ~80 mel bands and taking the log gives the log-mel spectrogram, the input consumed by almost every modern speech model.",
    "Model-predictive control (decision-time planning)": "Planning by rolling a learned model forward over a horizon, scoring candidate action sequences by their imagined discounted return plus a learned terminal value, executing only the first action of the best plan, then re-planning. MuZero is the canonical instance; the danger is that search amplifies model error, so plans can exploit dynamics the world does not actually have.",
    "Multi-LoRA serving": "Holding one base model in GPU memory and swapping or batching many small LoRA adapters over it, so a single card can host hundreds of per-task or per-customer fine-tunes. Because a rank-16 adapter is a few hundred MB versus tens of GB for the base, frameworks like S-LoRA and vLLM multi-LoRA keep the VRAM bill flat as the number of fine-tunes grows — the alternative to merging an adapter for lowest single-model latency.",
    "Neural audio codec (RVQ)": "A convolutional autoencoder (SoundStream, EnCodec) that compresses a waveform to a low-rate latent and quantizes it with residual vector quantization: a stack of Q codebooks, each quantizing the residual the previous one left behind. Stacking Q codebooks of K entries yields K^Q effective combinations at only Q*log2(K) bits, turning continuous audio into a grid of discrete tokens a language model can predict.",
    "Object hallucination (VLM)": "A VLM confidently describing objects that are not present in the image, the failure mode that benchmark accuracy tends to hide because the cross-entropy objective rewards fluent, plausible answers without grounding them to actual pixels. Adversarial probes such as POPE exist specifically to measure it.",
    "Open-source AI": "The stricter bar set by the Open Source Initiative's 2024 definition: weights plus enough data information and training code to reproduce the system, under a recognized open license. Most 'open' LLMs are open-weight rather than open-source; OLMo and Pythia are among the few that clear this bar.",
    "Open-weight model": "A model whose trained parameters are downloadable, so you can run it offline, fine-tune it, and pin a version forever. It says nothing about the training data or code, which are almost always withheld — Llama, Mistral, DeepSeek, and Qwen all ship weights without their corpora.",
    "Patch embedding": "The single image-specific operation in a ViT: each raw P x P x 3 patch is flattened and multiplied by one shared learned matrix E to produce a D-dimensional token vector, equivalent to a convolution whose kernel and stride both equal the patch size P. A 224x224 image with P=16 yields a 14x14 grid, i.e. 196 patch tokens plus the [CLS] token.",
    "Patch projection": "The single learned linear map W (shape d x P^2C) that turns a flattened image patch into one model-width token, plus an added learned positional embedding. Shared across all patches, it is equivalent to a stride-P convolution and is the only new module LLaVA adds on top of a frozen vision encoder and a frozen LLM.",
    "Patch token": "The visual analogue of a word embedding: one fixed-size square patch of an image, flattened and linearly projected into the language model's embedding space as a single d-dimensional vector. An H x W image at patch size P yields N = HW/P^2 patch tokens; the transformer then attends to them exactly as it attends to word tokens.",
    "Permissive vs community license": "A permissive open-source license (Apache-2.0, MIT) imposes minimal conditions and no field-of-use limits. A community or source-available license (such as Meta's Llama terms) is commercially usable but adds carve-outs — acceptable-use policies, naming requirements, or a scale clause — that bite a minority of users hard.",
    "Quality / control tokens": "Reserved special tokens written inline into training sequences (a leading quality or domain marker) that let a model condition on provenance and be told at inference to imitate only the good data. They must be atomic tokenizer tokens, not plain-text strings, so the model cannot hallucinate them mid-generation.",
    "Quantization (bits per weight)": "Storing each weight at lower numerical precision so it occupies fewer bits — the central lever that turns 'needs a datacenter' into 'runs on my desk.' Footprint is roughly bits-per-weight times parameters, so a 7B model is 14 GB at bf16, 7 GB at 8-bit, and 3.5 GB at 4-bit. Quality is near-lossless down to ~8 bits, drops only a little to ~4 bits, then falls off steeply below 4; Q4_K_M to Q5_K_M is the local sweet spot.",
    "Refusal direction": "The empirical finding from mechanistic interpretability that an aligned model's refusal behavior is often mediated by a single low-dimensional direction in activation space, rather than being diffusely distributed. This is why 'abliteration' can strip refusals from open weights without retraining, and a sharp illustration of the chapter's core caveat: safety training suppresses the expression of a capability, it does not remove the capability from the weights.",
    "Replay (rehearsal)": "Folding a fraction of the model's original general-domain data back into each training batch so the old distribution's gradients stay alive. Even 1-10% replay recovers most retained capability for a small slowdown in adaptation, making it the most reliable and cheapest defense against forgetting.",
    "Representation collapse": "The degenerate failure where an encoder maps every input to the same constant embedding, driving a joint-embedding loss to zero while learning nothing useful. JEPA and similar methods prevent it with an EMA target encoder, stop-gradient, and variance/covariance regularizers.",
    "RSSM (Recurrent State-Space Model)": "Dreamer's world model, which splits the latent into a deterministic recurrent hidden state that carries history and a stochastic state sampled from a learned distribution. It is trained variationally by pulling a prior (transition-only) toward a posterior (observation-conditioned) via a KL term, so the transition learns to anticipate latents before observations arrive.",
    "Self-host breakeven volume": "The monthly token volume n* = F / (p - m) at which renting an API (cost p per token) and self-hosting (fixed cost F plus marginal m per token) cost the same. Below it, renting is cheaper; above it, owning the weights wins and keeps winning as the fixed cost amortizes over more tokens.",
    "Semantic gap": "The mismatch between an image's low-level pixel values and the high-level meaning we want from it. Two photos of the same object can share almost no pixels while two photos of different objects can look nearly identical, so a useful vision model must learn a representation that is invariant to nuisances like lighting, viewpoint, and clutter. Closing this gap by learning a feature hierarchy from data, rather than hand-designing features, is the core advance of deep computer vision.",
    "Short-Time Fourier Transform (STFT)": "Sliding a window of N samples across a waveform (hopping by H samples each step) and taking the Fourier transform of each frame. The window length N sets the frequency resolution (df = fs/N) and the time resolution (dt = N/fs); because their product is fixed at 1, a long window resolves frequency well but blurs time, and a short window does the reverse — the audio form of the Heisenberg-Gabor uncertainty limit.",
    "Sim-to-real transfer": "Training a policy in a physics simulator and deploying it on hardware despite the reality gap — the mismatch between simulated and real dynamics, sensing, latency, and appearance. The dominant tool is domain randomization, often combined with system identification and a small amount of real-world fine-tuning.",
    "Spacetime latent patches": "The unit of Sora-class video generation: a video is compressed into small cubes spanning a few pixels and a few frames, and a diffusion transformer denoises the whole grid jointly. Attending across space and time together enforces temporal coherence, but its O(N²) cost is why long, high-resolution video is the hard part.",
    "Spectrogram": "A 2-D image of an audio signal with time on one axis and frequency on the other, produced by taking the magnitude of a Short-Time Fourier Transform of overlapping windowed frames. Brightness encodes energy at each time-frequency point. Phase is usually discarded, so a vocoder must re-synthesize it when reconstructing audio.",
    "Supervised fine-tuning (SFT)": "The standard instruction fine-tuning step: next-token prediction over example conversations, with the cross-entropy loss masked so it scores only the assistant's completion tokens, not the prompt. The model becomes exactly as good as the curated examples and no better, which is why dataset quality dominates everything else.",
    "Vision Transformer (ViT)": "An image classifier that applies a standard Transformer encoder to a sequence of image patches. The image is cut into non-overlapping P x P patches, each is flattened and linearly projected to a token embedding, a learnable [CLS] token and positional embeddings are added, and self-attention does the rest. It removes the convolutional prior entirely, gaining a global receptive field from the first layer at the cost of being data-hungry.",
    "Vision-language model (VLM)": "A transformer whose context window holds both image tokens and text tokens, generating text autoregressively over the combined sequence. Most modern VLMs reuse a pre-trained (usually CLIP) vision encoder and a pre-trained language model, joined by a small projection or by cross-attention layers.",
    "Vision-Language-Action model (VLA)": "A vision-language model whose output space is extended to include motor commands, so a single transformer maps camera frames and a language instruction to a robot action. RT-2 emits actions as discretized tokens from the model's own vocabulary; π0 attaches a continuous action head instead.",
    "Visual instruction tuning": "The second training stage of LLaVA-style VLMs: fine-tuning the projection and usually the LLM on multimodal instruction-following data (image + question -> answer, visual chat, OCR, grounding), with cross-entropy over the answer tokens only. LLaVA bootstrapped this data by prompting a strong text LLM with image annotations to author the conversations.",
    "Vocoder": "The second stage of neural text-to-speech: a model that converts a mel spectrogram into a waveform, re-inventing the phase the spectrogram discarded. WaveNet (2016) did this autoregressively with dilated causal convolutions — high fidelity but one sample at a time — and was largely replaced by GAN vocoders such as HiFi-GAN that generate an entire waveform in a single non-autoregressive forward pass.",
    "VQ-VAE / VQGAN tokenizer": "An autoencoder whose bottleneck snaps each latent vector to the nearest entry in a learned discrete codebook, turning an image into a sequence of integer tokens. This makes images consumable by autoregressive or masked transformers; reconstruction quality of the codebook caps the achievable fidelity.",
    "Waveform": "The raw, one-dimensional signal a microphone produces: a sequence of amplitude samples taken at a fixed sample rate (16 kHz for speech, 44.1/48 kHz for music). It is a faithful but punishingly long representation — one second of 16 kHz mono audio is 16,000 numbers — and locally almost meaningless, which is why audio models first transform it into something shorter and more structured.",
    "Whisper": "OpenAI's encoder-decoder transformer for speech recognition (2022), trained on 680,000 hours of weakly labelled multilingual web audio. The encoder ingests an 80-bin log-mel spectrogram and the decoder autoregressively predicts text, with special prompt tokens selecting the task (transcribe, translate, timestamps). Its robustness comes from scale rather than architecture; its failure mode is hallucinating fluent text on silent or unintelligible input.",
    "World model": "A learned simulator of an environment's dynamics: given a compact latent summary of the present and a proposed action, it predicts the next state (and often the reward). Once trained, it can be rolled forward in imagination to generate futures without touching the real environment, supporting prediction, generation, and planning.",
    "Zero-shot classification": "Classifying an image into categories the model was never explicitly trained on, by writing each candidate class as a text prompt (e.g. 'a photo of a {label}'), embedding the prompts with CLIP's text encoder, embedding the image with its image encoder, and choosing the label with the highest cosine similarity. The classifier is built on the fly from words, which is why it generalizes to open vocabularies and is robust across distribution shifts."
  };

  /* longest-first alternation so "multi-head attention" beats "attention" */
  var TERMS = Object.keys(DEFS).sort(function (a, b) { return b.length - a.length; });
  var PATTERN = new RegExp(
    "\\b(" + TERMS.map(function (t) {
      return t.replace(/[.*+?^${}()|[\]\\]/g, "\\$&").replace(/[- ]/g, "[- ]");
    }).join("|") + ")\\b", "i"
  );

  var SKIP = { SCRIPT: 1, STYLE: 1, CODE: 1, PRE: 1, A: 1, H1: 1, H2: 1, H3: 1, BUTTON: 1, SVG: 1, CANVAS: 1, SELECT: 1, INPUT: 1, OUTPUT: 1 };

  function skippable(el, allowWidget) {
    for (var n = el; n && n !== document.body; n = n.parentElement) {
      if (SKIP[n.tagName]) return true;
      var c = n.className;
      if (typeof c === "string") {
        if (c.indexOf("katex") !== -1 || c.indexOf("gloss") !== -1 ||
            c.indexOf("topbar") !== -1 || c.indexOf("side-nav") !== -1 ||
            c.indexOf("pager") !== -1) return true;
        /* inside widgets, only curated surfaces are glossed */
        if (!allowWidget && c.indexOf("widget") !== -1) return true;
        if (allowWidget && (c.indexOf("readout") !== -1 || c.indexOf("tok-") === 0 ||
            c.indexOf("r-value") !== -1)) return true;
        if (c.indexOf("eq-tag") !== -1) return true;
      }
    }
    return false;
  }

  var seen = {};   // term (lowercase) -> wrap count on this page
  var MAX_PER_TERM = 4;

  function canonical(raw) {
    var low = raw.toLowerCase().replace(/[- ]+/g, " ");
    for (var i = 0; i < TERMS.length; i++) {
      if (TERMS[i].toLowerCase().replace(/[- ]+/g, " ") === low) return TERMS[i];
    }
    return null;
  }

  function scan() {
    if (scan.done) return;
    scan.done = true;
    /* prose surfaces, plus curated widget surfaces (notes + control labels)
       and hub/landing surfaces — anywhere a reader meets a term cold */
    var PROSE = "main p, main li, main td, main .fig-cap, .lede, .eq-note, .eq-x-body, .t-desc, .how-card p, .cov-sub, .dr-exp";
    var WIDGETY = ".w-note, .ctl label, .drill .dr-q";
    var roots = [];
    document.querySelectorAll(PROSE).forEach(function (r) { roots.push({ el: r, w: false }); });
    document.querySelectorAll(WIDGETY).forEach(function (r) { roots.push({ el: r, w: true }); });
    roots.forEach(function (entry) {
      var root = entry.el, allowW = entry.w;
      if (skippable(root, allowW)) return;
      var walker = document.createTreeWalker(root, NodeFilter.SHOW_TEXT, {
        acceptNode: function (node) {
          return skippable(node.parentElement, allowW) ? NodeFilter.FILTER_REJECT : NodeFilter.FILTER_ACCEPT;
        }
      });
      var nodes = [];
      while (walker.nextNode()) nodes.push(walker.currentNode);

      nodes.forEach(function (textNode) {
        var text = textNode.nodeValue;
        var m = PATTERN.exec(text);
        if (!m) return;
        var term = canonical(m[1]);
        if (!term) return;
        var key = term.toLowerCase();
        if ((seen[key] || 0) >= MAX_PER_TERM) return;
        seen[key] = (seen[key] || 0) + 1;

        var span = document.createElement("span");
        span.className = "gloss";
        span.setAttribute("data-term", term);
        span.textContent = m[1];
        var after = textNode.splitText(m.index);
        after.nodeValue = after.nodeValue.slice(m[1].length);
        textNode.parentNode.insertBefore(span, after);
        /* one wrap per text node is enough — keeps DOM churn low */
      });
    });
    attachTip();
  }

  /* ---------- tooltip ---------- */
  function attachTip() {
    var tip = document.createElement("div");
    tip.className = "gloss-tip";
    tip.innerHTML = "<div class='gt-term'></div><div class='gt-body'></div>";
    document.body.appendChild(tip);
    var termEl = tip.querySelector(".gt-term"), bodyEl = tip.querySelector(".gt-body");

    function show(target) {
      var term = target.getAttribute("data-term");
      termEl.textContent = term;
      bodyEl.textContent = DEFS[term];
      var r = target.getBoundingClientRect();
      tip.style.left = "0px"; tip.style.top = "0px";
      tip.classList.add("show");
      /* measure after content set */
      var tw = tip.offsetWidth, th = tip.offsetHeight;
      var x = Math.min(Math.max(8, r.left), window.innerWidth - tw - 8);
      var y = r.top - th - 10;
      if (y < 64) y = r.bottom + 10;
      tip.style.left = x + "px";
      tip.style.top = y + "px";
    }
    function hide() { tip.classList.remove("show"); }

    var DESKTOP = window.matchMedia("(min-width: 60em)").matches;

    /* hover = quick glance (desktop only); never while the dock-driven
       detail is the intended interaction on a touch device */
    document.addEventListener("mouseover", function (e) {
      var g = e.target.closest && e.target.closest(".gloss");
      if (g && DESKTOP) show(g);
    });
    document.addEventListener("mouseout", function (e) {
      if (e.target.closest && e.target.closest(".gloss")) hide();
    });
    document.addEventListener("scroll", hide, { passive: true });

    /* click = detailed explanation. Desktop: open the right-side dock with
       the full definition + explorable related terms. Mobile: toggle the
       inline tooltip (the dock is desktop-only). */
    document.addEventListener("click", function (e) {
      var g = e.target.closest && e.target.closest(".gloss");
      if (!g) { hide(); return; }
      var term = g.getAttribute("data-term");
      if (DESKTOP && window.AIEDock && DEFS[term]) {
        e.preventDefault();
        hide();
        openReferenceFor(term);
      } else {
        if (tip.classList.contains("show")) hide(); else show(g);
      }
    });
  }

  /* related terms = other glossary entries named inside this definition
     (longest-first, word-bounded), so the dock becomes explorable */
  function relatedFor(term) {
    var def = " " + (DEFS[term] || "") + " ";
    var rel = [];
    for (var i = 0; i < TERMS.length && rel.length < 8; i++) {
      var t = TERMS[i];
      if (t.toLowerCase() === term.toLowerCase()) continue;
      var esc = t.replace(/[.*+?^${}()|[\]\\]/g, "\\$&").replace(/[- ]/g, "[- ]");
      if (new RegExp("(^|[^A-Za-z])" + esc + "([^A-Za-z]|$)", "i").test(def)) rel.push(t);
    }
    return rel;
  }
  function openReferenceFor(term) {
    if (!DEFS[term] || !window.AIEDock) return;
    window.AIEDock.openReference({
      term: term,
      def: DEFS[term],
      related: relatedFor(term),
      onRelated: openReferenceFor
    });
  }

  window.__glossaryScan = scan;
  /* fallback if KaTeX never loads (offline): scan anyway after 2.5s */
  setTimeout(scan, 2500);
})();
